INSERT INTO `wp_options` VALUES (4729, 0, '_transient_dash_de3249c4736ad3bd2cd29147c4a0d43e', '<h4>Most Popular</h4>\n<h5><a href=\'http://wordpress.org/extend/plugins/wordpress-importer/\'>WordPress Importer</a></h5>&nbsp;<span>(<a href=\'plugin-install.php?tab=plugin-information&amp;plugin=wordpress-importer&amp;_wpnonce=838275929d&amp;TB_iframe=true&amp;width=600&amp;height=800\' class=\'thickbox\' title=\'WordPress Importer\'>Install</a>)</span>\n<p>Import posts, pages, comments, custom fields, categories, tags and more from a WordPress export file.</p>\n<h4>Newest Plugins</h4>\n<h5><a href=\'http://wordpress.org/extend/plugins/movingboxes-wp/\'>movingboxes-wp</a></h5>&nbsp;<span>(<a href=\'plugin-install.php?tab=plugin-information&amp;plugin=movingboxes-wp&amp;_wpnonce=4a6feacbfd&amp;TB_iframe=true&amp;width=600&amp;height=800\' class=\'thickbox\' title=\'movingboxes-wp\'>Install</a>)</span>\n<p>movingboxes-wp displays images attached to posts or pages in a jQuery image slider which expands the images as you scroll through them.</p>\n<h4>Recently Updated</h4>\n<h5><a href=\'http://wordpress.org/extend/plugins/st-admin-protection/\'>ST Admin Protection</a></h5>&nbsp;<span>(<a href=\'plugin-install.php?tab=plugin-information&amp;plugin=st-admin-protection&amp;_wpnonce=26b60356be&amp;TB_iframe=true&amp;width=600&amp;height=800\' class=\'thickbox\' title=\'ST Admin Protection\'>Install</a>)</span>\n<p>This plugin blocks everyone but the admin from accessing the Wordpresss Admin</p>\n', 'no'); 
