INSERT INTO `wp_options` VALUES (4653, 0, '_transient_embed_github_gist-1266616', '<div id="gist-1266616" class="gist">\n  \n  \n    \n      \n        \n        \n\n        <div class="gist-file">\n          <div class="gist-data gist-syntax">\n            \n            \n            \n              <div class="highlight"><pre><div class=\'line\' id=\'LC1\'>	<span class="nb">require</span> <span class="s1">&#39;rubygems&#39;</span></div><div class=\'line\' id=\'LC2\'><br/></div><div class=\'line\' id=\'LC3\'>	<span class="no">Gem</span><span class="o">.</span><span class="n">clear_paths</span></div><div class=\'line\' id=\'LC4\'>	<span class="no">ENV</span><span class="o">[</span><span class="s1">&#39;GEM_HOME&#39;</span><span class="o">]</span> <span class="o">=</span> <span class="s1">&#39;/home/avishek/jruby/jruby-1.6.4/lib/ruby/gems/1.8&#39;</span></div><div class=\'line\' id=\'LC5\'>	<span class="no">ENV</span><span class="o">[</span><span class="s1">&#39;GEM_PATH&#39;</span><span class="o">]</span> <span class="o">=</span> <span class="s1">&#39;/home/avishek/jruby/jruby-1.6.4/lib/ruby/gems/1.8&#39;</span></div><div class=\'line\' id=\'LC6\'><br/></div><div class=\'line\' id=\'LC7\'>	<span class="nb">require</span> <span class="s1">&#39;basis_processing&#39;</span></div><div class=\'line\' id=\'LC8\'><br/></div><div class=\'line\' id=\'LC9\'>	<span class="k">class</span> <span class="nc">Demo</span> <span class="o">&lt;</span> <span class="no">Processing</span><span class="o">::</span><span class="no">App</span></div><div class=\'line\' id=\'LC10\'>		<span class="n">app</span> <span class="o">=</span> <span class="nb">self</span></div><div class=\'line\' id=\'LC11\'>		<span class="k">def</span> <span class="nf">setup</span></div><div class=\'line\' id=\'LC12\'>			<span class="n">smooth</span></div><div class=\'line\' id=\'LC13\'>			<span class="n">no_loop</span></div><div class=\'line\' id=\'LC14\'>			<span class="n">background</span><span class="p">(</span><span class="mi">0</span><span class="p">,</span><span class="mi">0</span><span class="p">,</span><span class="mi">0</span><span class="p">)</span></div><div class=\'line\' id=\'LC15\'>			<span class="n">color_mode</span><span class="p">(</span><span class="no">RGB</span><span class="p">,</span> <span class="mi">1</span><span class="o">.</span><span class="mi">0</span><span class="p">)</span></div><div class=\'line\' id=\'LC16\'>			<span class="n">stroke</span><span class="p">(</span><span class="mi">1</span><span class="p">,</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="p">,</span><span class="mi">1</span><span class="p">)</span></div><div class=\'line\' id=\'LC17\'>			<span class="vi">@highlight_block</span> <span class="o">=</span> <span class="nb">lambda</span> <span class="k">do</span> <span class="o">|</span><span class="nb">p</span><span class="o">|</span></div><div class=\'line\' id=\'LC18\'>						<span class="n">rect_mode</span><span class="p">(</span><span class="no">CENTER</span><span class="p">)</span></div><div class=\'line\' id=\'LC19\'>						<span class="n">stroke</span><span class="p">(</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="p">,</span><span class="mi">0</span><span class="p">)</span></div><div class=\'line\' id=\'LC20\'>						<span class="n">fill</span><span class="p">(</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="p">,</span><span class="mi">0</span><span class="p">)</span></div><div class=\'line\' id=\'LC21\'>						<span class="n">rect</span><span class="p">(</span><span class="nb">p</span><span class="o">[</span><span class="ss">:x</span><span class="o">]</span><span class="p">,</span> <span class="nb">p</span><span class="o">[</span><span class="ss">:y</span><span class="o">]</span><span class="p">,</span> <span class="mi">5</span><span class="p">,</span> <span class="mi">5</span><span class="p">)</span></div><div class=\'line\' id=\'LC22\'>					   <span class="k">end</span></div><div class=\'line\' id=\'LC23\'><br/></div><div class=\'line\' id=\'LC24\'>			<span class="vi">@passive_block</span> <span class="o">=</span> <span class="nb">lambda</span> <span class="k">do</span> <span class="o">|</span><span class="nb">p</span><span class="o">|</span></div><div class=\'line\' id=\'LC25\'>						<span class="n">rect_mode</span><span class="p">(</span><span class="no">CENTER</span><span class="p">)</span></div><div class=\'line\' id=\'LC26\'>						<span class="n">stroke</span><span class="p">(</span><span class="mi">1</span><span class="p">,</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="p">,</span><span class="mi">1</span><span class="p">)</span></div><div class=\'line\' id=\'LC27\'>						<span class="n">fill</span><span class="p">(</span><span class="mi">1</span><span class="p">,</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="p">)</span></div><div class=\'line\' id=\'LC28\'>						<span class="n">rect</span><span class="p">(</span><span class="nb">p</span><span class="o">[</span><span class="ss">:x</span><span class="o">]</span><span class="p">,</span> <span class="nb">p</span><span class="o">[</span><span class="ss">:y</span><span class="o">]</span><span class="p">,</span> <span class="mi">5</span><span class="p">,</span> <span class="mi">5</span><span class="p">)</span></div><div class=\'line\' id=\'LC29\'>					   <span class="k">end</span></div><div class=\'line\' id=\'LC30\'><br/></div><div class=\'line\' id=\'LC31\'>			<span class="n">points</span> <span class="o">=</span> <span class="o">[]</span></div><div class=\'line\' id=\'LC32\'>			<span class="mi">200</span><span class="o">.</span><span class="n">times</span> <span class="p">{</span><span class="o">|</span><span class="n">n</span><span class="o">|</span><span class="n">points</span> <span class="o">&lt;&lt;</span> <span class="p">{</span><span class="ss">:x</span> <span class="o">=&gt;</span> <span class="n">n</span><span class="p">,</span> <span class="ss">:y</span> <span class="o">=&gt;</span> <span class="n">random</span><span class="p">(</span><span class="mi">300</span><span class="p">)}}</span></div><div class=\'line\' id=\'LC33\'><br/></div><div class=\'line\' id=\'LC34\'>			<span class="n">x_basis_vector</span> <span class="o">=</span> <span class="p">{</span><span class="ss">:x</span> <span class="o">=&gt;</span> <span class="mi">1</span><span class="o">.</span><span class="mi">0</span><span class="p">,</span> <span class="ss">:y</span> <span class="o">=&gt;</span> <span class="mi">0</span><span class="o">.</span><span class="mi">0</span><span class="p">}</span></div><div class=\'line\' id=\'LC35\'>			<span class="n">y_basis_vector</span> <span class="o">=</span> <span class="p">{</span><span class="ss">:x</span> <span class="o">=&gt;</span> <span class="mi">0</span><span class="o">.</span><span class="mi">2</span><span class="p">,</span> <span class="ss">:y</span> <span class="o">=&gt;</span> <span class="mi">1</span><span class="o">.</span><span class="mi">0</span><span class="p">}</span></div><div class=\'line\' id=\'LC36\'><br/></div><div class=\'line\' id=\'LC37\'>			<span class="n">x_range</span> <span class="o">=</span> <span class="no">ContinuousRange</span><span class="o">.</span><span class="n">new</span><span class="p">({</span><span class="ss">:minimum</span> <span class="o">=&gt;</span> <span class="mi">0</span><span class="p">,</span> <span class="ss">:maximum</span> <span class="o">=&gt;</span> <span class="mi">200</span><span class="p">})</span></div><div class=\'line\' id=\'LC38\'>			<span class="n">y_range</span> <span class="o">=</span> <span class="no">ContinuousRange</span><span class="o">.</span><span class="n">new</span><span class="p">({</span><span class="ss">:minimum</span> <span class="o">=&gt;</span> <span class="mi">0</span><span class="p">,</span> <span class="ss">:maximum</span> <span class="o">=&gt;</span> <span class="mi">300</span><span class="p">})</span></div><div class=\'line\' id=\'LC39\'><br/></div><div class=\'line\' id=\'LC40\'>			<span class="vi">@basis</span> <span class="o">=</span> <span class="no">CoordinateSystem</span><span class="o">.</span><span class="n">new</span><span class="p">(</span><span class="no">Axis</span><span class="o">.</span><span class="n">new</span><span class="p">(</span><span class="n">x_basis_vector</span><span class="p">,</span><span class="n">x_range</span><span class="p">),</span> <span class="no">Axis</span><span class="o">.</span><span class="n">new</span><span class="p">(</span><span class="n">y_basis_vector</span><span class="p">,</span><span class="n">y_range</span><span class="p">),</span> <span class="o">[[</span><span class="mi">1</span><span class="p">,</span><span class="mi">0</span><span class="o">]</span><span class="p">,</span><span class="o">[</span><span class="mi">0</span><span class="p">,</span><span class="mi">1</span><span class="o">]]</span><span class="p">,</span> <span class="nb">self</span><span class="p">)</span></div><div class=\'line\' id=\'LC41\'>			<span class="n">screen_transform</span> <span class="o">=</span> <span class="no">Transform</span><span class="o">.</span><span class="n">new</span><span class="p">({</span><span class="ss">:x</span> <span class="o">=&gt;</span> <span class="mi">3</span><span class="p">,</span> <span class="ss">:y</span> <span class="o">=&gt;</span> <span class="o">-</span><span class="mi">2</span><span class="p">},</span> <span class="p">{</span><span class="ss">:x</span> <span class="o">=&gt;</span> <span class="mi">300</span><span class="p">,</span> <span class="ss">:y</span> <span class="o">=&gt;</span> <span class="mi">900</span><span class="p">})</span></div><div class=\'line\' id=\'LC42\'>			<span class="vi">@screen</span> <span class="o">=</span> <span class="no">Screen</span><span class="o">.</s