ibs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/C6sM_BhKrTQ/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:851:"<p><img class="alignnone size-full wp-image-10565" title="bluetreme" src="http://weblogtoolscollection.com/wp-content/uploads/2011/10/bluetreme.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://www.mdikici.com/wordpress-themes/blutreme/"><strong>Blutreme</strong></a> is a lightweight and simple theme with built-in fancybox support for thumbnails and medium sized images in the posts.</p>\n<p><img class="alignnone size-full wp-image-10566" title="pinktouch2" src="http://weblogtoolscollection.com/wp-content/uploads/2011/10/pinktouch2.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://wordpress.org/extend/themes/pink-touch-2"><strong>Pink Touch 2</strong></a> has a stellar mix of color, texture and typography.</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/C6sM_BhKrTQ" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 08 Oct 2011 13:00:12 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"James Huff";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:3;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:41:"WPTavern: WPWeekly Episode 114 – WordUp";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5566";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:99:"http://feedproxy.google.com/~r/WordpressTavern/~3/lhA91M5jOGg/wpweekly-episode-114-%e2%80%93-wordup";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2926:"<p><img src="http://www.wptavern.com/wp-content/uploads/2009/02/wordpressweekly1.png" alt="wordpressweekly1" title="wordpressweekly1" width="120" height="120" class="alignright size-full wp-image-436" />In this episode of WordPress Weekly, I had a roundtable discussion with longtime WordPress community member <a href="http://mindsharestrategy.com/">Eric Mann</a> on a number of topics mentioned in previous episodes. The end of the show featured an interview with Taryn and Martin who are organizers of WordUp Edinburgh to talk about not only the event but also about the WordCamp Guidelines and the interesting dynamic of hosting WordCamp events in the U.K. region. </p>\n<h2>Stories Discussed:</h2>\n<p><a href="http://www.wptavern.com/wordup-a-fork-of-wordcamp">WordUp &#8211; A Fork Of WordCamp</a><br />\n<a href="http://wpcandy.com/announces/wpcandy-is-now-four-years-old">WPCandy Turns 4</a><br />\n<a href="http://www.wptavern.com/tribute-to-steve-jobs-via-retro-macos-wordpress-theme">Tribute To Steve Jobs</a><br />\n<a href="http://www.wptavern.com/should-automatic-upgrades-be-opt-in">Should Automatic Upgrades be Opt-In?</a><br />\n<a href="http://www.wptavern.com/plugin-quality-not-plugin-quantity">Plugin Quantity Not Quality</a><br />\n<a href="http://www.wptavern.com/reasons-not-to-upgrade-wordpress">Reasons Not To Upgrade WordPress</a><br />\n<a href="http://kevinjohngallagher.com/2011/09/omg-wtf-y-u-no-upgrade-kktnx/">Kevin Johns Reaction To The Post Regarding Reasons Not To Upgrade</a><br />\n<a href="http://www.wptavern.com/when-will-automattic-be-acquired">When Will Automattic Be Acquired? </a></p>\n<h2>WPWeekly Meta:</h2>\n<p><strong>Subscribe To WPWeekly Via Itunes: </strong><a href="itpc://recordings.talkshoe.com/rss34224.xml" target="_blank">Click here to subscribe</a></p>\n<p><strong>Length Of Episode:</strong> 1 Hour 20 Minutes</p>\n<p><strong>Download The Show:</strong> <a href="http://recordings.talkshoe.com/TC-34224/TS-543676.mp3" target="_blank">WordPressWeeklyEpisode114.mp3</a></p>\n<p><strong>Listen To Episode #114:</strong><br />\n</p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/wpweekly-episode-111-%e2%80%93-youve-been-devpressed" rel="bookmark" title="Permanent Link: WPWeekly Episode 111 – You&#8217;ve Been DevPressed">WPWeekly Episode 111 – You&#8217;ve Been DevPressed</a></li>\n<li><a href="http://www.wptavern.com/wpweekly-episode-12-%e2%80%93-round-table-discussion-post-wordcamp-dallas" rel="bookmark" title="Permanent Link: WPWeekly Episode 12 – Round Table Discussion Post WordCamp Dallas">WPWeekly Episode 12 – Round Table Discussion Post WordCamp Dallas</a></li>\n<li><a href="http://www.wptavern.com/wordup-a-fork-of-wordcamp" rel="bookmark" title="Permanent Link: WordUp &#8211; A Fork Of WordCamp">WordUp &#8211; A Fork Of WordCamp</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/lhA91M5jOGg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 08 Oct 2011 10:07:50 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:4;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explic