ordpress.tv/2011/10/06/pascal-deschenes-wordpress-need-for-speed/"><img alt="Pascal Deschenes: WordPress Need for Speed" src="http://videos.videopress.com/77BkKI9m/wordpress-need-for-speed_f9-1mbps_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 21:02:49 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"wcmontreal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:10;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:40:"WPTavern: Status Update On WordPress 3.3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5561";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:92:"http://feedproxy.google.com/~r/WordpressTavern/~3/kECWTkYOLyQ/status-update-on-wordpress-3-3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1033:"<p>According to the revised project schedule, WordPress 3.3 beta 1 is expected to be released sometime on Friday, October 7th. <a href="http://wpdevel.wordpress.com/2011/10/05/were-getting-3-3-ready-for-beta-heres-the/">Ryan Boren has published</a> a list of things on the to-do list in order to get WordPress 3.3 to beta status. </p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/wordpress-271-beta-released" rel="bookmark" title="Permanent Link: WordPress 2.7.1 Beta Released">WordPress 2.7.1 Beta Released</a></li>\n<li><a href="http://www.wptavern.com/buddypress-10-beta2-now-available" rel="bookmark" title="Permanent Link: BuddyPress 1.0 Beta2 Now Available">BuddyPress 1.0 Beta2 Now Available</a></li>\n<li><a href="http://www.wptavern.com/wordpress-2-8-1-beta-by-end-of-the-week" rel="bookmark" title="Permanent Link: WordPress 2.8.1 Beta By End Of The Week">WordPress 2.8.1 Beta By End Of The Week</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/kECWTkYOLyQ" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 21:00:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:11;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:71:"WPTavern: Jane Wells Publishes Results Of WP 3.3 Pre-Beta User Feedback";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5558";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:123:"http://feedproxy.google.com/~r/WordpressTavern/~3/WMw6vT9yfL0/jane-wells-publishes-results-of-wp-3-3-pre-beta-user-feedback";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1300:"<p>If you&#8217;re curious into how some of the decisions are made regarding the UI/UX area of WordPress, definitely <a href="http://wpdevel.wordpress.com/2011/10/05/3-3-pre-beta-user-feedback-aka-testing-results/">check out this post</a> by Jane Wells on the WordPress Developers Prologue site where she explains the results of her tests using WordPress 3.3 pre-beta. Also worthy of note is the discussion within the comments regarding the <em>Feature Pointers</em> and the concern of whether or not plugin and theme authors will abuse them. </p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/wordpress-live-user-testing" rel="bookmark" title="Permanent Link: WordPress Live User Testing">WordPress Live User Testing</a></li>\n<li><a href="http://www.wptavern.com/feedback-needed-for-new-widget-context-user-interface" rel="bookmark" title="Permanent Link: Feedback Needed For New Widget Context User Interface">Feedback Needed For New Widget Context User Interface</a></li>\n<li><a href="http://www.wptavern.com/wordpress-2-8-1-beta-by-end-of-the-week" rel="bookmark" title="Permanent Link: WordPress 2.8.1 Beta By End Of The Week">WordPress 2.8.1 Beta By End Of The Week</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/WMw6vT9yfL0" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 17:00:26 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:12;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:71:"Alex King: Upgrading WordPress ALL THE TIME is a Security Best-Practice";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=6049";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:76:"http://alexking.org/blog/2011/10/06/upgrade-wordpress-security-best-practice";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2153:"<p>Over the last 6 months <a href="http://crowdfavorite.com">we</a> have had a few clients want to delay upgrading to the latest version of WordPress. They didn&#8217;t see any urgency to upgrade because there were no immediate security concerns addressed in the update that affected their site.</p>\n<p>I can certainly understand this thinking. When upgrading you need to spend time re-testing custom functionality, perhaps take the site down briefly, address any post-upgrade issues that might have snuck through the initial QA process; when the site is reasonably complex, it takes time. I can understand this thinking, but it&#8217;s wrong.</p>\n<p><strong>Any time you are running an application in production, you need to keep yourself in position to apply security patches immediately upon release. For WordPress, this means always running the latest version.</strong></p>\n<p>While the current new release may not include any security patches, it&#8217;s still important to upgrade quickly. You never know when a new security patch may be released. With WordPress, these patches are available as new versions (3.2.x) to the most recent version (3.2). If you delay upgrading because there were no security issues addressed in a specific release, you can easily find yourself in a position where you need to urgently upgrade through several releases in order to apply the security patches in the latest release. </p>\n<p>That kind of fire drill is a recipe for trouble and sometimes it just isn&#8217;t feasible. If this happens, you may end up running code with known vulnerabilities for several days while you get everything in place and tested to push the upgrade to your live site. That&#8217;s a bad place to be.</p>\n<p>You want to be performing upgrading to major feature releases on <em>your</em> schedule. This allows the upgrade process to be organized, well-tested and (hopefully) without incident. You also benefit from smaller functional deltas &#8211; fewer changes to test against makes the testing easier.</p>\n<p>Performing upgrades as soon as they are available is the best way to keep your site secure and running smoothly. Do it.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 15:49:31 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:13;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:49:"Weblog Tools Collection: Steve Jobs 1955 – 2011";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:41:"http://weblogtoolscollection.com/?p=10558";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/z-qm9DDsfwg/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1464:"<p>There is not much that I can say in a few words here that you have not already heard elsewhere in the news. However, I would like to pay my respects to Steve.</p>\n<p>Steve Jobs was and will be one of the greatest influencers in my life. I learned about him in college, started to follow his career and philosophy as a student of his, and became an ardent fan of the man and his career as I learned more about him. He was a brilliant thinker, a fantastic leader and a living legend to me. His commitment to the computing experience is shared by many but is paralleled by few.</p>\n<div id="attachment_10559" class="wp-caption aligncenter"><img class="size-medium wp-image-10559" title="Steve Jobs" src="http://weblogtoolscollection.com/wp-content/uploads/2011/10/t_hero-300x273.png" alt="" width="300" height="273" /><p class="wp-caption-text">Steve Jobs</p></div>\n<p>His death is even closer to home because of personal reasons but I mourn his loss with more heaviness in my heart than I have ever felt for someone I have only known through the media. I can selfishly say that it comes as a huge shock to me. I cannot imagine what his immediate family and his Apple family feel right now. My thoughts and prayers are with them.</p>\n<p>Hats off to you Mr. Jobs. A part of you will continue to live in me and everything I do and say. That is a promise.</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/z-qm9DDsfwg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 14:19:11 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Mark Ghosh";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:14;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:75:"WordPress.tv: Tom Catallini: Tom’s Top Ten Tips for Blogging on WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=6716";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:98:"http://wordpress.tv/2011/10/06/tom-catallini-tom%e2%80%99s-top-ten-tips-for-blogging-on-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1857:"<div id="v-fSQeMlql-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gofacebook/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/facebook/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gotwitter/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/twitter/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/6716/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/6716/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/6716/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=6716&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2011/10/06/tom-catallini-tom%e2%80%99s-top-ten-tips-for-blogging-on-wordpress/"><img alt="Tom Catallini: Tom’s Top Ten Tips for Blogging on WordPress" src="http://videos.videopress.com/fSQeMlql/wcbos2011-howto-tcatallini_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 13:09:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:15:"WordCamp Boston";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:15;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"Weblog Tools Collection: WordPress Plugin Releases for 10/6";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:41:"http://weblogtoolscollection.com/?p=10555";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/h6WhO4PxKKg/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1276:"<h3>New plugins</h3>\n<p><a href="http://www.advancedhtml.co.uk/ad-logger-click-logging-plugin-for-wordpress/"><strong>Ad Logger</strong></a> allows you to log clicks on iframe adverts and other social network buttons.</p>\n<p><a href="http://wordpress.org/extend/plugins/imagefx/"><strong>ImageFX</strong></a> allows you to add filters to your WordPress images uploaded through the normal media uploader.</p>\n<p><a href="http://www.jacobfresco.nl/programmeren/wordpress/wp-tweetbox/"><strong>WP-Tweetbox</strong></a> gives you a widget to show a fully customizable Twitter-searchbox in your sidebar.</p>\n<p><a href="http://wordpress.org/extend/plugins/wpsc-support-tickets/"><strong>wpsc Support Tickets</strong></a> is an open source help desk and support ticket system that allows you add support ticket capabilities to any WordPress site.</p>\n<h3>Updated plugins</h3>\n<p><a href="http://wordpress.org/extend/plugins/ui-labs/"><strong>UI Labs</strong></a> offers experimental WordPress admin UI features with the aim of building upon and enhancing the default WordPress User Interface. These are unofficial core UI experiments &#8211; who knows what could happen?</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/h6WhO4PxKKg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 13:00:08 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"James Huff";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:16;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"WPTavern: Tribute To Steve Jobs Via Retro MacOS WordPress Theme";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5554";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:115:"http://feedproxy.google.com/~r/WordpressTavern/~3/9Kbipx74OqU/tribute-to-steve-jobs-via-retro-macos-wordpress-theme";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2228:"<p>With the passing of Steve Jobs, memorials and tributes are showing up all over the web. While <a href="http://boingboing.net/">BoingBoing.net</a> seems to be one of the more popular tributes, I&#8217;m happy to inform you that if you&#8217;re using WordPress, you too can join in with the same tribute of making your site look like the Mac OS via a freely available WordPress theme called <a href="http://modernl.com/article/retro-mac-os-wordpress-theme">Retro MacOS</a>. </p>\n<div id="attachment_5555" class="wp-caption aligncenter"><a href="http://www.wptavern.com/wp-content/uploads/2011/10/boingboingSteveJobsTribute.png" rel="thumbnail"><img src="http://www.wptavern.com/wp-content/uploads/2011/10/boingboingSteveJobsTribute-500x218.png" alt="BoingBoing.net Steve Jobs Tribute" title="boingboingSteveJobsTribute" width="500" height="218" class="size-large wp-image-5555" /></a><p class="wp-caption-text">Tribute Based On Retro MacOS WordPress Theme</p></div>\n<p>According to the release post, this was Stuart Browns first WordPress theme which was created during the days of WordPress 2.1.2. However, it appears to work fine for the latest version of WordPress if BoingBoing.net is anything to go by. </p>\n<p>I wonder if via this theme, WordPress users can celebrate a new holiday called <em>Steve Jobs day</em> by having our site look like the retro MacOS every year on October 5th. I think it would be pretty interesting to browse some of the largest sites using WordPress when they use this theme just to see how it looks. At the very least, this is one way WordPress users can pay tribute to a great man.  </p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/a-theme-i-can-be-critical-about" rel="bookmark" title="Permanent Link: A Theme I Can Be Critical About">A Theme I Can Be Critical About</a></li>\n<li><a href="http://www.wptavern.com/a-3d-wordpress-theme" rel="bookmark" title="Permanent Link: A 3D WordPress Theme">A 3D WordPress Theme</a></li>\n<li><a href="http://www.wptavern.com/a-theme-called-2010" rel="bookmark" title="Permanent Link: A Theme Called 2010">A Theme Called 2010</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/9Kbipx74OqU" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 10:50:59 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:17;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:74:"Mark Jaquith: Translating WordPress Plugins and Themes: Don’t Get Clever";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:39:"http://markjaquith.wordpress.com/?p=724";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:101:"http://markjaquith.wordpress.com/2011/10/06/translating-wordpress-plugins-and-themes-dont-get-clever/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3260:"<p>When you use the WordPress translation functions to make your plugin or theme translatable, you pass in a text domain as a second parameter, like so:</p>\n<pre class="brush: php;">&lt;?php _e( \'Some Text String\', \'my-plugin-name\' ); ?&gt;</pre>\n<p>This text domain is just a unique string (usually your plugin&#8217;s WordPress.org repository slug). Well, many plugin developers see code like this:</p>\n<pre class="brush: php;">&lt;?php _e( \'Another Text String\', \'my-plugin-name\' ); ?&gt;\n&lt;?php _e( \'Yet Another Text String\', \'my-plugin-name\' ); ?&gt;\n&lt;?php _e( \'Gosh, So Many Text Strings!\', \'my-plugin-name\' ); ?&gt;</pre>\n<p>And they think to themselves &#8220;hm, I sure am typing the <code>\'my-plugin-name\'</code> string a lot. I&#8217;ll apply the DRY (Don&#8217;t Repeat Yourself) principle and throw that string into a variable or a constant!&#8221;</p>\n<p><strong>Stop! You&#8217;re being too clever! That won&#8217;t work!*</strong></p>\n<p>See, PHP isn&#8217;t the only thing that needs to parse out your translatable strings. GNU gettext also needs to parse out the strings in order to provide your blank translation file to your translators. <strong>GNU gettext is not a PHP parser.</strong> It can&#8217;t read variables or constants. It only reads strings. So your text domain strings needs to stay hardcoded as actual quoted strings. <code>\'my-plugin-name\'</code>.</p>\n<p>Happy coding!</p>\n<p><em>* Well, it won&#8217;t break your plugin, but it could make it harder to be used with automated translation tools. And trust me, you don&#8217;t want to be manually managing your translation files&#8230; we have a better solution coming.</em></p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gofacebook/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/facebook/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gotwitter/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/twitter/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/markjaquith.wordpress.com/724/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/markjaquith.wordpress.com/724/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/markjaquith.wordpress.com/724/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=markjaquith.wordpress.com&blog=316&post=724&subd=markjaquith&ref=&feed=1" width="1" height="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 Oct 2011 05:41:44 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Mark Jaquith";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:18;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:56:"WordPress.tv: Cameron 