m/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/6741/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gofacebook/wptv.wordpress.com/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/facebook/wptv.wordpress.com/6741/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gotwitter/wptv.wordpress.com/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/twitter/wptv.wordpress.com/6741/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/6741/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/6741/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/6741/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/6741/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=6741&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2011/10/05/reiko-beach-making-your-wordpress-site-social/"><img alt="Reiko Beach: Making your WordPress Site Social" src="http://videos.videopress.com/1QGte0d5/wcbos2011-howto-rbeach_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 Oct 2011 23:45:33 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:15:"WordCamp Boston";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:20;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:60:"WPTavern: Quick Way To Find Out The Scheduled Time Of A Post";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5549";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:112:"http://feedproxy.google.com/~r/WordpressTavern/~3/lwjY46pNjb0/quick-way-to-find-out-the-scheduled-time-of-a-post";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2079:"<p>Since publishing more content for WPTavern, I&#8217;ve become quite fond of the ability to schedule posts into the future. However, one gripe I&#8217;ve had is not being able to easily identify the time a post has been scheduled to be published. I was hoping that at some point in the future, on the <strong>All Posts</strong> administration panel that I would be able to see the time the post was going to go live under the term Scheduled, instead of having to go into the edit panel for the post to see the exact time. My mouse cursor must have been at the right place at the right time because I discovered tonight that if I hover my mouse cursor over the date the post has been scheduled, a tool-tip will appear that gives me the exact time.</p>\n<p><a href="http://www.wptavern.com/wp-content/uploads/2011/10/postscheduletime.png" rel="thumbnail"><img src="http://www.wptavern.com/wp-content/uploads/2011/10/postscheduletime.png" alt="See Exact Time For Post To Go Live" title="postscheduletime" width="163" height="57" class="aligncenter size-full wp-image-5550" /></a></p>\n<p>It&#8217;s little things like this that I really appreciate.</p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/does-scheduling-posts-freak-you-out" rel="bookmark" title="Permanent Link: Does Scheduling Posts Freak You Out?">Does Scheduling Posts Freak You Out?</a></li>\n<li><a href="http://www.wptavern.com/keeping-an-eye-out-for-post-ideas" rel="bookmark" title="Permanent Link: Keeping An Eye Out For Post Ideas">Keeping An Eye Out For Post Ideas</a></li>\n<li><a href="http://www.wptavern.com/ask-jeff-how-did-you-get-the-photo-to-the-left-side-of-your-posts-and-how-was-the-post-automatically-shorted" rel="bookmark" title="Permanent Link: Ask Jeff: How Did You Get The Photo To The Left Side Of Your Posts And How Was The Post Automatically Shorted?">Ask Jeff: How Did You Get The Photo To The Left Side Of Your Posts And How Was The Post Automatically Shorted?</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/lwjY46pNjb0" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 Oct 2011 22:00:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:21;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"WPTavern: BuddyPress Skeleton Component Upgraded To Version 1.6";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5546";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:115:"http://feedproxy.google.com/~r/WordpressTavern/~3/dlupxWKopIg/buddypress-skeleton-component-upgraded-to-version-1-6";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2871:"<p><a href="http://www.wptavern.com/wp-content/uploads/2009/04/buddypresslogo.png" rel="thumbnail"><img src="http://www.wptavern.com/wp-content/uploads/2009/04/buddypresslogo.png" alt="" title="buddypresslogo" width="212" height="76" class="alignright size-full wp-image-966" /></a>One of the coolest things about BuddyPress is that when it was developed by Andy Peatling, he made sure to put in a considerable amount of effort into creating a <a href="http://www.wptavern.com/buddypress-releases-skeleton-theme">BuddyPress Starter theme</a> as well as a BuddyPress starter plugin. Knowing that those two things would be often used as the beginning stages of a plugin or theme, only the best coding practices were used as a means of not only having a blank slate to start from, but also teach developers at the same time. It&#8217;s like Hello Dolly! but without the lyrics. Boone Gorges has announced that the tradition has continued with the release of <a href="http://buddypress.org/2011/09/buddypress-skeleton-component-v1-6-is-built-for-buddypress-1-5/">BuddyPress Skeleton Component v1.6</a>. The new release features the following:</p>\n<ul>\n<li>Refactored to use the BuddyPress 1.5′s new <code>BP_Component</code> class, making it dead-simple to register globals, create navigation items, and hook into the BP load order</li>\n<li>File structure reorganized to better reflect BP 1.5′s organization, and to provide more fine-grained access to functions</li>\n<li>Data storage class totally refactored, to use custom post types and WP_Query, instead of custom database tables.</li>\n<li>Added a small guide for creating a top-level component directory (a “root component”), which was missing in earlier versions</li>\n<li>Tons of documentation added and revised</li>\n<li>All <code>WP_DEBUG</code> notices removed</li>\n</ul>\n<p>It&#8217;s important to know that any plugin built from version 1.6 of the Skeleton Component <a href="http://bpdevel.wordpress.com/tag/1-5-plugin-update/">will be incompatible</a> with BuddyPress versions prior to 1.5. It&#8217;s recommended by Boone that you first create the plugin for BuddyPress 1.5 and build in backwards compatibility as an after thought. </p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/buddypress-releases-skeleton-theme" rel="bookmark" title="Permanent Link: BuddyPress Releases Skeleton Theme">BuddyPress Releases Skeleton Theme</a></li>\n<li><a href="http://www.wptavern.com/buddypress-1-1-released" rel="bookmark" title="Permanent Link: BuddyPress 1.1 Released">BuddyPress 1.1 Released</a></li>\n<li><a href="http://www.wptavern.com/buddypress-themes-are-future-proof" rel="bookmark" title="Permanent Link: BuddyPress Themes Are Future Proof">BuddyPress Themes Are Future Proof</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/dlupxWKopIg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 Oct 2011 18:15:27 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:22;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:66:"WPTavern: 5 Questions To Consider Before Using WordPress or Drupal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=5542";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:118:"http://feedproxy.google.com/~r/WordpressTavern/~3/CA0OZXJPRaM/5-questions-to-consider-before-using-wordpress-or-drupal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2107:"<p><a href="http://www.wptavern.com/wp-content/uploads/2011/10/poynterlogo.png" rel="thumbnail"><img src="http://www.wptavern.com/wp-content/uploads/2011/10/poynterlogo.png" alt="poynter logo" title="poynterlogo" width="230" height="71" class="alignright size-full wp-image-5543" /></a>Meg Heckman of Poynter.org <a href="http://www.poynter.org/how-tos/digital-strategies/147568/5-questions-to-ask-when-deciding-whether-to-use-drupal-or-wordpress/">shares her experience</a> from a newsroom perspective with The Monitor using Drupal while sharing the experience of William Davis of the Daily News and their move to WordPress. </p>\n<blockquote><p>So which system is better?</p>\n<p>Neither.</p>\n<p>The question of WordPress versus Drupal isn’t Coke/Pepsi, boxers/briefs, Red Sox/Yankees. It’s about understanding the needs of your organization.</p></blockquote>\n<p>The five questions brought up within the post are definitely ones you should have answers to before making any decision to go with a particular platform. As a bonus, check out the <a href="http://www.poynter.org/how-tos/digital-strategies/147568/5-questions-to-ask-when-deciding-whether-to-use-drupal-or-wordpress/#comment-326003677">comment left by pmaiorana</a> who claims to work for Automattic with regards to the important factor of software updates. </p>\n\n\n<p>Related posts:<ol><li><a href="http://www.wptavern.com/saying-goodbye-to-drupal-and-hello-to-wordpress" rel="bookmark" title="Permanent Link: Saying Goodbye To Drupal And Hello To WordPress">Saying Goodbye To Drupal And Hello To WordPress</a></li>\n<li><a href="http://www.wptavern.com/joomla-against-drupal-against-wordpress" rel="bookmark" title="Permanent Link: Joomla Against Drupal Against WordPress">Joomla Against Drupal Against WordPress</a></li>\n<li><a href="http://www.wptavern.com/the-crossing-paths-of-drupal-and-wordpress" rel="bookmark" title="Permanent Link: The Crossing Paths Of Drupal And WordPress">The Crossing Paths Of Drupal And WordPress</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/CA0OZXJPRaM" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 Oct 2011 14:00:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:23;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:74:"WordPress.tv: Toby McKes: Developing a Modular Theme for Multiple Site Use";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=6938";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:91:"http://wordpress.tv/2011/10/05/toby-mckes-developing-a-modular-theme-for-multiple-site-use/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1857:"<div id="v-h7EnagZv-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/6938/"><img alt="" border="0" src="