eator";a:1:{i:0;a:5:{s:4:"data";s:11:"wcvancouver";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:24;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:70:"Weblog Tools Collection: WordPress 3.2 Downloaded over 9 Million Times";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:41:"http://weblogtoolscollection.com/?p=10552";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/r0Sc87aEN9s/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:800:"<p><a href="http://wordpress.org/">WordPress</a> 3.2 has been downloaded <a href="http://wordpress.org/download/counter/">over 9 million times</a> since it was <a href="http://weblogtoolscollection.com/archives/2011/07/04/wordpress-3-2-released/">released last July</a>. That means that there has almost been 100,000 downloads of WordPress 3.2 each day, once again calling out to the rapid adoption rate that WordPress sees with each major release.</p>\n<p>At this rate, WordPress 3.2 will soon exceed the 15 million count that WordPress 3.1 reached just before WordPress 3.2 was released.</p>\n<p>If you aren&#8217;t using WordPress, start today and contribute to the counter&#8217;s rise!</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/r0Sc87aEN9s" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 Oct 2011 13:00:20 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"x