INSERT INTO `wp_options` VALUES (4709, 0, '_transient_dash_4077549d03da2e451c8b5f002294ff51', '<div class="rss-widget"><ul><li><a class=\'rsswidget\' href=\'http://wordpress.org/news/2011/09/software-freedom-day-hackathon/\' title=\'Saturday, September 17 is Software Freedom Day. To that end, a few announcements about this weekend’s hackathon and WordCamp Portland. 3.3 Hackathon WordPress 3.3 is about to hit feature freeze. This means it’s the last chance to squeeze in features that haven’t quite been finished, and enhancements and fixes that no one has had time [&hellip;]\'>Software Freedom Day + Hackathon</a> <span class="rss-date">September 15, 2011</span><div class=\'rssSummary\'>Saturday, September 17 is Software Freedom Day. To that end, a few announcements about this weekend’s hackathon and WordCamp Portland. 3.3 Hackathon WordPress 3.3 is about to hit feature freeze. This means it’s the last chance to squeeze in features that haven’t quite been finished, and enhancements and fixes that no one has had time [&hellip;]</div></li><li><a class=\'rsswidget\' href=\'http://wordpress.org/news/2011/09/a-tale-of-two-wordcamps/\' title=\'This coming weekend, two WordCamps will be going on simultaneously — yep, it’s WordCamp season again! This weekend will be the first of many this autumn with multiple WordCamps. Tomorrow (not quite the weekend but close enough) is WordCamp Cape Town, and then this weekend, first-time WordCamp Albuquerque coincides with 4-time returning champ WordCamp Portlan [&hellip;]\'>A Tale of Two WordCamps</a> <span class="rss-date">September 14, 2011</span><div class=\'rssSummary\'>This coming weekend, two WordCamps will be going on simultaneously — yep, it’s WordCamp season again! This weekend will be the first of many this autumn with multiple WordCamps. Tomorrow (not quite the weekend but close enough) is WordCamp Cape Town, and then this weekend, first-time WordCamp Albuquerque coincides with 4-time returning champ WordCamp Portlan [&hellip;]</div></li></ul></div>', 'no'); 
