;}i:5;a:5:{s:4:"data";s:11:"WPtouch Pro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:6;a:5:{s:4:"data";s:7:"contest";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:7;a:5:{s:4:"data";s:8:"giveaeay";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:35:"http://www.bravenewcode.com/?p=4823";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:361:"Happy Holidays Everyone! Below are the winners of our free iPadTM + WPtouch ProTM Licenses Giveaway Contest! 1st Draw: iPad 64GB + 3G and a WPtouch Pro Developer/Unlimited License: @maguay 2nd Draw: A WPtouch Pro 5-Pack License: @suggymoto 3rd, 4th and 5th Draws: WPtouch Pro Single Licenses: @rumple, @cidodd, and @benny8484 We&#8217;ll be sending direct [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Dale Mugford";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:1274:"<h3>Happy Holidays Everyone!</h3>\n<p><strong>Below are the winners of our free iPad<sup>TM</sup> + WPtouch Pro<sup>TM</sup> Licenses Giveaway Contest!</strong></p>\n<h4>1st Draw:</h4>\n<p><strong>iPad 64GB + 3G and a WPtouch Pro Developer/Unlimited License:</strong><br />\n<a href="http://twitter.com/maguay">@maguay</a></p>\n<h4>2nd Draw:</h4>\n<p><strong>A WPtouch Pro 5-Pack License:</strong><br />\n<a href="http://twitter.com/suggymoto/">@suggymoto</a></p>\n<h4>3rd, 4th and 5th Draws:</h4>\n<p><strong>WPtouch Pro Single Licenses:</strong><br />\n<a href="http://twitter.com/rumple/">@rumple</a>, <a href="http://twitter.com/cidodd/">@cidodd</a>, and <a href="http://twitter.com/benny8484/">@benny8484</a></p>\n<p>We&#8217;ll be sending direct messages to the winners on Twitter to let them know that they&#8217;ve won.  To claim your prize, please <a href="/contact-us/">contact us</a> and we&#8217;ll finish setting up your WPtouch Pro account.</p>\n<p>Thank you to everyone who entered the contest, and a big congratulations to the winners!  We&#8217;ll have a few more contests in the future, so keep checking our Twitter feed for details in the future.</p>\n<p>On behalf of everyone here at BraveNewCode, we want to wish everyone a Merry Christmas and a Happy new Year!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:113:"http://www.bravenewcode.com/2010/12/drumroll-the-winners-of-our-free-ipad-wptouch-pro-licenses-giveaway-are/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"8";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:10;a:6:{s:4:"data";s:59:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:73:"Tweet For A Chance To Win a 64GB iPad 3G + WPtouch Pro Developer License!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:58:"http://www.bravenewcode.com/2010/12/december-ipad-contest/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:67:"http://www.bravenewcode.com/2010/12/december-ipad-contest/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 13 Dec 2010 13:00:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:7:{i:0;a:5:{s:4:"data";s:12:"BraveNewCode";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:8:"Featured";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:4:"iPad";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:7:"WPtouch";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:4;a:5:{s:4:"data";s:11:"WPtouch Pro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:5;a:5:{s:4:"data";s:7:"contest";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:6;a:5:{s:4:"data";s:9:"promotion";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:35:"http://www.bravenewcode.com/?p=4761";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:375:"The contest is now closed, thanks to everyone who participated! We&#8217;ll be announcing the winners shortly. *Some conditions apply Over $1250 CAD Value in Prizes! To celebrate the forthcoming release of our 2.1 update for WPtouch Pro (which includes amazing iPad support) we&#8217;re giving away a top-of-the-line iPad, together with a WPtouch Pro developer license. [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"The BNC Team";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:3038:"<p><img class="aligncenter size-full wp-image-4803" title="ad-post-new3" src="http://www.bravenewcode.com/wordpress/wp-content/uploads/2010/12/ad-post-new3.jpg" alt="" width="500" height="195" /><br />\n<strong><span style="color: #ff0000;">The contest is now closed, thanks to everyone who participated!<br />\nWe&#8217;ll be announcing the winners shortly.</span></strong><br />\n<small><a id="ipad-conditions" href="http://www.bravenewcode.com/ipad-contest.txt">*Some conditions apply</a></small></p>\n<h3>Over $1250 CAD Value in Prizes!</h3>\n<p>To celebrate the forthcoming release of our 2.1 update for WPtouch Pro (which includes amazing iPad support) we&#8217;re giving away a top-of-the-line iPad, together with a WPtouch Pro developer license.</p>\n<p>There are also runner-up WPtouch Pro licenses, too.</p>\n<p><strong>The 5 Prizes available to be won are:</strong><br />\n- An Apple iPad, 64GB with 3G/WiFi, along with a WPtouch Pro Developer License<br />\n- One WPtouch Pro 5-Pack License<br />\n- 3 separate WPtouch Pro Single Licenses</p>\n<p><strong>All you need to do to enter is click the &#8220;Tweet Now&#8221; button above + tweet the entry message and <a rel="nofollow" href="http://www.twitter.com/bravenewcode">follow us on Twitter!</a></strong></p>\n<p>The contest runs until this Friday December 17th 2010 at 12pm noon EST.</p>\n<p>We&#8217;ll draw the winners then and announce them on twitter and our blog. If you&#8217;re a selected winner, we&#8217;ll contact you on Twitter.</p>\n<p>*iPad prize is available to North American and EU residents only.<br />\n<img class="aligncenter size-medium wp-image-4801" title="photo 4" src="http://www.bravenewcode.com/wordpress/wp-content/uploads/2010/12/photo-4-500x410.png" alt="" width="500" height="410" /><br />\nThe iPad, complete with Apple Gift Box!</p>\n<h3>WPtouch Pro 2.1: Available Soon</h3>\n<p>Very soon we&#8217;ll be releasing the 2.1 update for WPtouch Pro, <strong>a free update</strong> for all existing customers.</p>\n<p>WPtouch and WPtouch Pro<sup>TM</sup> have gained worldwide attention providing unique, rich and beautiful mobile experiences for website visitors on touch-based smart phones.</p>\n<p>With WPtouch Pro 2.1, that great experience has been redefined and brought to the iPad<sup>TM</sup>, with a user-interface tailored for the iPad experience.</p>\n<p>Nowhere else can you find the sophistication, tremendous usability and feature-set for working with iPad and WordPress websites.</p>\n<p>Since WPtouch Pro on iPad is a part of WPtouch Pro 2.1 (starting at only $39), you get incredible value, great features, product support &amp; future upgrades— all at an unbelievable price.</p>\n<div id="attachment_4607" class="wp-caption aligncenter" style="width: 560px"><img class="size-full wp-image-4607" title="WPtouch Pro on iPad - Landscape View" src="http://www.bravenewcode.com/wordpress/wp-content/uploads/2010/09/ipad-hor-post-acct-open.png" alt="" width="550" height="471" /><p class="wp-caption-text">WPtouch Pro on iPad - Landscape View</p></div>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:63:"http://www.bravenewcode.com/2010/12/december-ipad-contest/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"22";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:11;a:6:{s:4:"data";s:65:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:36:"Thoughts On WPtouch & The Mobile Web";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://www.bravenewcode.com/2010/12/thoughts-on-wptouch-the-mobile-web-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:82:"http://www.bravenewcode.com/2010/12/thoughts-on-wptouch-the-mobile-web-2/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 07 Dec 2010 14:51:56 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:9:{i:0;a:5:{s:4:"data";s:12:"BraveNewCode";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:8:"Featured";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:6:"iPhone";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:10:"technology";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:4;a:5:{s:4:"data";s:9:"WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:5;a:5:{s:4:"data";s:7:"WPtouch";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:6;a:5:{s:4:"data";s:11:"WPtouch Pro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:7;a:5:{s:4:"data";s:10:"blackberry";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:8;a:5:{s:4:"data";s:6:"Mobile";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:35:"http://www.bravenewcode.com/?p=4736";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:309:"The Beginning When we first wrote the code and designed what would become WPtouch we did so with one clear thing in mind— we were creating something for where the mobile web was going, not where it was or where it had been. On Every Website We imagined that nearly every website would eventually offer [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Dale Mugford";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:7188:"<h3>The Beginning</h3>\n<p>When we first wrote the code and designed what would become <a href="/wptouch-pro">WPtouch</a> we did so with one clear thing in mind— <em>we were creating something for where the mobile web was going, not where it was or where it had been.</em></p>\n<h3>On Every Website</h3>\n<p>We imagined that nearly every website would eventually offer mobile versions, and that those who didn&#8217;t would be the exception. </p>\n<p>At first, tools like WPtouch would be useful to bridge the gap between desktop and mobile presentation. As anyone who&#8217;s built a website knows, development and design aren&#8217;t all that cheap, and if you&#8217;re adding a mobile version to it just adds more time, money, and effort to the process. What&#8217;s more, there just weren&#8217;t any good tools available previously to help do so. Many site owners previously didn&#8217;t consider shipping a mobile version for these reasons.</p>\n<p>Being able to install and configure a mobile version <strong>with little to know development time or cost</strong> is a great stop-gap solution for many, and perfectly suitable as a permanent solution for others. WPtouch accomplishes this gracefully.</p>\n<h3>The Wave</h3>\n<p>These people venturing into the mobile arena with regular websites are intrepid explorers; the first wave of small and medium-sized website owners adapting to a space that previously could only be occupied by large companies, or those with the cash/business need to deliver mobile web experiences. Now, there are different tools to harness web traffic viewership that make it easier and more affordable to offer &#8220;tailored for the mobile web&#8221; solutions.</p>\n<h3>The Wave Redux</h3>\n<p>At present, a growing number of those explorers in the mobile web publishing world are growing more savvy, and want more custom mobile solutions that better reflect the style and brand that their desktop sites/services offer.</p>\n<p>As more and more people join the mobile revolution, postered by similar solutions to mobile web presentation of content like WPtouch, this wave of mobile exploration will grow strong, yet not everyone will follow.</p>\n<p>This marks the point of divergence. </p>\n<h3>Two Schools</h3>\n<p>With the rise of social networking services which collect information and serve vast amounts of people, together with the &#8220;app-ification&#8221; of the web ( the tendency for ubiquitous interface styles to serve content), users are increasingly demanding this ubiquity- simple solutions like WPtouch Pro which offer a compromise between customization and ease of use.</p>\n<p>The divergence is created not by the explorers, but rather by their users— much of the feedback we see and hear is often from those who are <em>asking website owners to install WPtouch for them to use to access content.</em> The growing want for a familiar, easy interface is a by-product of the increasing complexity experienced by web users on all web and technology fronts.</p>\n<h3>The High Horsers</h3>\n<p>Conversely, those that advocate and prefer completely custom mobile solutions are either a) in the web industry and are savvy, preferring to distinguish themselves from others and have the skill to do so, or b) have the resources to afford the cost of such development.</p>\n<p>It&#8217;s been our experience that the majority of mobile web <em>users</em> prefer something like WPtouch. That may not be true of website <em>owners</em>, but the demand for WPtouch by visitors says something powerful that you just don&#8217;t see on the desktop.</p>\n<h3>Idealism vs. Reality</h3>\n<p>As a content publisher, it&#8217;s ideal to deliver completely custom mobile solutions- similar design experiences on the desktop + mobile web is really (what seems at first pass) the most natural. But the differences between them are vast, like those between  the workings of quantum and relative mechanics; with time and examination it becomes clear that completely custom mobile experiences might not be the best solution for a great many sites.</p>\n<p>The medium of the internet is heavily influenced by the ways it can be presented. As desktop displays got larger and the tools for web development smarter, the web grew in a way that was directly opposed to the restrictive nature of small mobile devices and the &#8220;information without decoration&#8221; needs of mobile web users (oh, the dreaded WAP).</p>\n<p>Then came the iPhone, and with it an explosion of touch-based smartphones that aimed to put the real web in your pocket.</p>\n<p>But the real web in your pocket just didn&#8217;t feel right. Native apps showed that web content presented and tailored for the device and touch interface proved far more popular than the websites they were culled from.</p>\n<h3>That App-Like Experience</h3>\n<p>That&#8217;s why we chose to go the route of separating the presentation of mobile web content in a user interface from its website&#8217;s presentation, and instead tailor it to the devices it would be viewed on— at current the iOS and Android devices that make up the bulk of the mobile web traffic today.</p>\n<p>These touch devices have interface requirements and interactive interactive prepositions which either do not exist on the desktop or have no corollary. We thought it was more natural that a mobile user, becoming accustomed to the way their mobile device worked and behaved, be presented with a similar interface that they would instantly recognize and understand.</p>\n<p>We worked to match expectations for the behavior of how content + navigation were seen &#038; interacted with. The goal for a user being (when presented with a similar layout on another website) that <em>they would focus less on the layout itself but more on its content.</em></p>\n<h3>Bold-ly Forward</h3>\n<p>Some people think WPtouch should also have backwards, non-touch compatibility on devices like the BlackBerry Bold, Curve, etc. While these devices are still popular in many business environments, they don&#8217;t represent much of the mobile web traffic today, and the direction these browsing statistics are going. What&#8217;s more, the browsers on older, non-touch mobile devices make it quite difficult to offer rich, engaging experiences, dampening the cause to create them.</p>\n<p>That&#8217;s an important distinction: <em>The popularity of mobile devices themeselves in the wild doesn&#8217;t necessarily mean you should invest in web solutions for them;</em> rather, popular mobile devices <strong>which account for the bulk of mobile traffic</strong> should be your concern.</p>\n<p>And in that regard, WPtouch and WPtouch Pro cover well over 90% of that traffic.</p>\n<h3>Philosophy</h3>\n<p>So we look forward to what&#8217;s next, and instead of working with the mobile web today exclusively, we see the future of the mobile web when we consider what we do with the WPtouch/WPtouch Pro plugins. We&#8217;re not prophets and have no crystal ball when it comes to where the mobile revolution might take us all, but we are tuned to the needs of users and content creators, and hope to remain a leader in providing tools for accessing WordPress on the go.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:78:"http://www.bravenewcode.com/2010/12/thoughts-on-wptouch-the-mobile-web-2/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"6";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:12;a:6:{s:4:"data";s:71:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:44:"WPtouch 1.9.21, WPtouch Pro 2.1 RC1 Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:80:"http://www.bravenewcode.com/2010/12/wptouch-1-9-21-wptouch-pro-2-1-rc1-releases/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:89:"http://www.bravenewcode.com/2010/12/wptouch-1-9-21-wptouch-pro-2-1-rc1-releases/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 03 Dec 2010 01:59:19 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:11:{i:0;a:5:{s:4:"data";s:12:"Brave