:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:306:"We&#8217;ve had quite a few inquiries since launching WPtouch Pro about the possibility of having an affiliate program. While we&#8217;re still a few weeks away from launching, we wanted to let people know a few of the details and also get a list of people who are interested in being a part of it. A [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Duane Storey";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:847:"<p>We&#8217;ve had quite a few inquiries since launching WPtouch Pro about the possibility of having an affiliate program.  While we&#8217;re still a few weeks away from launching, we wanted to let people know a few of the details and also get a list of people who are interested in being a part of it.</p>\n<p>A few of the relevant details of the program are:</p>\n<ul>\n<li>The affiliate program is only available to WPtouch Pro customers</li>\n<li>The commission rate is 30% for all new WPtouch Pro purchases &#8211; upgrades are not eligible</li>\n<li>Commissions will be paid out once per month via PayPal &#8211; other payment methods are not available</li>\n</ul>\n<p>For more information and to sign up to be notified when the affiliate program is released, please visit the main <a href="/affiliate-program/">WPtouch Pro affiliate page</a>.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:71:"http://www.bravenewcode.com/2010/08/wptouch-pro-affiliate-program/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:19;a:6:{s:4:"data";s:50:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:22:"The State Of The Touch";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.bravenewcode.com/2010/08/the-state-of-the-touch/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:68:"http://www.bravenewcode.com/2010/08/the-state-of-the-touch/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 02 Aug 2010 17:57:41 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:4:{i:0;a:5:{s:4:"data";s:7:"WPtouch";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:8:"Features";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:3:"Pro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:8:"Upgrades";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:35:"http://www.bravenewcode.com/?p=4466";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:324:"We released WPtouch 2.0 about 6 weeks ago now, and have constantly been improving it since day one. In fact, since that time we&#8217;ve added or improved over 100 features &#8212; you can take a look at the change log. We&#8217;re currently in the process of revamping our product information pages to reflect some of [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Duane Storey";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:3910:"<p>We released WPtouch 2.0 about 6 weeks ago now, and have constantly been improving it since day one.  In fact, since that time we&#8217;ve added or improved over 100 features &#8212; <a href="http://dl.dropbox.com/u/2674729/wptouch-changelog-2.0.7.txt">you can take a look at the change log</a>.</p>\n<p>We&#8217;re currently in the process of revamping our product information pages to reflect some of these new changes, but I thought now would be a good time to overview where we are with the product.</p>\n<h3>New Features</h3>\n<p>Version 2.0.7 was a substantial update, adding a whack of new customizations options (colors, fonts, etc.) for the Classic theme.  We also added a Backup/Restore function to aid 5-pack and development package users, many of which can save time by using this feature to Backup on one site, and Restore on another.  We also improved the WPtouch Pro warning system &#8212; if you have a plugin that may interfere with WPtouch Pro, we show a warning message so you can learn more about it and possibly fix it.  In addition, we&#8217;ve been active in our Pro support forums, helping users sort out issues in short order.</p>\n<h3>Internationalization</h3>\n<p>WPtouch Pro has been fully internationalized since day one.  Our plan has always been to translate our Pro series plugins into as many languages as possible.  Truthfully, I love seeing WPtouch in another language &#8212; I was like a kid in a candy store when WPtouch Pro was translated into Japanese.</p>\n<p>WPtouch Pro is currently available in <em>eight</em> languages: Spanish, German, Portuguese, French, Italian, Japanese, Norwegian, and Dutch.  The plugin will automatically detect what language WordPress is configured to use and emulate that, or the language that WPtouch Pro will use can be selected from the WPtouch Pro administration panel.  </p>\n<p><img src="http://www.bravenewcode.com/wordpress/wp-content/uploads/2010/08/wptouch-inter4.png" alt="" title="wptouch-inter4" width="802" height="482" class="alignright size-full wp-image-4479" /></p>\n<h3>Developer Package</h3>\n<p>WPtouch Pro also has a developer package, complete with online development documentation.  If you&#8217;re a development package user, you&#8217;ll have access to architecture information, plugin hooks and filters, and various code examples for tweaking the plugin.  </p>\n<p>WPtouch Pro is a full mobile development framework, capable of being used to customize the look and feel for any mobile device at the code level.  Some of our users are using it to do iPad development, some are doing custom integrations with their own iPhone applications.  Because WPtouch Pro is GPL, the sky is really the limit for what some of these projects may ultimately become &#8212; we&#8217;re anxiously awaiting to see the results, as some of them are going to be pretty exciting.</p>\n<h3>Going Forward</h3>\n<p>We&#8217;re currently working on our 2.0.8 release, which will probably be out late next week.  We&#8217;re also working hard on finishing off the upgrade system for those users that are looking to upgrade between packages (we&#8217;ve actually had quite a few inquiries about this recently).  Hopefully within a week or so users will be able to automatically upgrade their packages.</p>\n<p>Our 2.1 release will be a fairly important update, and we&#8217;re looking forward to starting to work on that.  If you&#8217;ve already purchased WPtouch Pro, you&#8217;ll automatically receive 2.1 when the times comes.  If you&#8217;re interested in grabbing a copy now, <a href="/products/wptouch-pro/?utm_source=bravenewcode&#038;utm_medium=web&#038;utm_campaign=state-of-the-word">head on over to the WPtouch Pro page and pick one up</a>.</p>\n<p>Thanks again to everyone who has supported WPtouch Pro and BraveNewCode &#8211; we have many more great things to add to the product, so hop aboard the train and come along for the ride!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:64:"http://www.bravenewcode.com/2010/08/the-state-of-the-touch/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"14";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}s:27:"http://www.w3.org/2005/Atom";a:1:{s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:0:"";s:7:"attribs";a:1:{s:0:"";a:3:{s:4:"href";s:45:"http://www.bravenewcode.com/tag/wptouch/feed/";s:3:"rel";s:4:"self";s:4:"type";s:19:"application/rss+xml";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:44:"http://purl.org/rss/1.0/modules/syndication/";a:2:{s:12:"updatePeriod";a:1:{i:0;a:5:{s:4:"data";s:6:"hourly";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:15:"updateFrequency";a:1:{i:0;a:5:{s:4:"data";s:1:"1";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:13:{s:4:"date";s:29:"Thu, 09 Jun 2011 11:05:48 GMT";s:6: