//aquoid.com/news/2011/07/suffusion-version-3-8-1/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2011/07/suffusion-version-3-8-1/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 05 Jul 2011 17:59:47 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/07/suffusion-version-3-8-1/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:389:"Version 3.8.1 went live today. This version addresses the issues reported with Version 3.8.0. Truth be told I was a bit nervous about 3.8.0 because the change log for that version was almost 40 items long and since the development took over 4 months, I was concerned that what I had started developing in February <a href=\'http://aquoid.com/news/2011/07/suffusion-version-3-8-1/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:2911:"<p>Version 3.8.1 went live today. This version addresses the issues reported with Version 3.8.0.</p>\n<p>Truth be told I was a bit nervous about 3.8.0 because the change log for that version was almost 40 items long and since the development took over 4 months, I was concerned that what I had started developing in February might have been forgotten by June. Luckily nothing of that sort happened, and though there were bugs, they were nowhere as bad as 3.7.5/3.7.7.</p>\n<p>So here is the list of changes:</p>\n<ol>\n<li><strong>Bug Fixes</strong>\n<ol>\n<li>In IE9, there was a stray closing comment tag (<code>--&gt;</code>) appearing near the top of the page. This was due to the incorrect inclusion of a conditional script in IE for rounded corners.</li>\n<li>I had upgraded the JQuery Cycle scripts for featured content in the theme. This didn’t pose any problems in most cases, however some users reported that when the Featured Content Widget was being used with the “lite” version of the script, the script stopped cycling through images. I have rolled back the JQuery Cycle script, so hopefully there will be no issues.</li>\n<li>There was an undetected bug which would have caused JS errors in IE6 because I had forgotten to include a particular script. I have addressed this.</li>\n<li>Another “Featured Posts Widget” bug was causing the images to get squished when the widget was in the “Widget Area Below Header” or in the “Widget Area Above Footer”. I have addressed this. <a href="http://aquoid.com/forum/viewtopic.php?f=2&amp;t=5587">Props to “Kapusjon”</a> on the support forum for helping me track this down!</li>\n</ol>\n</li>\n<li><strong>New Features</strong></li>\n<ol>\n<li>I have enhanced the <code>post_class()</code> functionality in the theme. It now includes some classes for posts, such as <code>category-xx-id</code> (the id for the category), <code>post-seq-x</code> (the number of the post on a page), <code>post-parity-odd</code> (whether the post is in an odd location or even). You can take advantages of these classes for adding extra styles to your site.</li>\n</ol>\n<li><strong>Code Changes</strong></li>\n<ol>\n<li>I have removed output buffering where possible. This shouldn’t impact you as a user.</li>\n<li>I have replaced a query parameter in the Featured Content to ignore sticky posts – this is because the previous query parameter was deprecated.</li>\n<li>I have added a <code>wp_reset_query()</code> call to the Category Posts widget to account for any query changes to it.</li>\n</ol>\n</ol>\n<p>I would also like to get your inputs on features that you liked or would like to see improved in the previous release. I added a lot of them, like column control for individual posts and the magazine layout, enhancements to the Twitter and Category Posts widgets and byline information handling for the magazine template, the tile layout and post formats.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2011/07/suffusion-version-3-8-1/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"18";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:1;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.8.0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/07/suffusion-version-3-8-0/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2011/07/suffusion-version-3-8-0/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 01 Jul 2011 04:04:20 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/07/suffusion-version-3-8-0/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:382:"Version 3.7.9 of Suffusion was approved today, and as things happen, shortly after approval I discovered a bug which I fixed. So the new version available is 3.8.0. This version should work on the upcoming WP 3.2 – I have made sure that the admin-side JS doesn’t break. This version has a very long but <a href=\'http://aquoid.com/news/2011/07/suffusion-version-3-8-0/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:10898:"<p>Version 3.7.9 of Suffusion was approved today, and as things happen, shortly after approval I discovered a bug which I fixed. So the new version available is 3.8.0. This version should work on the upcoming WP 3.2 – I have made sure that the admin-side JS doesn’t break.</p>\n<p>This version has a very long but hopefully low impact change log. The following are the changes:</p>\n<ol>\n<li><strong>Bug Fixes</strong>\n<ol>\n<li>There was a problem with selecting fonts that had spaces in their name in the back-end. This has been addressed. </li>\n<li>In IE7 if you were to use the “No Sidebars” template with the “Widget Area Below Header” enabled, there were markup issues. This has been addressed. </li>\n<li>The “pullout” style displays (like the Minima skin) had an error in the markup – it was missing a closing tag. </li>\n<li>The image resizer was incorrectly creating multiple copies of the source file if the file extension was in uppercase. Now it will not. </li>\n<li>I fixed a bug where the sidebars below Sidebar 1 and Sidebar 2 were incorrectly picking the styles defined for the upper sidebars. </li>\n<li>This is not a bug fix as such, but I removed the “Notifier Failed” message that was shown earlier in the options panel if my site was down. </li>\n<li>I fixed a minor problem where the options panel was sometimes showing incorrect values for default colours. </li>\n<li>The sitemap template was not showing contents properly without saving the options for it twice. Now that has been resolved. </li>\n<li>Another minor bug fixed is that in the Alternate Page Title handling. There was a small inaccuracy in the code that would prevent the alternate titles from working under some circumstances. </li>\n</ol>\n</li>\n<li><strong>Changed Features</strong>\n<ol>\n<li>The “Edit” link earlier used to be displayed only on singular views (i.e. on pages and on single posts). I have now made it visible on the archive views too. </li>\n<li>I made the button bar in the back-end a lot less intrusive, based on user feedback. I also made the back-end fluid-width instead of fixed width. </li>\n<li>The Featured Content has always used the JQuery Cycle plugin. Cycle was meant to cycle through a series of images, so it displayed a blank box whenever you had a single post in your featured content. I worked around this – you can now have just one post in your featured content and it will work just fine. </li>\n<li><u>Code Housekeeping </u>\n<ol>\n<li><em>IE6-specific Cleanup                <br /></em>\n<ol>\n<li>In an effort to clean up for IE6, I replaced Microsoft Expressions with JavaScript. As an end user you will not see any impact, except that it speeds up a few things. Not that I expect you to use IE6, but even so. </li>\n<li>I also got the IE-specific fixes to enqueue instead of including them directly. Again, you can safely ignore this – it will not impact you as a user. </li>\n</ol>\n</li>\n<li>I swapped out some of the admin panel checks with standard WP functions like <code>checked()</code> and <code>selected()</code>. </li>\n<li>There are some minor CSS cleanups done. </li>\n<li>I have swapped out the use of <code>$post-&gt;post_title</code> with <code>get_the_title()</code>. so that the right filters are applied. </li>\n<li>I have removed the scripts for JQuery Accordion – it was something erroneously included in the first place, so removing it should have no impact on you. </li>\n</ol>\n</li>\n<li>The replacement text for […] in excerpts now supports HTML in addition to plain text. </li>\n</ol>\n</li>\n<li><strong>New Features</strong>\n<ol>\n<li>This is something that folks might like: I introduced a method to search for options in the back-end. It is not perfect, but it should help people find options a lot quicker. You will see a box called “Quick Search” in your options screens – that is where you can start typing what you are looking for. </li>\n<li><u>Magazine and Tile Layout </u>\n<ol>\n<li>Now there is byline support for the Tile Layout and the Magazine Template. Hopefully you will like what has been implemented. To save on real estate, this has been implemented as clickable icons, which you can click to see the details. </li>\n<li>Additional modifications to the Magazine Template include the ability to control the number of sidebars in there. This too makes its way after quite a few requests. </li>\n<li>Custom thumbnail sizes can now explicitly be defined for the Tile Layout. Earlier the thumbnail inherited the sizes from the Magazine layout. </li>\n</ol>\n</li>\n<li><u>Widgets</u>\n<ol>\n<li>There is a new Flickr widget to help display your Flickr stream. It is not as fancy as what I had put together for the gallery short-code extension, but it does its job as it should. </li>\n<li>The Twitter Widget got a rewrite! It now displays your Avatar for your tweets, and the Avatar of the original tweeter in case of a retweet. </li>\n<li>The Category Posts widget (and the static category posts in the magazine layout) got a rewrite too! It now displays a post thumbnail, in addition to an excerpt if you wish. You can additionally control the length of the excerpt and make it different from that of a standard excerpt. </li>\n</ol>\n</li>\n<li><u>Special Handling </u>\n<ol>\n<li>Support for post formats has been significantly improved. For each post format you can control how the bylines should appear etc. Check out <em>Other Graphical Elements → Post Formats</em>. </li>\n<li>You can now control the number of sidebars on single posts. In your “Edit Post” screen you will see a drop-down that says “Select the sidebar layout to apply to this post” under “Additional Options for Suffusion”. You can pick the layout you wish for that. </li>\n<li>You can now hide the page title for pages. In the “Edit Page” screen you will see a checkbox that says “Do not display the page title” under “Additional Options for Suffusion”, which upon selecting will hide the page title. </li>\n<li>For posts without a title, a specific “Permalink” is displayed. This is turned on by default and can be switched off in <em>Other Graphical Elements → Post and Page Bylines</em>. </li>\n</ol>\n</li>\n<li>A search form has been added to the 404 page, as per WordPress requirements. </li>\n<li>For image attachments you can display all available image sizes at the top. Take a look at <em>Templates → Attachments.</em> </li>\n<li>Rounded corner support has been extended to IE9. </li>\n<li>There is a new “Mosaic Layout”. Consider this an apology for not including the photo-blogging features I had thought I would, but this was the least I felt I could do. The mosaic layout will display just the thumbnails of your posts in an archive view, nothing else. In many ways it is like the List Layout, except that this shows thumbnails instead of titles. </li>\n<li>There is a new short code that accompanies the Flickr Widget, called suffusion-flickr. It takes the same parameters as the widget, so you can pass the following\n<ol>\n<li><code>id</code> – Mandatory, can be obtained from <a href="http://idgettr.com">http://idgettr.com</a> using your photo stream&#8217;s URL </li>\n<li><code>type</code> – Mandatory, legitimate values: user, group </li>\n<li><code>size</code> – Optional, legitimate values: s (square), t (thumbnail), m (mid-size); default: s </li>\n<li><code>number</code> – Optional, default 10 </li>\n<li><code>order</code> – Optional, legitimate values: latest, random; default: latest </li>\n<li><code>layout</code> – Optional, legitimate values: h (horizontal), v (vertical), x (no layout &#8211; user-styled); default: x </li>\n</ol>\n</li>\n<li>There are a couple of new filters: <code>suffusion_comment_form_fields</code> and <code>suffusion_permalink_text</code>. The former can be used if you want to override the fields in the comment form, while the latter can be used to override the “Permalink” text that you see for the newly introduced permalink byline. </li>\n<li>In the previous version I introduced WPML support for text fields entered on the admin side. In this release this support has been extended to fields that are of type “textarea” as well. E.g. The 404 page content under <em>Templates → 404</em> is a text area, so the text you have there can be translated into multiple languages using WPML. </li>\n</ol>\n</li>\n<li><u>Removed Features</u>\n<ol>\n<li>I removed the ability to load JS files in the footer, because this was causing a lot of dependency issues. Most caching plugins will let you do this, though, so you are not really losing out on much by means of functionality. </li>\n</ol>\n</li>\n</ol>\n<p>There is one thing I am not pleased with for this release, and that is a lack of polish on some of the new functionality, like the enhanced Post Format support, the Mosaic Layout etc. Believe me, I would have done things much better if I had more time to spare, but having got caught up between releasing the theme to be WP 3.2-ready and adding features and working full-time elsewhere, I had to make some sacrifices. Rest assured that I will improve on these in the near future.</p>\n<p>I would again like to reiterate something that I touched upon in my last few posts. Suffusion is almost 2 years old and has evolved into something that I am very proud of. However, due to several factors I believe now is the time to wind down the development of the theme:</p>\n<ol>\n<li>The theme has reached a level of complexity beyond which it will become more of a liability than an asset. So from now on, big ticket new features are a strict no-no, except for some things documented below. </li>\n<li>I am trying to reclaim some time for myself. Thanks to all volunteers on the forum (you know who you are!) the load on me has reduced quite a lot, however with every new feature comes a new set of support questions. Juggling between coding, supporting and working is turning out to be a strain. </li>\n</ol>\n<p>However, in the light of the queries posted in response to my previous post I must hasten to point out:</p>\n<ol>\n<li>Incremental development will continue, like new skins, new templates, support for newer WP versions. </li>\n<li>Some big ticket items are still in scope for the theme, specifically in the area of sidebars, and making the theme more of a customizable framework. </li>\n<li>I will channel my energy into building some plugins that you can take with you to any theme. As mentioned in my last post I will bundle the photo-blogging features into a plugin. In addition I will build some plugins to manage fonts etc. </li>\n<li>I will improve theme documentation. </li>\n<li>I will also switch back to mini-releases instead of humongous ones. Though a lot of people don’t like frequent updates to the theme, from my experience over the last few releases, smaller updates are easier to process and definitely easier to support. </li>\n</ol>\n<p>Cheers.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2011/07/suffusion-version-3-8-0/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"45";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:2;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.8";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/02/suffusion-version-3-7-8/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2011/02/suffusion-version-3-7-8/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 28 Feb 2011 23:59:16 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:34:"http://www.aquoid.com/news/?p=1007";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:354:"I have had bugs in software before, but by any standards version 3.7.7 was awful. Just awful. As the saying goes, The road to hell is paved with good intentions. In Beta 2 I tried to put in a tweak related to Suhosin, so I split the options into multiple forms and thought I got <a href=\'http://aquoid.com/news/2011/02/suffusion-version-3-7-8/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:10197:"<p>I have had bugs in software before, but by any standards version 3.7.7 was awful. Just awful. As the saying goes, <q>The road to hell is paved with good intentions</q>. In <a href="http://www.aquoid.com/news/2011/02/suffusion-version-3-7-4-update-3-beta-release-2-available/">Beta 2</a> I tried to put in <a href="http://www.aquoid.com/news/2011/01/cant-save-your-theme-options-tweak-your-suhosin-settings/">a tweak related to Suhosin</a>, so I split the options into multiple forms and thought I got it working. The Beta came and went by without alarms, so I submitted the code for approval, and then it proverbially hit the fan. Truth be told I was expecting issues with the <a href="http://www.aquoid.com/news/2011/02/suffusion-version-3-7-5/">TimThumb replacement</a>, and there were a few. But I seriously blew it with regards to the option management, costing people hours of work. Not all people faced issues, mind you – particularly several people who simply upgraded their sites and left it at that. People who are subscribed to my feed knew how to downgrade the release, so that alleviated some concerns. People who had little image jiggery-pokery on their sites (like me) faced literally no issues, because they didn’t have to tweak anything.</p>\n<p>But for all the rest, all I can offer you is an apology, and what I hope is a clean version – 3.7.8. If you have bought me a coffee and then realized it was not worth it due to this release, please send me an email through the support forum with a transaction id – I will issue an unconditional refund.</p>\n<p>Here is what I have covered in 3.7.8:</p>\n<ol>\n<li><strong>Thumbnail issues</strong>\n<ol>\n<li>If images were not in the template path but in the local directory they were not being picked up and a warning message was being displayed. Thanks a lot to <strong>Bob Schecter</strong> for an impressive array of websites with a wide range of configurations, which he let me use so that I could track this down. </li>\n<li>If the image source was a secure HTTP location (HTTPS, like PicasaWeb), the image was not getting resized. This should be fine now. Thanks to <a href="http://www.aquoid.com/forum/viewtopic.php?f=2&amp;t=4231&amp;p=17747#p17747">Jürgen</a> for the tip. </li>\n</ol>\n</li>\n<li><strong>Color issues</strong>\n<ol>\n<li>The first issue was with the color picker. Thanks to various quirks in the use of Farbtastic, I rolled back to something that has been a part of Suffusion since release 2.0 – JSColor. If you now pick a color and save, the change will go through without you having to go through an elaborate charade. </li>\n<li>Colors were inconsistently getting prefixed with a “#”. I have made sure that this is no longer the case. Thanks to Kattsby for the tip regarding this. </li>\n</ol>\n</li>\n<li><strong>Option issues</strong>\n<ol>\n<li>The biggest issue in the previous release was that the buttons to save/reset options had gone rogue and a lot of people have pointed this out. I have made sure of the following:\n<ol>\n<li>Clicking “Save” in one screen will not blank out options in another screen. </li>\n<li>Clicking “Reset” will not empty the entire theme’s options. </li>\n<li>Exporting / Importing will now work. </li>\n</ol>\n</li>\n<li>Another rather intermittent issue was the interference caused by a cookie used by the options panel while attempting to save things. I am only aware of 2 people facing this issue, mind you, and one of them (Mason) has confirmed that this has now been fixed. </li>\n<li>A minor issue was that if your options were saved, they needed to be saved twice for the auto-linked CSS to be updated. </li>\n<li>Quote characters around font names were being escaped, preventing the font from being loaded. </li>\n<li>Some people complained about a slowdown on IE. To counter this, I got rid of the JQuery Uniform script that I was using to make the admin panel look good. I will reconsider this once the changes introduced in this version stabilize. </li>\n</ol>\n</li>\n<li><strong>Miscellaneous issues</strong>\n<ol>\n<li>There was a bug that was breaking the layout of the <em>Widget Area Above Footer</em>. </li>\n<li>There were some issues with the navigation menu’s appearance in the standard skins, particularly with respect to visited items and hover-over items. </li>\n</ol>\n</li>\n</ol>\n<h3>Things that are not issues</h3>\n<p>When something goes wrong, the natural inclination is to assign to it all faults, real and perceived. Something similar happened with the last releases, and because the core faults with Suffusion were so severe, a lot of issues from other places were ascribed to the theme. Not that I blame any of you for it. The following are NOT issues with Suffusion:</p>\n<ol>\n<li>If your admin panel stops loading after printing the top bar, the culprit is, in all likelihood a plugin. There is a lot of literature around this on the web, but it bears repeating, particularly because Suffusion’s options panel is more complex and detailed than most other themes’ panels, and having an incorrect script interfering can really mess things up.</p>\n<p>A lot of people upgraded to WP 3.1 and Suffusion 3.7.7 at the same time. Now, WP 3.1 uses a new version of <a href="http://wpdevel.wordpress.com/2010/11/20/wordpress-3-1-uses-jquery-1-4-4-and-jqu/">JQuery libraries</a>. Some plugins and themes don’t include JQuery the right way. The somewhat correct way to include JS in WordPress is by using the <code>wp_enqueue_script</code> function. The truly correct way to include JS is to use <code>wp_enqueue_script</code> with the right hooks. Here is what I mean:\n<ol>\n<li>The absolutely wrong way:  </p>\n<pre class="brush: php; title: ; notranslate">\nfunction print_my_script() {\n	echo &quot;&lt;link media=\'all\' href=\'http://ajax.googleapis.com/ajax/libs/jquery/1.5/jquery.min.js\' type=\'text/css\' rel=\'stylesheet\' /&gt;&quot;;\n}\nprint_my_script();\n</pre>\n<p>The problem is that the above will load JQuery potentially twice. Plus you might be loading JQuery <em>after</em> something needs it, thereby resulting in errors. The only situation when this might be required is if you need conditional JavaScript (like something for IE), which is not the case in the above.</li>\n<li>The sometimes correct way:\n<pre class="brush: php; title: ; notranslate">\nadd_action(\'init\', \'my_enqueue_scripts\');\nfunction my_enqueue_scripts() {\n    wp_deregister_script( \'jquery\' ); // Will remove WP\'s standard JQuery\n    wp_register_script( \'jquery\', \'http://ajax.googleapis.com/ajax/libs/jquery/1.5/jquery.min.js\'); // Will register Google CDN\'s JQuery, version 1.5\n    wp_enqueue_script( \'jquery\' );// Will queue it up for printing.\n}\n</pre>\n<p>The trouble with the above is that the script is going to get enqueued for all pages, admin or otherwise.\n</li>\n<li>The almost correct way:\n<pre class="brush: php; title: ; notranslate">\nadd_action(\'admin_menu\', \'my_plugin_menu\');\nfunction my_plugin_menu() {\n	add_options_page(\'My Plugin Options\', \'My Plugin\', \'manage_options\', \'my-unique-identifier\', \'my_plugin_options\');\n	add_action(&quot;admin_print_scripts&quot;, \'my_admin_script_loader\');\n}\n\nfunction my_admin_script_loader() {\n    wp_deregister_script( \'jquery\' ); // Will remove WP\'s standard JQuery\n    wp_register_script( \'jquery\', \'http://ajax.googleapis.com/ajax/libs/jquery/1.5/jquery.min.js\'); // Will register Google CDN\'s JQuery, version 1.5\n    wp_enqueue_script( \'jquery\' );// Will queue it up for printing.\n}\n</pre>\n<p>The only problem with the above is that it will queue up the CDN JQuery for <strong>all</strong> admin pages. What if another plugin is relying on a different version of JQuery? A lot of developers get this one wrong.\n</li>\n<li>The truly correct way:\n<pre class="brush: php; title: ; notranslate">\nadd_action(\'admin_menu\', \'my_plugin_menu\');\nfunction my_plugin_menu() {\n	$options_manager = add_options_page(\'My Plugin Options\', \'My Plugin\', \'manage_options\', \'my-unique-identifier\', \'my_plugin_options\');\n	add_action(&quot;admin_print_scripts-$options_manager&quot;, \'my_admin_script_loader\');\n}\n\nfunction my_admin_script_loader() {\n    wp_deregister_script( \'jquery\' ); // Will remove WP\'s standard JQuery\n    wp_register_script( \'jquery\', \'http://ajax.googleapis.com/ajax/libs/jquery/1.5/jquery.min.js\'); // Will register Google CDN\'s JQuery, version 1.5\n    wp_enqueue_script( \'jquery\' );// Will queue it up for printing.\n}\n</pre>\n<p>If you notice, the only difference with #c is the way the <code>admin_print_scripts</code> hook is used. By appending the options page to it, we are saying that the JQuery script should be used only for this particular plugin&#8217;s admin screens.\n</li>\n</ol>\n<p>What has been happening is that a few plugins have followed route b or c above, causing a proliferation of bad JavaScript across the admin pages. With the WP upgrade these plugins now have conflicting JS. This unfortunately causes the correctly coded themes/plugins to break because they rely on the native version of JQuery, which the bad plugin has overwritten on all pages. If you are facing this, you should try deactivating your plugins, then reactivate them one by one to see which one is wrong. If you isolate the broken one, feel free to point the above instructions to the author.\n   </li>\n<li>Header height and margin between top of content and top of page: If you had set your options to show a certain header height and margin, please note that the option has moved from <em>Blog Features &rarr; Sizes and Margins</em> to <em>Theme Skinning &rarr; Header</em>. What has happened as a part of this move is that the control switch has changed. So under <em>Theme Skinning &rarr; Header</em> you have to set the options to use &#8220;Custom Styles&#8221; for the setting to continue to be effective.</li>\n</ol>\n<p>Thanks for all of you who had patience with me during the last one week. Thanks are also in order to all of you who provided detailed reports of the issues that you faced. I wish some of you had participated in the beta testing. Apologies if you don&#8217;t see your name above &#8211; it is just that there were so many people reporting the issues that I couldn&#8217;t fit everyone in here.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2011/02/suffusion-version-3-7-8/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"75";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:3;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.7";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/02/suffusion-version-3-7-7/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2011/02/suffusion-version-3-7-7/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 22 Feb 2011 17:33:41 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.aquoid.com/news/2011/02/suffusion-version-3-7-7/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:398:"Version 3.7.7 was released earlier today. This release mostly has bug fixes for 3.7.5. The following are the changes: I have included a workaround for a rather weird critical bug affecting some installations. The symptoms of the bug are that the header in the options page loads up, then nothing happens. I tracked it down <a href=\'http://aquoid.com/news/2011/02/suffusion-version-3-7-7/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:1396:"<p>Version 3.7.7 was released earlier today. This release mostly has bug fixes for 3.7.5. The following are the changes:</p>\n<ol>\n<li>I have included a workaround for a rather weird critical bug affecting some installations. The symptoms of the bug are that the header in the options page loads up, then nothing happens. I tracked it down to a bug due to those installations failing to load the <code>jquery.cookie.js</code> file. What makes this bug weird is that the file is there, yet accessing it returns a 404 error. What makes the bug (and the fix) weirder is that if I yank that file and put its contents in another place, the bug resolves itself.</li>\n<li>There was a bug that wasn’t updating the options CSS if you had set it to be auto-generated. This has been addressed.</li>\n<li>Resized images were not being generated in the default settings. If, however, you saved options on, say, the Featured Content page, the images would show up fine. I have fixed this issue.</li>\n<li>I have added basic post-format support without any special treatment, so as to be ready for WP 3.1. Further handling of post formats will be done in subsequent releases.</li>\n<li>Another fix is for folks on PHP 4.x. There was a call to a feature (<em>instanceof</em>) that came up in PHP 5, so people on PHP 4 were getting a critical error.</li>\n</ol>\n<p>Hope this takes care of the issues with 3.7.5.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2011/02/suffusion-version-3-7-7/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"26";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:4;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.5";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2011/02/suffusion-version-3-7-5/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2011/02/suffusion-version-3-7-5/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 21 Feb 2011 17:09:00 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.aquoid.com/news/2011/02/suffusion-version-3-7-5/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:389:"Version 3.7.5 was approved earlier today. I know that the beta releases were for 3.7.4, however 3.7.4 didn’t pass the approvals required by the Review Team, so I had to release 3.7.5. This is quite a big release with lots of changes. However, unlike other big releases this has more to do with code housekeeping <a href=\'http://aquoid.com/news/2011/02/suffusion-version-3-7-5/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:17020:"<p>Version 3.7.5 was approved earlier today. I know that the beta releases were for 3.7.4, however 3.7.4 didn’t pass the approvals required by the Review Team, so I had to release 3.7.5. This is quite a big release with lots of changes. However, unlike other big releases this has more to do with code housekeeping rather than brand new functionality. Before you read further, here is a warning:</p>\n<p class="warning">This release changes the whole look of the code behind the scenes. It has been beta-tested, but bugs always come up. In case this release critically breaks some functionality, <strong>please downgrade to the previous version and log a bug on the support forum</strong>. You can <a href="http://wordpress.org/extend/themes/download/suffusion.3.7.3.zip">download the old version</a>, then replace the contents of your <code>wp-content/themes/suffusion</code> folder with the unzipped suffusion folder that you get from the downloaded file.</p>\n<p>Without much ado, here is the change list:</p>\n<ol>\n<li><strong><u>Code Housekeeping </u></strong>\n<ol>\n<li><strong><em>Switch to native WordPress APIs </em></strong>          <br />I have removed a lot of custom or third party code from a lot of areas and started using native WordPress areas. Here are the changes:\n<ol>\n<li>\n<p><strong>Settings API </strong>                <br />One of the 2 biggest changes this release is a nice looking backend. For this I moved to the <a href="http://codex.wordpress.org/Settings_API">Settings API</a> that WordPress provides. This was a huge and high impact change, because I had to decommission a tried and tested options engine in favour of something that has not been implemented by anyone on such a large scale. All uses of the Settings API on the web are for simple cases where you require only one options page. Anything more complex makes developers pick up a custom approach, or an approach that only superficially uses the Settings API.                 <br />I can thump my chest here as the first theme with such a complex back-end to utilize the Settings API in all its glory. The only place where the API is <em>not</em> used is in the <em>Custom Types</em> section, which only partly uses the API. I will port it over in a subsequent release – for now it is not critical.</p>\n</li>\n<li>\n<p><strong>No TimThumb </strong>                <br />This is the second big change, and potentially more high impact than the first. TimThumb, though popular has some security holes, particularly with its old versions. Recently the WP review team started cracking down on themes relying solely on TimThumb. I introduced TimThumb into the mix <a href="http://www.aquoid.com/news/2010/01/suffusion-version-3-2-2/">more than a year back</a>, but I had also introduced support for the native post thumbnail functionality of WP almost as soon as it was introduced. This helped me avoid the axe. With this release Suffusion bids adieu to TimThumb.                 <br />I have put together a resizing algorithm based on a method suggested by a contributor on <a href="http://core.trac.wordpress.org/ticket/15311">WordPress Trac</a>. I had to modify it a good bit to make it work the way I wanted and so that it did not break how your existing images looked.</p>\n</li>\n<li>\n<p><strong>No “file open” operations </strong>                <br />Again, the WP review team has been cracking its whip to get file open operations removed. As a result I have had to think out of the box to make code behave to my liking. I have had to replace inbuilt CURL calls with the WP HTTP API, and where this really posed a challenge was regarding storing of the generated CSS and storing the resized file for the image resizing.</p>\n</li>\n</ol>\n</li>\n<li><strong><em>Use of more modern functions </em></strong>          <br />A few functions have been deprecated by the WP development team. I have replaced all such functions with their new variants:\n<ol>\n<li><code>get_bloginfo(\'wpurl\')</code> → <code>site_url()</code> </li>\n<li><code>get_bloginfo(\'template_url\')</code> → <code>get_template_directory_uri()</code> </li>\n<li>\n<p><code></code><code>get_bloginfo(\'url\')</code>, <code>bloginfo(\'url\')</code> → <code>get_template_directory_uri()</code>&#160; </p>\n</li>\n</ol>\n</li>\n<li>\n<p><strong><em>Removal of backwards compatibility </em></strong>            <br />As stated in a previous post, WordPress 3.0 has been out for more than 8 months now and version 3.1 is almost upon us. So if you haven’t upgraded your WP installation now is the time to do it. This latest release of Suffusion will not work on anything older than 2.9. I have removed function/class existence checks for all these versions: </p>\n<ol>\n<li>3.0.x – <code>get_template_part</code>, <code>comment_form</code>, <code>wp_nav_menu</code>, <code>wp_login_form</code>, <code>get_nav_menu_locations</code>, <code>wp_get_nav_menus</code>, <code>register_post_type</code>, <code>register_taxonomy</code>, <code>post_type_exists</code> and <code>register_nav_menu</code> </li>\n<li>2.9.x – <code>add_theme_support</code>, <code>get_the_post_thumbnail</code> </li>\n<li>2.8.x – class <code>WP_Widget</code> </li>\n</ol>\n</li>\n<li>Function names are now more consistent. All functions within Suffusion are either prefixed with <code>suffusion</code> or <code>suf</code>. </li>\n</ol>\n</li>\n<li><strong><u>Feature Changes </u></strong>\n<ol>\n<li><strong><em>Reorganized the Options Menu (again) </em></strong>          <br />Trust me – <a href="http://wordpress.org/support/topic/plugin-theme-check-questions-about-the-new-version?replies=10">I did not want to do this</a>. Suffusion started out with one link under the <em>Appearance</em> section of the admin page. <a href="http://www.aquoid.com/news/2010/06/suffusion-version-3-5-3-and-buddypress-support/">I then pulled it out to give Suffusion its own menu</a> when I introduced Custom Post Type support. I initially had horizontal tabs at the top and vertical tabs within each page, but <a href="http://www.aquoid.com/news/2010/08/suffusion-version-3-6-3/">I switched it out when the page got sluggish</a>.           <br />This change consumed a lot of my development time in what was already an intensive exercise. But I believe I got it right this time:\n<ol>\n<li><strong>New Menu Position (aka Older Menu Position)</strong>              <br /><a href="http://www.aquoid.com/news/wp-content/uploads/2011/02/3.7.4options1.jpg"><img title="3.7.4-options-1" style="border-top-width: 0px; display: inline; border-left-width: 0px; border-bottom-width: 0px; border-right-width: 0px" height="172" alt="3.7.4-options-1" src="http://www.aquoid.com/news/wp-content/uploads/2011/02/3.7.4options1_thumb.jpg" width="158" border="0" /></a> </li>\n<li><strong>New Tab Design </strong>              <br /><a href="http://www.aquoid.com/news/wp-content/uploads/2011/02/3.7.4options2.jpg"><img title="3.7.4-options-2" style="border-top-width: 0px; display: inline; border-left-width: 0px; border-bottom-width: 0px; border-right-width: 0px" height="158" alt="3.7.4-options-2" src="http://www.aquoid.com/news/wp-content/uploads/2011/02/3.7.4options2_thumb.jpg" width="563" border="0" /></a> </li>\n<li><strong>Moved items </strong>              <br />There has been some upheaval in the options sections. Notably:\n<ol>\n<li><em>Introduction</em> – This is the same as the <em>Introduction</em> section of the old options </li>\n<li><em>Theme Skinning</em> – Earlier you had a tab called <em>Theme Skinning</em> under <em>Visual Effects</em>. <em>Theme Skinning</em> is now a section of its own and deals almost explicitly with setting up the colors of various components (aka “skinning”). All former individual sub-sections under the old <em>Theme Skinning</em> are now tabs under the new <em>Theme Skinning</em>. For example you have <em>Body Background</em>, <em>Main Wrapper</em> etc.                   <br />The main purpose of this split was <a href="http://www.aquoid.com/news/2011/01/cant-save-your-theme-options-tweak-your-suhosin-settings/">to avoid Suhosin-related issues</a>. You can click on the “Notes” button near the section title as shown above for more information. </li>\n<li><del>Visual Effects</del> <em>Other Graphical Elements</em> – This has mostly the remainder of the items of the former <em>Visual Effects</em> section. In addition it has picked up items from the former <em>Blog Features</em> that dealt with graphical aspects, like <em>Featured Content</em>, <em>Post and Page Bylines</em>, layout options etc. You can click on the “Notes” button near the section title as shown above for more information. </li>\n<li><strike>Sidebars and Widgets</strike> <em>Sidebar Configuration</em> – This is the same as the former Sidebars and Widgets section, except for the fact that the <em>Static Tabbed Sidebar</em> has been moved from the former Blog Features page to here. </li>\n<li><strike>Blog Features</strike> <em>Back-end Settings</em> – This is a heavily stripped down version of the former <em>Blog Features</em>. Most of the older options have moved to <em>Other Graphical Elements</em>. You can click on the “Notes” button near the section title as shown above for more information. </li>\n<li><em>Templates</em> – This is the same as the old versions. </li>\n<li><em>Custom Types</em> – This is the same as the old versions. </li>\n</ol>\n</li>\n</ol>\n</li>\n<li><strong><em>No Translations             <br /></em></strong>Translations are no longer a part of the core theme. They have all been moved to the <a href="http://www.aquoid.com/news/themes/suffusion/translating-suffusion/">translations page</a>. Additionally, at no impact to you the translation text domain has changed from “suf_theme” to “suffusion”. </li>\n<li><strong><em>Changes to Default Settings</em></strong>          <br />Some changes were required to the default settings to make it pass the review process, and some others were needed for ease of use.</li>\n<ol>\n<li>JQuery Masonry is switched off by default instead of being switched on.</li>\n<li>By default both navigation menus are switched off. This was one change I did not want to make, however I did so to avoid a lengthy back and forth exchange.</li>\n</ol>\n<li>Made the blog title use h1/h2 tags instead of div tags. </li>\n<li>I have renamed the classes <code>category-info</code> and <code>tag-info</code> to <code>info-category</code> and <code>info-tag</code> respectively. This is to avoid weird styling issues if you have a category or a tag named info. Please make note of this if you have used Custom Styles for these elements. </li>\n<li><strong><em>Goodbye Marvin!             <br /></em></strong>For those familiar with lore, <a href="http://en.wikipedia.org/wiki/Marvin_the_Paranoid_Android#Film">Marvin the Paranoid Android</a> used to reassure you not to panic. Unfortunately, since the photo of Marvin was not GPL’ed, I had to remove him from the introductory screen (though I had provided the appropriate credits to Buena Vista).</li>\n</ol>\n</li>\n<li><strong><u>New Features </u></strong>\n<ol>\n<li><strong><em>Sidebar Control</em></strong>          <br />There is a new capability to control the number of sidebars on different views like the blog, category, tag, date archive and search. For example you can now have 2 sidebars across your site, but only one sidebar on the blog page. Check the settings under <em>Sidebar Configuration → Sidebar Layout</em>. All in all the ability to manage sidebars for specific pages/views has improved from previous versions, and in the next release or two you should have something very flexible. I might write up an article on how to effectively tweak sidebars shortly – let’s see. </li>\n<li>You can now upload an image directly from the options pages instead of entering a URL. Of course, entering a URL works too. </li>\n<li><strong><em>New Notifiers</em></strong>          <br />Added the following notifiers:\n<ol>\n<li><strong>New versions</strong> – Tells you when a new version is available and points you to the release notes. The reason for this is that some people complained about frequent updates (though old-timers will note that I have significantly slowed down) – this is for them to check out what the latest version has, so that they can make an informed decision about upgrading. </li>\n<li><strong>Translations</strong> – If you are using WP in a language other than Americanized English, you are pointed to the right locations to pick up the correct translations. </li>\n<li><strong>BuddyPress</strong> – If you are using BP, this provides you information about making Suffusion work with it. </li>\n</ol>\n</li>\n<li>Added options to control the “Posted By” format. See <em>Other Graphical Elements → Post and Page Bylines</em> for more information. </li>\n<li>Added better WPML integration. There are texts that you set in the back-end, like the labels for your comment forms etc. I have added <a href="http://wpml.org/documentation/support/creating-multilingual-wordpress-themes/">WPML support</a> for them, so that you can translate those strings in the back-end. </li>\n<li>Added zoom-crop capability (aka proportional resizing) for images in featured content, magazine headlines and magazine excerpts. See the respective sections for setup options. </li>\n<li>There is dual JQuery UI support, for version 1.7.3 (WP 3.0.x) and 1.8.7 (WP 3.1.x). </li>\n<li>You can now control the number of headlines you want to display in the headlines section of the Magazine template. </li>\n<li>There are a couple of new filters: <code>suffusion_author_information</code> and <code>suffusion_category_information</code>. They can be used by you to tweak the information that appears at the top of the Author page and the Category pages. </li>\n<li>There is a new option to force compatibility mode in IE8. You will find the option in <em>Back-end Settings → SEO / Meta Settings</em>. </li>\n<li>There are a couple of options more dealing with the generated CSS. You can choose to cache the generated CSS, include it directly in the HTML, include it via a link etc. </li>\n</ol>\n</li>\n<li><strong><u>Bug Fixes </u></strong>\n<ol>\n<li>There was a bug earlier that was causing the title set through Suffusion’s SEO to clash with the title set by different SEO plugins. This should now be fine. </li>\n<li>In the Magazine template if you were displaying headlines, the first headline was not being selected by default. This has now been fixed. </li>\n<li>The $post variable was getting overwritten if the Ad Hoc Widgets were used to display things like featured posts or category blocks. </li>\n<li>I have fixed a bug where if you looked at a page in BP you would see an incorrect HTML title. </li>\n<li>I have included what is hopefully a patch for a WP problem (not a Suffusion problem) affecting a very small percentage of users. With the bug kicking in, users were unable to reliably see the child pages for a given page in the breadcrumb because WP fails to provide the ancestry relationships properly. </li>\n<li>I have also included a patch for a NEXTGen Gallery bug. I have often expressed my dislike for this plugin thanks to a variety of reasons. In this case including the fix at my end seems to be a much easier thing to do than wait for the NGG guys to put it in. The fix deals with viewing NGG, when used with themes employing max-width and min-width on IE8 without compatibility mode.</li>\n</ol>\n</li>\n<li><strong><u>Removed Options</u></strong>       <br />I have decided that I will periodically do a review of redundant options in the theme and cull them. Options that have much better plugin-based alternatives and options that have significant maintenance overhead will be removed.      <br /> \n<ol>\n<li><span style="color: red">Compression options for JS, CSS and the site as a whole have been removed.</span> Sorry, but those serve very limited functionality and are incapable of generating compressed content for files from external plugins. If you are looking to do any of these, you can try using W3 Total Cache or some similar plugin. The only compression-specific option introduced is to minify the generated CSS into 1 line, so that you don’t add hundreds of lines into your source code – just one long line will be present. </li>\n<li>Removed the option to load JQuery via CDN. This was becoming extremely ungainly. If you want to use CDN versions, please use a plugin. </li>\n</ol>\n</li>\n</ol>\n<p> I do understand that this is a pretty big release. So if you have upgraded and something has broken badly, please do not hesitate to downgrade (and report the problem on the <a href="http://www.aquoid.com/forum">Support Forum</a>). This isn’t meant to alarm you, for most code-related issues can be fixed and I have taken a lot of care to keep the code good. This is just to assuage your concerns that if something goes wrong, it makes best sense to follow the advice on the introductory page of the options: Don’t Panic.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2011/02/suffusion-version-3-7-5/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"17";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:5;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2010/12/suffusion-version-3-7-3/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2010/12/suffusion-version-3-7-3/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 Dec 2010 15:47:42 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://www.aquoid.com/news/?p=966";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:401:"Version 3.7.3 is another security patch that was released yesterday. The following are the changes: Apparently there was a problem with my checked in code in 3.7.2, so the site optimization check for CSS files didn&#8217;t go through correctly. This has now been corrected. I fixed a problem where the edit link for pages was <a href=\'http://aquoid.com/news/2010/12/suffusion-version-3-7-3/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:432:"<p>Version 3.7.3 is another security patch that was released yesterday. The following are the changes:</p>\n<ol>\n<li>Apparently there was a problem with my checked in code in 3.7.2, so the site optimization check for CSS files didn&#8217;t go through correctly. This has now been corrected.</li>\n<li>I fixed a problem where the edit link for pages was not clickable.</li>\n</ol>\n<p>You are strongly encouraged to do this upgrade.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2010/12/suffusion-version-3-7-3/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"31";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:6;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.2";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2010/12/suffusion-version-3-7-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2010/12/suffusion-version-3-7-2/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 16 Dec 2010 14:51:01 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://www.aquoid.com/news/?p=962";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:411:"For once this is an important security patch, hence I made this release by disrupting my regular theme development. Here are the changes: Added some security checks to ensure that the site optimization activities would take only CSS files for compression/zipping. Fixed a bug with the byline pullout in IE7, where the pullout was lying <a href=\'http://aquoid.com/news/2010/12/suffusion-version-3-7-2/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:763:"<p>For once this is an important security patch, hence I made this release by disrupting my regular theme development. Here are the changes:</p>\n<ol>\n<li>Added some security checks to ensure that the site optimization activities would take only CSS files for compression/zipping.</li>\n<li>Fixed a bug with the byline pullout in IE7, where the pullout was lying over the content.</li>\n<li>Fixed a bug with the SEO settings where if the theme&#8217;s SEO was disabled, it was not printing any title.</li>\n<li>Changed a Twitter icon file name to have only lower case characters, so that it works with all operating systems</li>\n</ol>\n<p>I encourage you to download this patch. For now the translations are in the theme. I will remove them from the next version.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2010/12/suffusion-version-3-7-2/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"11";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:7;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.7.1";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2010/11/suffusion-version-3-7-1/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2010/11/suffusion-version-3-7-1/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 30 Nov 2010 17:14:21 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.aquoid.com/news/2010/11/suffusion-version-3-7-1/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:426:"Suffusion Version 3.7.1 was released earlier today. These are the key changes in this version: New Features There were a handful of new features in this release Pullout-style Bylines I added a new way to display page and post byline information (the byline information comprises of “Posted By”, “Category”, “Tag” etc). You can now display <a href=\'http://aquoid.com/news/2010/11/suffusion-version-3-7-1/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:10766:"<p>Suffusion Version 3.7.1 was released earlier today. These are the key changes in this version:</p>\n<ol>\n<li><strong><u>New Features</u></strong>       <br />There were a handful of new features in this release\n<ol>\n<li><strong>Pullout-style Bylines</strong>           <br />I added a new way to display page and post byline information (the byline information comprises of “Posted By”, “Category”, “Tag” etc). You can now display the information as a “pullout” instead of in the corners. Here is a snapshot of how this looks:           <br /><a href="http://www.aquoid.com/news/wp-content/uploads/2010/11/pulloutdate.jpg"><img title="pullout-date" style="border-top-width: 0px; display: inline; border-left-width: 0px; border-bottom-width: 0px; border-right-width: 0px" height="257" alt="pullout-date" src="http://www.aquoid.com/news/wp-content/uploads/2010/11/pulloutdate_thumb.jpg" width="276" border="0" /></a>           <br />For the Minima skin the pullouts are enabled by default. If you don’t like it, or if you like it enough to enable it for other skins, go to <em>Blog Features → Post and Page Bylines → Position of Meta Information (including date)</em> and pick how you want to show it.           <br />Note that with this <strong>you can now display the publishing date of the post for the Minima skin</strong>, which was earlier not possible without a hack. </li>\n<li><strong>New Attachment Template </strong>          <br />Suffusion earlier used to default to a generic attachment page. In this release there is a special attachment template that displays an apt icon for the type of attachment you have. I have made this functionality extremely flexible. For example if your attachment is an audio file, you can set the attachment page to display an embedded player to play the file. If your attachment is an image file you can choose to show EXIF data for the image.           <br />In addition, you can define your own handling functions for different mime types. There are functions existing for the basic mime types: <code>suffusion_image_attachment</code> (for image attachments), <code>suffusion_audio_attachment</code> (for audio attachments), <code>suffusion_video_attachment</code> (for video attachments), <code>suffusion_text_attachment</code> (for text attachments) and <code>suffusion_application_attachment</code> (for application attachments). You could define other functions in your child theme like <code>suffusion_vnd_ms_powerpoint_attachment</code> (for Microsoft PowerPoint attachments).           <br />You can control the settings from <em>Templates → Attachment</em>. </li>\n<li><strong>JQuery Masonry</strong>           <br /><a href="http://desandro.com/resources/jquery-masonry/">JQuery Masonry</a> is a very interesting add-on that I had been wanting to add for a while now. This release I finally was able to get it in. This add-on automatically adjusts layout for floated elements. So you will not see fewer empty spaces in the horizontal widget areas (Widget Area Below Header etc), when the widgets are of different heights. </li>\n<li><strong>New Filter Hooks</strong>           <br />A lot of new filter hooks were added for better child theme support:\n<ol>\n<li><code>suffusion_can_display_top_navigation</code> </li>\n<li><code>suffusion_can_display_main_navigation</code> </li>\n<li><code>suffusion_can_display_sliding_panel</code> </li>\n<li><code>suffusion_can_display_left_sidebars</code> </li>\n<li><code>suffusion_can_display_right_sidebars</code> </li>\n<li><code>suffusion_can_display_widgets_above_header</code> </li>\n<li><code>suffusion_can_display_widget_area_below_header</code> </li>\n<li><code>suffusion_can_display_widget_area_above_footer</code> </li>\n<li><code>suffusion_can_display_open_header</code> </li>\n<li><code>suffusion_can_display_closed_header</code> </li>\n<li><code>suffusion_can_display_breadcrumb_navigation</code> </li>\n<li><code>suffusion_can_display_hierarchical_navigation</code> </li>\n</ol>\n<p> If you are using a child theme, you can hook in your custom functions through these and prevent a particular widget area from being displayed. </li>\n</ol>\n</li>\n<li><strong><u>Changed Functionality</u></strong>       <br />This is mostly technical mumbo-jumbo, so you can skip this section if you are not interested.       <br /> \n<ol>\n<li><strong>Selective removal of backward compatibility</strong>           <br />I have removed the following as per <a href="http://www.aquoid.com/news/2010/11/phasing-out-old-wordpress-version-support/">my previous announcement</a>:\n<ol>\n<li><code>function_exists</code> checks for functions such as <code>register_sidebar</code> and <code>dynamic_sidebar</code>. These functions have existed since version 2.2 of WP and hence a <code>function_exists</code> check for these was overkill. </li>\n<li>Some other checks using <code>function_exists</code> have been removed, where very old WP functions were being checked for existence. </li>\n<li>A call to <code>automatic_feed_links</code> has been removed. This was a weird requirement, since the replacement for this function has only been available since WP 3.0, so for backward compatibility up to 2.9, I had to fall back on an older approach! </li>\n</ol>\n</li>\n<li><strong>Replacement with new functions</strong>           <br />The following functions from older versions of WP have been replaced with better/new variants, as per <a href="http://codex.wordpress.org/Theme_Review">Theme Review</a> recommendations:\n<ol>\n<li><code>get_option(&quot;home&quot;)</code> → <code>home_url()</code> </li>\n<li><code>bloginfo(&quot;template_directory&quot;)</code> → <code>get_template_directory_uri()</code> </li>\n<li><code>bloginfo(&quot;stylesheet_directory&quot;)</code> → <code>get_stylesheet_directory_uri()</code> </li>\n<li><code>get_bloginfo(&quot;rss2_url&quot;)</code> → <code>get_feed_link(&quot;rss2&quot;)</code> </li>\n</ol>\n</li>\n<li><strong>CSS Optimization</strong>           <br />I have dome a good bit of CSS optimization by using a generic class for sidebars. I will be doing further optimizations to reduce CSS size in the next few releases. </li>\n</ol>\n</li>\n<li><strong>Bug Fixes</strong>\n<ol>\n<li>The biggest bug fix for this release was for one that was causing the Double Right Sidebar layout to position the sidebars outside the content. </li>\n<li>Thanks to a <a href="http://www.aquoid.com/forum/viewtopic.php?f=2&amp;t=2395#p14270">tip from one user</a> on the support forum, I managed to fix an unexpected bug with the Google Translator widget not working. That has now been fixed and it works as expected. </li>\n<li>There was a bug due to which disabling Suffusion’s SEO settings was not working for document titles. This has been fixed. </li>\n<li>There are a couple of rendering rendering issues on WebKit-based browsers (Safari and Chrome) that have been fixed. The first was a gap of 2 pixels between the bottom of the navigation bar items and the lower border of the navigation bars. The second was where setting the CSS max-width and min-width parameters with a fixed width layout was causing issues. </li>\n<li>Under some settings the navigation bar was not stretching across the width of the wrapper. This too has been fixed. </li>\n<li>The HTML attribute “height” has been removed from image HTML tags. This makes sure that the aspect ratio is preserved if you have a large image and it is being scaled down to fit into the dimensions of your content so that it doesn’t overflow. </li>\n<li>Another minor bug fix was where the home page wasn’t getting highlighted if it was a text link. </li>\n<li>Under certain rare cases there was a debug message showing up saying “Call-time pass-by-reference has been deprecated”. One such case was <a href="http://www.aquoid.com/forum/viewtopic.php?f=2&amp;t=3036&amp;p=13636#p13475">when the WP-United plugin was being used</a>. I put in some code so that this wouldn’t happen, so hopefully this bug is now fixed. </li>\n</ol>\n</li>\n</ol>\n<p>Now for some upcoming changes. Note that these changes are quite high impact, however they haven’t been made yet. </p>\n<ol>\n<li><strong>Removal of TimThumb Support</strong>       <br /><a href="http://www.darrenhoyt.com/2008/04/02/timthumb-php-script-released/">TimThumb</a> is the most widely used open-source PHP-based image resizing script available. But for various reasons the script doesn’t find favour with the WP theme approvers. Their requirement is that if your theme is not backwards compatible you MUST use WP’s native “post_thumbnail” feature. That would have been fine in the normal course of things, except that this is a fairly half-baked feature in WP at present. It has several shortcomings:\n<ol>\n<li>It doesn’t apply to custom fields. So you cannot use it to have one thumbnail for an excerpt, a different thumbnail for the same post in the featured post section and yet another picture in the main content. </li>\n<li>It is not dynamic. In other words, images of a particular size are generated when a post is saved, but if you were to demand an image of a different size, you would have to first register that size, then fetch the generated image. This is a double-edged shortcoming, though. It prevents users from specifying any size they want and filling up the WP installation’s folder with all the generated images. </li>\n<li>Not being dynamic presents another challenge. Existing posts in your blog will not work without being modified specifically to work with the post_thumbnail functionality. That is a real pain. </li>\n</ol>\n<p> Nonetheless, this is something that has to be fixed, because the theme reviewers are planning to completely outlaw TimThumb in a few weeks. I am working on some alternatives, so hopefully I will have something by the next release. </li>\n<li><strong>Moving Translations out of the Core Theme</strong>      <br />Suffusion has translations in 23 different languages at the time of writing this post. Though this means the theme has an excellent user base, it also means that the zipped theme file I upload to the repository is around 400KB larger than it could have been.      <br /><strong>So I am going to keep the translation files separate from the main theme</strong>. That would require you to download the translation that you need explicitly from this site. Luckily the translations don’t change very often, so this is mostly an infrequent annoyance. Version 3.7.1 had some translation-related changes, so I am expecting translators to post their updates. Once they do so, I will distribute them here so that you can make the update as appropriate.</li>\n</ol>\n<p>That’s it for this release. Keep watching this space for the two main items I wrote about above.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2010/11/suffusion-version-3-7-1/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"43";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:8;a:6:{s:4:"data";s:47:"\n		\n		\n		\n		\n		\n				\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.6.9";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2010/11/suffusion-version-3-6-9/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2010/11/suffusion-version-3-6-9/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 11 Nov 2010 17:02:15 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:3:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:5:"Menus";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:9:"Suffusion";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.aquoid.com/news/2010/11/suffusion-version-3-6-9/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:411:"Before I begin about this release, I would first like to apologize to all people whose layouts broke due to the last release. As it turns out I had not tested certain configurations involving the static Tabbed Sidebar, which resulted in all people using this feature having their sites become train-wrecks. Disabling the Tabbed Sidebar <a href=\'http://aquoid.com/news/2010/11/suffusion-version-3-6-9/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:4892:"<p>Before I begin about this release, I would first like to apologize to all people whose layouts broke due to the last release. As it turns out I had not tested certain configurations involving the static <em>Tabbed Sidebar</em>, which resulted in all people using this feature having their sites become train-wrecks. Disabling the <em>Tabbed Sidebar</em> would have fixed the issue for all affected people, but there was no way you as a user could have known that.</p>\n<p>Anyway, this release is a bug-fix release and there are <strong>no</strong> new features. Here are the fixes:</p>\n<ol>\n<li>Layout bugs\n<ol>\n<li>The biggest issue – wonky layouts upon activation of the <em>Tabbed Sidebar –</em> has been fixed. There is one exception – if you are using IE6 (yes, that fossil) and you have the <em>Tabbed Sidebar</em> on <em>and</em> your <em>Tabbed Sidebar</em> is on the left side <em>and</em> you have at least one sidebar on the left site, then your left sidebar will render incorrectly on IE6 (only on IE6). I spent some time trying to figure this out, but gave up because I had to get this release out early and this particular combination has an extremely low probability of occurring. Otherwise I have hopefully resolved all issues on all browsers regarding this mishap. </li>\n<li>The <em>Widget Area Below Header</em> was not spanning the full width of the wrapper and was showing a blank space on the side. </li>\n<li>The <em>Widget Area Above Footer</em> was overlapping the right sidebar if the sidebar was longer than the content. </li>\n<li>The <em>No Sidebars</em> template was showing up with empty space on the side. </li>\n<li>In the “Tiles” layout excerpt images were becoming very tiny because the widths were computing incorrectly. </li>\n</ol>\n</li>\n<li>If you had defined more than one WP 3.0 Menu, each menu item was getting repeated multiple times in the navigation bar. This has been fixed too. </li>\n<li>There was a bug that was preventing the post footer from appearing in the archive view (front page, category, date archive, tag etc). So if you had Tags or “Posted By” at the bottom of a post, that wasn’t being displayed. This now works. </li>\n<li>There was a very old bug where the excerpt title in the “Tiles” layout where the header of excerpts wasn’t reading the alignment setting correctly. Instead it was borrowing the alignment of Magazine excerpts. </li>\n</ol>\n<p>One point I would like to highlight – often when you upgrade your theme it apparently breaks your layout, while in truth there is nothing wrong with it. In such cases try out a few very simple things. First and foremost, clean out your browser’s cache and reload your page. Second, if you have a caching plugin make sure that you rebuild its cache, otherwise it will serve content that is not current.</p>\n<p>I also thought I should highlight what some known issues are. There are 2, actually, both of which are JavaScript-related:</p>\n<ol>\n<li>At some point in the last 3 releases the Google Translator widget stopped working. I have no idea why, since I haven’t changed anything there. If you were looking for this feature to work I encourage you to look for some free plugin to help you there. </li>\n<li>At some point in the last few months the Fade / delay effect on the navigation menu stopped working. Again, I have no idea why. Since this is a very low impact issue I didn’t spend an excruciating amount of time trying to resolve this. </li>\n</ol>\n<p>Another aspect I wanted to highlight was regarding my comment in my previous post, about “Rolled up menus”. A few users had difficulty understanding the concept, so I thought I will explain it here. To create a new dummy node:</p>\n<ol>\n<li>Go to <em>Appearance → Menus</em> and open up your menu. </li>\n<li>Create a new menu item using a <em>Custom Link</em>.\n<ol>\n<li>For the URL specify #. Make sure you delete the “http://” that sits there by default </li>\n<li>For the Label put in whatever you want to name your root node. </li>\n<li>Add to Menu </li>\n</ol>\n</li>\n<li>Once added, move this item to the top of the list. </li>\n<li>Now, indent every other item under this top item. This way each other node is a child of your newly created root. Remember to indent – <strong>this is important</strong>. </li>\n<li>That’s it. Since you have set the URL to be “#” Suffusion knows that it shouldn’t open any page for it. All other items are listed as children of this new node. </li>\n</ol>\n<p>That’s it for this release. I am hoping this will smooth over the rough edges of 3.6.8. I will keep subsequent releases smaller in scope, though, quite frankly I don’t foresee <em>anything</em> being so large in scope.</p>\n<p>Over the next few weeks I will focus on building a proper plugin for Suffusion and BP compatibility, assuming that the support queue for 3.6.9 isn’t huge.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2010/11/suffusion-version-3-6-9/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"30";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:9;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Suffusion Version 3.6.8";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:55:"http://aquoid.com/news/2010/11/suffusion-version-3-6-8/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:64:"http://aquoid.com/news/2010/11/suffusion-version-3-6-8/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 08 Nov 2010 06:07:16 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:14:"Theme Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:59:"http://www.aquoid.com/news/2010/11/suffusion-version-3-6-8/";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:389:"After what seems like ages, here is a new version of Suffusion. As already mentioned, this has been a very very code-intensive release because of the nature of the changes. These are the main changes in this release: New Features The following were added in this release: Fluid Width – By far the biggest change <a href=\'http://aquoid.com/news/2010/11/suffusion-version-3-6-8/\'>[...]</a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:8:"Sayontan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:6575:"<p>After what seems like ages, here is a new version of Suffusion. As already mentioned, this has been a very very code-intensive release because of the nature of the changes.</p>\n<p>These are the main changes in this release:</p>\n<ol>\n<li><strong><u>New Features</u></strong>       <br />The following were added in this release:\n<ol>\n<li><strong>Fluid Width</strong> – By far the biggest change in Suffusion since the inclusion of options in the very second release. This change required me to <a href="http://www.aquoid.com/news/2010/10/an-update-on-suffusion-part-2/">overhaul the HTML structure of the theme</a> and always put the content before the sidebars, then do massive amounts of testing. While I put in every bit of effort required to get this working as per expectations, <strong>if you find something that is not working as you expect, please let me know</strong>. I will be very happy to fix it. </li>\n<li><strong>Improved Menus</strong> – In any other release this would have been the prima donna. But as it stands, this has been relegated to second position. Now you have even better control of your navigation menus, in terms of the number of options you can pick from:\n<ol>\n<li><em>Include all, ignoring next option</em> </li>\n<li><em>Include selections from the next option</em> </li>\n<li><em>Exclude all, ignoring next option</em> <strong>(New)</strong> </li>\n<li><em>Exclude selections from the next option</em> <strong>(New)</strong> </li>\n</ol>\n<p> The new options can be better understood in context of some major code reengineering. Earlier I had a very comprehensive menu-building code, that worked very intuitively. This behavior was different from WP’s default behavior. However the old code created an insane number of queries, particularly if your menu was big.           <br />In this release I have removed all my self-created code and resorted to using WP’s inbuilt functions – <code>wp_list_pages</code>, <code>wp_list_categories</code>, <code>wp_list_bookmarks</code> and <code>wp_nav_menu</code>. his significantly reduces the number of queries and the load on your server.           <br />As a tip, if you want to completely remove pages/categories/links from your menu, use the “<em>Exclude all, ignoring next option</em>” setting instead of “<em>Include selections from the next option</em>”. This is much more optimal in terms of code. </li>\n<li>You can now get rid of the HTML title that shows up when you hover over your navigation menu. Visit <em>Blog Features → Main Navigation Bar Setup → “Title” attribute upon hovering over navigation bar</em>. </li>\n<li>There was no styling available for the HTML elements <code>legend</code> and <code>fieldset</code>. CSS declarations have been added for them. </li>\n</ol>\n</li>\n<li><strong><u>Removed Features</u></strong>       <br />The following features have been removed:\n<ol>\n<li>I have removed the “rolled-up” setting for WP 3.0 menus as it is redundant. If you want to create a rolled-up menu you can automatically create a base node in the menu and add the rest of your menu under it. </li>\n<li>I have also removed the option to not use <code>body_class</code> WP function to generate classes for your body. This removal was essential because the <code>body_class</code> function is essential to the style setup for the theme. </li>\n</ol>\n</li>\n<li><strong><u>Bug Fixes</u></strong>       <br />The following bugs were fixed:\n<ol>\n<li>A fix has been included for a severe bug that was causing page templates to <a href="http://www.aquoid.com/forum/viewtopic.php?f=2&amp;t=2684&amp;start=0">max out at a width of 600px</a>. The bug was caused by incorrectly applying filters to the sidebars and templates. </li>\n<li>The following navigation menu-related bugs have been fixed:\n<ol>\n<li>Selected navigation bar items (Pages, Categories and WP 3.0 menus) were not getting highlighted in the Minima skin. </li>\n<li>Selected navigation bar items for WP 3.0 menus were not getting highlighted across any skin. </li>\n<li>The values set for highlighting in <em>Visual Effects → Theme Skinning</em> were not being accurately reflected. </li>\n</ol>\n</li>\n<li>The following BuddyPress-related bugs have been fixed:\n<ol>\n<li>In various BP screens, if something was selected from a drop-down list (like filters, or sort criteria), nothing was happening. The correct AJAX calls for this have been included. </li>\n<li>The <em>Create Profile</em> and <em>Edit Profile</em> pages in BP were not rendering properly. This has been fixed. </li>\n<li>Messages in the inbox etc. were not being styled properly. This has been addressed. </li>\n</ol>\n</li>\n<li>There was a bug in the List Layout style, which was offsetting the posts by 1 if all posts were not being displayed. In other words, the top post was not being displayed, and if there were&#160; <em>N+1</em> posts in all and each page was to display <em>N</em> posts, the second page was showing an error. This has been rectified. </li>\n<li>Links in featured content were not getting the right color. Again, this has been fixed. </li>\n<li>There was an error in the <code>charset</code> syntax in <em>header.php</em>, <em>style.php</em> and <em>rounded-corners.php</em>. This wasn’t impacting anything as such, but it has been rectified nonetheless. </li>\n<li>In the options pages if you put in 0 as a value for some dimensions it wasn’t being read correctly. I have changed the code to handle this. </li>\n</ol>\n</li>\n<li><strong><u>Changes</u></strong>\n<ol>\n<li>The comments section has been revamped to look better and to facilitate better styling. There is now a custom callback function invoked from there. </li>\n<li>As per the <a href="http://codex.wordpress.org/Theme_Review#Credit_links">theme review guidelines</a> I had to change the credit link at the bottom. It now just links to the Suffusion home page and not <a href="http://mynethome.net/blog">my home page</a>. </li>\n<li>Somewhat whimsically I have changed the default font from Arial to Trebuchet. You can however switch back to Trebuchet if you want, from the <em>Visual Effects → Body Font Customization</em> options. </li>\n<li>You now will not see any version tag appended to JS files included by the theme. </li>\n<li>The Spanish and French translations have been updated. Thanks to <a href="http://www.traduction.biz/">David</a> for his modifications of the French translation! </li>\n</ol>\n</li>\n</ol>\n<p>I will soon update the Suffusion BP Pack so that you can make use of the new changes to the core theme. I will keep you posted.</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:60:"http://aquoid.com/news/2010/11/suffusion-version-3-6-8/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:2:"37";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}s:27:"http://www.w3.org/2005/Atom";a:1:{s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:0:"";s:7:"attribs";a:1:{s:0:"";a:3:{s:4:"href";s:52:"http://aquoid.com/news/category/theme-releases/feed/";s:3:"rel";s:4:"self";s:4:"type";s:19:"application/rss+xml";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:44:"http://purl.org/rss/1.0/modules/syndication/";a:2:{s:12:"updatePeriod";a:1:{i:0;a:5:{s:4:"data";s:6:"hourly";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:15:"updateFrequency";a:1:{i:0;a:5:{s:4:"data";s:1:"1";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:8:{s:4:"date";s:29:"Wed, 13 Jul 2011 09:31:16 GMT";s:6:"server";s:6:"Apache";s:10:"x-pingback";s:33:"http://aquoid.com/news/xmlrpc.php";s:4:"etag";s:34:""6befd40e6f357c3fc5f6c7977da2b924"";s:13:"last-modified";s:29:"Mon, 11 Jul 2011 22:23:25 GMT";s:4:"vary";s:15:"Accept-Encoding";s:10:"connection";s:5:"close";s:12:"content-type";s:23:"text/xml; charset=UTF-8";}s:5:"build";s:14:"20090627192103";}', 'no'); 
