INSERT INTO `wp_posts` VALUES (26, 1, '2011-02-05 13:44:24', '2011-02-05 21:44:24', 'It\'s not easy imagining them. But it can get better with practice. And that\'s what I\'ve been doing. An excellent accompanying read is Force : Dynamic Life Drawing for Animators. It\'s one of those books that\'s perfect for kicking you out of a rut, inspiring you to loosen your strokes. It\'s worth several rereads; I\'ve only skimmed through some parts of it, and they are immediately useful.\r\n\r\nI\'d say there are several ways of approaching drawing/sketching that I\'ve seen so far. Each one of them is useful in its own right, but the real progress happens when you start to mix and match them together. Specifically, I\'m talking about:\r\n<ul>\r\n	<li>The skeleton/stick figure approach : Very good for initial posing. Translates poorly to foreshortening exercises (at least initially)</li>\r\n	<li>The anatomy approach : Ranges from knowing a few basic landmark muscle groups to very detailed knowledge of musculature. Very good for capturing volume and outline. Requires some practice to apply to foreshortening exercises.</li>\r\n	<li>The blob/cylinder approach : Very good for indicating foreshortening before more detail work. Not so good at capturing a realistic outline.</li>\r\n	<li>The force approach : Almost a meta-approach which can be used to validate any pose you can think of. Good for dissolving stiff poses or adding more dynamics to the figure. Can be used to exaggerate a pose greatly.</li>\r\n</ul>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/invented-poses/poses1.jpg" alt="" height="35%" width="35%"/>\r\nI\'ll probably doing a lot more of figure drawing; so I\'ve set up a new <a href="http://avishek.net/plogger/index.php?level=album&amp;id=4">Poses Gallery</a> for reference purposes.', 'Inventing poses', 0, '', 'inherit', 'open', 'open', '', '16-revision-8', '', '', '2011-02-05 13:44:24', '2011-02-05 21:44:24', '', 16, 'http://www.avishek.net/blog/?p=26', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (27, 1, '2011-02-05 13:45:15', '2011-02-05 21:45:15', 'It\'s not easy imagining them. But it can get better with practice. And that\'s what I\'ve been doing. An excellent accompanying read is Force : Dynamic Life Drawing for Animators. It\'s one of those books that\'s perfect for kicking you out of a rut, inspiring you to loosen your strokes. It\'s worth several rereads; I\'ve only skimmed through some parts of it, and they are immediately useful.\r\n\r\nI\'d say there are several ways of approaching drawing/sketching that I\'ve seen so far. Each one of them is useful in its own right, but the real progress happens when you start to mix and match them together. Specifically, I\'m talking about:\r\n<ul>\r\n	<li>The skeleton/stick figure approach : Very good for initial posing. Translates poorly to foreshortening exercises (at least initially)</li>\r\n	<li>The anatomy approach : Ranges from knowing a few basic landmark muscle groups to very detailed knowledge of musculature. Very good for capturing volume and outline. Requires some practice to apply to foreshortening exercises.</li>\r\n	<li>The blob/cylinder approach : Very good for indicating foreshortening before more detail work. Not so good at capturing a realistic outline.</li>\r\n	<li>The force approach : Almost a meta-approach which can be used to validate any pose you can think of. Good for dissolving stiff poses or adding more dynamics to the figure. Can be used to exaggerate a pose greatly.</li>\r\n</ul>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/invented-poses/poses1.jpg" alt="" height="30%" width="30%"/>\r\nI\'ll probably doing a lot more of figure drawing; so I\'ve set up a new <a href="http://avishek.net/plogger/index.php?level=album&amp;id=4">Poses Gallery</a> for reference purposes.', 'Inventing poses', 0, '', 'inherit', 'open', 'open', '', '16-revision-9', '', '', '2011-02-05 13:45:15', '2011-02-05 21:45:15', '', 16, 'http://www.avishek.