INSERT INTO `wp_posts` VALUES (29, 2, '2011-02-05 13:46:42', '2011-02-05 21:46:42', 'It\'s not easy imagining them. But it can get better with practice. And that\'s what I\'ve been doing. An excellent accompanying read is Force : Dynamic Life Drawing for Animators. It\'s one of those books that\'s perfect for kicking you out of a rut, inspiring you to loosen your strokes. It\'s worth several rereads; I\'ve only skimmed through some parts of it, and they are immediately useful.\r\n\r\nI\'d say there are several ways of approaching drawing/sketching that I\'ve seen so far. Each one of them is useful in its own right, but the real progress happens when you start to mix and match them together. Specifically, I\'m talking about:\r\n<ul>\r\n	<li><strong>The skeleton/stick figure approach</strong> : Very good for initial posing. Translates poorly to foreshortening exercises (at least initially)</li>\r\n	<li><strong>The anatomy approach</strong> : Ranges from knowing a few basic landmark muscle groups to very detailed knowledge of musculature. Very good for capturing volume and outline. Requires some practice to apply to foreshortening exercises.</li>\r\n	<li><strong>The blob/cylinder approach</strong> : Very good for indicating foreshortening before more detail work. Not so good at capturing a realistic outline.</li>\r\n	<li><strong>The force approach</strong> : Almost a meta-approach which can be used to validate any pose you can think of. Good for dissolving stiff poses or adding more dynamics to the figure. Can be used to exaggerate a pose greatly.</li>\r\n</ul>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/invented-poses/poses1.jpg" alt=""/>\r\nI\'ll probably doing a lot more of figure drawing; so I\'ve set up a new <a href="http://avishek.net/plogger/index.php?level=album&amp;id=4">Poses Gallery</a> for reference purposes.', 'Inventing poses', 0, '', 'inherit', 'open', 'open', '', '16-revision-11', '', '', '2011-02-05 13:46:42', '2011-02-05 21:46:42', '', 16, 'http://www.avishek.net/blog/?p=29', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (30, 2, '2011-02-05 13:49:23', '2011-02-05 21:49:23', 'It\'s not easy imagining them. But it can get better with practice. <a href="http://avishek.net/plogger/index.php?level=album&id=4">And that\'s what I\'ve been doing</a>. An excellent accompanying read is Force : Dynamic Life Drawing for Animators. It\'s one of those books that\'s perfect for kicking you out of a rut, inspiring you to loosen your strokes. It\'s worth several rereads; I\'ve only skimmed through some parts of it, and they are immediately useful.\r\n\r\nI\'d say there are several ways of approaching drawing/sketching that I\'ve seen so far. Each one of them is useful in its own right, but the real progress happens when you start to mix and match them together. Specifically, I\'m talking about:\r\n<ul>\r\n	<li><strong>The skeleton/stick figure approach</strong> : Very good for initial posing. Translates poorly to foreshortening exercises (at least initially)</li>\r\n	<li><strong>The anatomy approach</strong> : Ranges from knowing a few basic landmark muscle groups to very detailed knowledge of musculature. Very good for capturing volume and outline. Requires some practice to apply to foreshortening exercises.</li>\r\n	<li><strong>The blob/cylinder approach</strong> : Very good for indicating foreshortening before more detail work. Not so good at capturing a realistic outline.</li>\r\n	<li><strong>The force approach</strong> : Almost a meta-approach which can be used to validate any pose you can think of. Good for dissolving stiff poses or adding more dynamics to the figure. Can be used to exaggerate a pose greatly.</li>\r\n</ul>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/invented-poses/poses1.jpg" alt="" ref="http://avishek.net/plogger/"/>\r\nI\'ll probably doing a lot more of figure drawing; so I\'ve set up a new <a href="http://avishek.net/plogger/index.php?level=album&amp;id=4">Poses Gallery</a> for reference purposes.', 'Inventing poses', 0, '', 'inherit', 'open', 'open', '', '16-revision-12', '', '', '2011-02-05 13:49:23', '2011-02-05 21:49:23', '', 16, 'http://www.avishek.net/blog/?p=30', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (31, 2, '2011-02-05 13:50:45', '2011-02-05 21:50:45', 'It\'s not easy imagining them. But it can get better with practice. <a href="http://avishek.net/plogger/index.php?level=album&id=4">And that\'s what I\'ve been doing</a>. An excellent accompanying read is Force : Dynamic Life Drawing for Animators. It\'s one of those books that\'s perfect for kicking you out of a rut, inspiring you to loosen your strokes. It\'s worth several rereads; I\'ve only skimmed through some parts of it, and they are immediately useful.\r\n\r\nI\'d say there are several ways of approaching drawing/sketching that I\'ve seen so far. Each one of them is useful in its own right, but the real progress happens when you start to mix and match them together. Specifically, I\'m talking about:\r\n<ul>\r\n	<li><strong>The skeleton/stick figure approach</strong> : Very good for initial posing. Translates poorly to foreshortening exercises (at least initially)</li>\r\n	<li><strong>The anatomy approach</strong> : Ranges from knowing a few basic landmark muscle groups to very detailed knowledge of musculature. Very good for capturing volume and outline. Requires some practice to apply to foreshortening exercises.</li>\r\n	<li><strong>The blob/cylinder approach</strong> : Very good for indicating foreshortening before more detail work. Not so good at capturing a realistic outline.</li>\r\n	<li><strong>The force approach</strong> : Almost a meta-approach which can be used to validate any pose you can think of. Good for dissolving stiff poses or adding more dynamics to the figure. Can be used to exaggerate a pose greatly.</li>\r\n</ul>\r\n<a href="http://avishek.net/plogger/"><img src="http://avishek.net/plogger/plog-content/images/sketch-collection/invented-poses/poses1.jpg" alt=""/></a>\r\nI\'ll probably doing a lot more of figure drawing; so I\'ve set up a new <a href="http://avishek.net/plogger/index.php?level=album&amp;id=4">Poses Gallery</a> for reference purposes.', 'Inventing poses', 0, '', 'inherit', 'open', 'open', '', '16-revision-13', '', '', '2011-02-05 13:50:45', '2011-02-05 21:50:45', '', 16, 'http://www.avishek.net/blog/?p=31', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (32, 2, '2011-02-04 13:00:14', '2011-02-04 21:00:14', 'Ughhh, almost forgot about this place; well, better late than never.\r\n\r\nYeah, I\'m on a holiday now. And suddenly, it seems that there\'s a ton of things to do.\r\n\r\nFocusing a lot on improving my drawing/shading technique. I\'ve gone back to pencils, sworn off digital painting till I get some experience working with colors in real life. Not that prevents me from messing around with Painter. Been doing a few drawing sessions with people at work, after work; so far, the results seem encouraging, i.e., no rotten tomatoes yet.\r\n\r\nI used to hate having to get to work to scan my drawings, now I completely detest it. Firstly, I\'m too lazy to take a stroll down there while I\'m on vacation. Secondly...well, I think the first reason is good enough. So I went over to the local Croma store and snagged a HP Deskjet J610a. Primarily using it for scanning, but taking a printout should come in handy too. Installation was a snap, though the scan of the white areas of the paper have a slight sepia tone. Nothing a little color correction can\'t handle.\r\n\r\nAs a side effect of this increased drawing output, I went ahead and cleaned up the site after a (very) long time. Installed Plogger today to give the new stuff I\'ve been drawing a better presentation, threw away the old home page, et cetera. Well, at least this evening wasn\'t a total waste...\r\n\r\nAlso found the time to run all my books through the MyBookDroid app: not bad so far. The books I\'m currently reading are:\r\n<ul>\r\n	<li>Figure Drawing: Design and Invention - Michael Hampton</li>\r\n	<li>Castles: Their Construction and History - Sidney Toy</li>\r\n</ul>\r\nContinuing work on Exo next week; I want to try out an easier way of weaving IL without tacking in IL for every aspect that is specified.\r\n\r\nBeen trying out this very funny game called Magicka. I highly recommend giving it a try, it\'s hilarious, drops fantasy cliches left, right and center; and the narrator keeps insisting that the player\'s mentor \'Vlad\' is by no means a vampire.\r\n\r\nChecked out the new Incarna character creation system in EVE Online; they did a nice job of it; should be fun when they introduce in-station ambulation.', 'Unforgotten', 0, '', 'inherit', 'open', 'open', '', '14-revision-2', '', '', '2011-02-04 13:00:14', '2011-02-04 21:00:14', '', 14, 'http://www.avishek.net/blog/?p=32', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (34, 2, '2011-02-17 05:46:43', '2011-02-17 13:46:43', 'I was working through The Artist\'s Complete Guide to Facial Expression by Gary Faigin. Pretty thorough book, and the facial landmarks for different expressions are well detailed. Except that I was still having problems inventing expressions. I mean, yeah, expressions can vary a lot, but I think what I was looking for was a system using which one could \'generate\' expressions on demand, without having to copy from something.\nThe problem I see with copying is that I\'d end up copying the facial characteristics of the subject I\'m copying as well, which hardly bodes well for the (imaginary) face I\'ve cooked up. And yes, it wouldn\'t affect my drawing that much, but I was still unsatisfied with that idea.\nThis afternoon, an idea struck me: what if I used the same system I use to generate poses to generate expressions? If you really think about it, the face is just a bunch of muscles with fat over them with the layering of skin. If I could figure out the forms at the appropriate resolution, these forms could be blobs which could be displaced/deformed at will to generate expressions. Boundaries of jostling blobs basically become potential creases and wrinkles. Blobs which get squeezed on all sides by other forms bulge out.\nThe idea seems to be working.\nThe basic technique involves breaking up the \'neutral\' face into the \'forms\'. These forms may or may not correspond to muscles, but they exist.\nThe next step is to decide what expression to generate. This I do by making that face myself. Once I\'m satisfied that my expression is close enough to what I want in my drawing, I get back to paper.\nAfter this, for each of the forms I\'ve broken up the face into, I trace the corresponding motion that that form takes when I make that expression on my face. Just lightly touching the general area with your finger and making the expression is enough to give you a sense of which direction the blob is \'stretching\' or \'moving\'. That\'s usually enough to move that blob around on paper. Once done with all the blobs, generating the expression is surprisingly easy.\n\nI\'m still refining the form system. Here are some examples of the things you can do with this volumetric approach.\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions1.jpg"/>\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions2.jpg"/>\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions3.jpg"/>\n\nThe Expressions gallery is up now.', 'Facial Expressions as Volumetric Deformation and Displacements', 0, '', 'inherit', 'open', 'open', '', '33-revision', '', '', '2011-02-17 05:46:43', '2011-02-17 13:46:43', '', 33, 'http://www.avishek.net/blog/?p=34', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (35, 2, '2011-02-17 05:47:43', '2011-02-17 13:47:43', 'I was working through The Artist\'s Complete Guide to Facial Expression by Gary Faigin. Pretty thorough book, and the facial landmarks for different expressions are well detailed. Except that I was still having problems inventing expressions. I mean, yeah, expressions can vary a lot, but I think what I was looking for was a system using which one could \'generate\' expressions on demand, without having to copy from something.\nThe problem I see with copying is that I\'d end up copying the facial characteristics of the subject I\'m copying as well, which hardly bodes well for the (imaginary) face I\'ve cooked up. And yes, it wouldn\'t affect my drawing that much, but I was still unsatisfied with that idea.\nThis afternoon, an idea struck me: what if I used the same system I use to generate poses to generate expressions? If you really think about it, the face is just a bunch of muscles with fat over them with the layering of skin. If I could figure out the forms at the appropriate resolution, these forms could be blobs which could be displaced/deformed at will to generate expressions. Boundaries of jostling blobs basically become potential creases and wrinkles. Blobs which get squeezed on all sides by other forms bulge out.\nThe idea seems to be working.\nThe basic technique involves breaking up the \'neutral\' face into the \'forms\'. These forms may or may not correspond to muscles, but they exist.\nThe next step is to decide what expression to generate. This I do by making that face myself. Once I\'m satisfied that my expression is close enough to what I want in my drawing, I get back to paper.\nAfter this, for each of the forms I\'ve broken up the face into, I trace the corresponding motion that that form takes when I make that expression on my face. Just lightly touching the general area with your finger and making the expression is enough to give you a sense of which direction the blob is \'stretching\' or \'moving\'. That\'s usually enough to move that blob around on paper. Once done with all the blobs, generating the expression is surprisingly easy.\n\nI\'m still refining the form system. Here are some examples of the things you can do with this volumetric approach.\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions1.jpg"/>\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions2.jpg"/>\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions3.jpg"/>\n\nThe <a href="http://www.avishek.net/plogger/index.php?level=album&id=7">Expressions gallery</a> is up now.\n', 'Facial Expressions as Volumetric Deformation and Displacements', 0, '', 'inherit', 'open', 'open', '', '33-revision-2', '', '', '2011-02-17 05:47:43', '2011-02-17 13:47:43', '', 33, 'http://www.avishek.net/blog/?p=35', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (37, 2, '2011-02-17 05:47:45', '2011-02-17 13:47:45', 'I was working through The Artist\'s Complete Guide to Facial Expression by Gary Faigin. Pretty thorough book, and the facial landmarks for different expressions are well detailed. Except that I was still having problems inventing expressions. I mean, yeah, expressions can vary a lot, but I think what I was looking for was a system using which one could \'generate\' expressions on demand, without having to copy from something.\r\nThe problem I see with copying is that I\'d end up copying the facial characteristics of the subject I\'m copying as well, which hardly bodes well for the (imaginary) face I\'ve cooked up. And yes, it wouldn\'t affect my drawing that much, but I was still unsatisfied with that idea.\r\nThis afternoon, an idea struck me: what if I used the same system I use to generate poses to generate expressions? If you really think about it, the face is just a bunch of muscles with fat over them with the layering of skin. If I could figure out the forms at the appropriate resolution, these forms could be blobs which could be displaced/deformed at will to generate expressions. Boundaries of jostling blobs basically become potential creases and wrinkles. Blobs which get squeezed on all sides by other forms bulge out.\r\nThe idea seems to be working.\r\nThe basic technique involves breaking up the \'neutral\' face into the \'forms\'. These forms may or may not correspond to muscles, but they exist.\r\nThe next step is to decide what expression to generate. This I do by making that face myself. Once I\'m satisfied that my expression is close enough to what I want in my drawing, I get back to paper.\r\nAfter this, for each of the forms I\'ve broken up the face into, I trace the corresponding motion that that form takes when I make that expression on my face. Just lightly touching the general area with your finger and making the expression is enough to give you a sense of which direction the blob is \'stretching\' or \'moving\'. That\'s usually enough to move that blob around on paper. Once done with all the blobs, generating the expression is surprisingly easy.\r\n\r\nI\'m still refining the form system. Here are some examples of the things you can do with this volumetric approach.\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions1.jpg"/>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions2.jpg"/>\r\n<img src="http://avishek.net/plogger/plog-content/images/sketch-collection/expressions/volumetricexpressions3.jpg"/>\r\n\r\nThe <a href="http://www.avishek.net/plogger/index.php?level=album&id=7">Expressions gallery</a> is up now.\r\n', 'Facial Expressions as Volumetric Deformation and Displacements', 0, '', 'inherit', 'open', 'open', '', '33-revision-3', '', '', '2011-02-17 05:47:45', '2011-02-17 13:47:45', '', 33, 'http://www.avishek.net/blog/?p=37', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (39, 1, '2011-05-09 21:54:46', '2011-05-10 05:54:46', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<b>MediaLoadListener.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\n<code>MediaLoadListener</code> is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the <code>ImageContainer</code> class.\r\nThe <code>WaitingIndication</code> will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of <code>ImageContainer\'s</code> structure should be pretty obvious. The one thing I should point out is that <code>ImageContainer</code> could have been a <code>UIViewController</code>-derived class, since it basically manages the lifecycle of an <code>UIImageView</code>; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the <code>WaitingIndication</code> object to display itself. It then fires the <code>MediaLoadRetryTimer</code> object, which handles firing off load requests at periodic intervals.\r\nWhen and if the <code>MediaLoadRetryTimer</code> is successful in retrieving the <code>UIImage</code> object, it notifies the <code>ImageContainer</code> by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the <code>ImageContainer</code> stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of <code>MediaLoadRetryTimer</code> now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the <code>MediaLoadRetryTimer</code> object.\r\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\r\n\r\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of <code>MediaLoadRetryTimer</code>, you\'ll notice a second method called <code>go:</code>.\r\nThis is the method that <code>ImageContainer</code> calls, rather than <code>run:</code>; that internally calls <code>TimerBatcher</code>, which is how I throttle requests in this example. The source for <code>TimerBatcher</code> is below.\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n[/sourcecode]\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by <code>MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS</code>. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\r\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'publish', 'open', 'open', '', 'ios-appdev-patterns-asynchronous-image-loader', '', '', '2011-07-13 09:19:43', '2011-07-13 17:19:43', '', 0, 'http://www.avishek.net/blog/?p=39', 0, 'post', '', 0); 
INSERT INTO `wp_posts` VALUES (40, 1, '2011-05-09 03:02:52', '2011-05-09 11:02:52', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="960" height="720" />\n\nThere are a few considerations when implementing a solution like this:\n\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<code>\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n\n@protocol WaitingIndication <NSObject>\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id<WaitingIndication> waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\n@end\n\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id<MediaLoadListener> blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id<WaitingIndication> indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n		return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		NSLog(@"Found image - %@", [imageURL path]);\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n		DShowBorder(imageView.layer, orangeColor);\n}\n\n-(void) cancelIfLoading {\n    [mediaLoadRetryTimer cancel];\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n\n\n</code>\n\n\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision', '', '', '2011-05-09 03:02:52', '2011-05-09 11:02:52', '', 39, 'http://www.avishek.net/blog/?p=40', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (41, 1, '2011-05-09 03:03:02', '2011-05-09 11:03:02', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="960" height="720" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n\r\n\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-2', '', '', '2011-05-09 03:03:02', '2011-05-09 11:03:02', '', 39, 'http://www.avishek.net/blog/?p=41', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (42, 1, '2011-05-09 03:03:07', '2011-05-09 11:03:07', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="960" height="720" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n\r\n\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-3', '', '', '2011-05-09 03:03:07', '2011-05-09 11:03:07', '', 39, 'http://www.avishek.net/blog/?p=42', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (43, 1, '2011-05-09 03:12:45', '2011-05-09 11:12:45', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n\r\n\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-4', '', '', '2011-05-09 03:12:45', '2011-05-09 11:12:45', '', 39, 'http://www.avishek.net/blog/?p=43', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (44, 1, '2011-05-09 03:12:49', '2011-05-09 11:12:49', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n\r\n\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-5', '', '', '2011-05-09 03:12:49', '2011-05-09 11:12:49', '', 39, 'http://www.avishek.net/blog/?p=44', 0, 'revision', '', 0); 
