r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-7', '', '', '2011-05-09 03:37:47', '2011-05-09 11:37:47', '', 39, 'http://www.avishek.net/blog/?p=46', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (47, 1, '2011-05-09 03:41:05', '2011-05-09 11:41:05', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n<b>MediaLoadListener.h</b>\r\n\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-8', '', '', '2011-05-09 03:41:05', '2011-05-09 11:41:05', '', 39, 'http://www.avishek.net/blog/?p=47', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (48, 1, '2011-05-09 03:41:09', '2011-05-09 11:41:09', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<code>\r\n<b>MediaLoadListener.h</b>\r\n\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-9', '', '', '2011-05-09 03:41:09', '2011-05-09 11:41:09', '', 39, 'http://www.avishek.net/blog/?p=48', 0, 'revision', '', 0); 
