nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n</small>', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-10', '', '', '2011-05-09 03:41:51', '2011-05-09 11:41:51', '', 39, 'http://www.avishek.net/blog/?p=49', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (50, 1, '2011-05-09 03:41:56', '2011-05-09 11:41:56', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\nLoad request throttling: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\nMemory management: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<small>\r\n<code>\r\n<b>MediaLoadListener.h</b>\r\n\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n</small>', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-11', '', '', '2011-05-09 03:41:56', '2011-05-09 11:41:56', '', 39, 'http://www.avishek.net/blog/?p=50', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (52, 1, '2011-05-09 03:48:37', '2011-05-09 11:48:37', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<small>\n<code>\n<b>MediaLoadListener.h</b>\n\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n\n<b>WaitingIndication.h</b>\n\n@protocol WaitingIndication <NSObject>\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n\n<b>ImageContainer.h</b>\n\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id<WaitingIndication> waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\n@end\n\n<b>ImageContainer.m</b>\n\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id<MediaLoadListener> blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id<WaitingIndication> indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		NSLog(@"Found image - %@", [imageURL path]);\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n		DShowBorder(imageView.layer, orangeColor);\n}\n\n-(void) cancelIfLoading {\n    [mediaLoadRetryTimer cancel];\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n\n\n</code>\n</small>', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-13', '', '', '2011-05-09 03:48:37', '2011-05-09 11:48:37', '', 39, 'http://www.avishek.net/blog/?p=52', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (51, 1, '2011-05-09 03:44:44', '2011-05-09 11:44:44', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<small>\r\n<code>\r\n<b>MediaLoadListener.h</b>\r\n\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n		return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n</small>', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-12', '', '', '2011-05-09 03:44:44', '2011-05-09 11:44:44', '', 39, 'http://www.avishek.net/blog/?p=51', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (53, 1, '2011-05-09 03:49:25', '2011-05-09 11:49:25', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<small>\r\n<code>\r\n<b>MediaLoadListener.h</b>\r\n\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n\r\n<b>WaitingIndication.h</b>\r\n\r\n@protocol WaitingIndication <NSObject>\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n\r\n<b>ImageContainer.h</b>\r\n\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id<MediaLoadListener> blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id<WaitingIndication> indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		NSLog(@"Found image - %@", [imageURL path]);\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n		DShowBorder(imageView.layer, orangeColor);\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id<MediaLoadListener> listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id<MediaLoadListener> listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id<MediaLoadListener>) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id<MediaLoadListener>) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id<MediaLoadListener> loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@"%@", u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@"Warning...possible bad access on retry timer or timer\'s listener.");\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n</code>\r\n</small>', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-14', '', '', '2011-05-09 03:49:25', '2011-05-09 11:49:25', '', 39, 'http://www.avishek.net/blog/?p=53', 0, 'revision', '', 0); 
