     UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>ImageContainer.m</h3>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@&quot;%@&quot;, u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-23', '', '', '2011-05-09 20:48:24', '2011-05-10 04:48:24', '', 39, 'http://www.avishek.net/blog/?p=62', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (65, 1, '2011-05-09 21:02:57', '2011-05-10 05:02:57', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"][/sourcecode][/sourcecode]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id<WaitingIndication> waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\n@end\n[/sourc\n\n<b>ImageContainer.m</b>\n\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id<MediaLoadListener> blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id<WaitingIndication> indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n-(void) cancelIfLoading {\n    [mediaLoadRetryTimer cancel];\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n\n<b>MediaLoadRetryTimer.h</b>\n\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id<MediaLoadListener> listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id<MediaLoadListener> listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id<MediaLoadListener>) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n\n<b>MediaLoadRetryTimer.m</b>\n\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id<MediaLoadListener>) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id<MediaLoadListener> loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	NSLog(@"%@", u);\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n			NSLog(@"Warning...possible bad access on retry timer or timer\'s listener.");\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n\n<b>TimerBatcher.m</b>\n\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n<b>TimerBatcher.m</b>\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] >= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] >= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n\n</code>\n</small>\n</pre>\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-26', '', '', '2011-05-09 21:02:57', '2011-05-10 05:02:57', '', 39, 'http://www.avishek.net/blog/?p=65', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (64, 1, '2011-05-09 21:01:36', '2011-05-10 05:01:36', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\r\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"][/sourcecode][/sourcecode]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id<WaitingIndication> waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id<WaitingIndication> waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id<WaitingIndication>) indication;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@&quot;%@&quot;, u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-25', '', '', '2011-05-09 21:01:36', '2011-05-10 05:01:36', '', 39, 'http://www.avishek.net/blog/?p=64', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (67, 1, '2011-05-09 21:09:16', '2011-05-10 05:09:16', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n@end\n[/sourcecode]\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n-(void) cancelIfLoading {\n    [mediaLoadRetryTimer cancel];\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	NSLog(@&quot;%@&quot;, u);\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-28', '', '', '2011-05-09 21:09:16', '2011-05-10 05:09:16', '', 39, 'http://www.avishek.net/blog/?p=67', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (66, 1, '2011-05-09 21:03:18', '2011-05-10 05:03:18', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\r\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"][/sourcecode][/sourcecode]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id<MediaLoadListener>) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id<MediaLoadListener> loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@"%@", u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@"Warning...possible bad access on retry timer or timer\'s listener.");\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] >= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] >= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n\r\n</code>\r\n</small>\r\n</pre>\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-27', '', '', '2011-05-09 21:03:18', '2011-05-10 05:03:18', '', 39, 'http://www.avishek.net/blog/?p=66', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (68, 1, '2011-05-09 21:12:15', '2011-05-10 05:12:15', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\r\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n-(void) cancelIfLoading {\r\n    [mediaLoadRetryTimer cancel];\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@&quot;%@&quot;, u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-29', '', '', '2011-05-09 21:12:15', '2011-05-10 05:12:15', '', 39, 'http://www.avishek.net/blog/?p=68', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (69, 1, '2011-05-09 21:28:24', '2011-05-10 05:28:24', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaL\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	NSLog(@&quot;%@&quot;, u);\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-30', '', '', '2011-05-09 21:28:24', '2011-05-10 05:28:24', '', 39, 'http://www.avishek.net/blog/?p=69', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (70, 1, '2011-05-09 21:32:14', '2011-05-10 05:32:14', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this i\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	NSLog(@&quot;%@&quot;, u);\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-31', '', '', '2011-05-09 21:32:14', '2011-05-10 05:32:14', '', 39, 'http://www.avishek.net/blog/?p=70', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (73, 1, '2011-05-09 21:37:50', '2011-05-10 05:37:50', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\n\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nThere are two method\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-34', '', '', '2011-05-09 21:37:50', '2011-05-10 05:37:50', '', 39, 'http://www.avishek.net/blog/?p=73', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (71, 1, '2011-05-09 21:33:12', '2011-05-10 05:33:12', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\r\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\r\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@&quot;%@&quot;, u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-32', '', '', '2011-05-09 21:33:12', '2011-05-10 05:33:12', '', 39, 'http://www.avishek.net/blog/?p=71', 0, 'revision', '', 0); 
