self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\r\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	NSLog(@&quot;%@&quot;, u);\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n			NSLog(@&quot;Warning...possible bad access on retry timer or timer\'s listener.&quot;);\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-33', '', '', '2011-05-09 21:33:52', '2011-05-10 05:33:52', '', 39, 'http://www.avishek.net/blog/?p=72', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (74, 1, '2011-05-09 21:42:18', '2011-05-10 05:42:18', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\n\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the MediaLoadRetryTimer object.\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-35', '', '', '2011-05-09 21:42:18', '2011-05-10 05:42:18', '', 39, 'http://www.avishek.net/blog/?p=74', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (75, 1, '2011-05-09 21:49:43', '2011-05-10 05:49:43', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\n\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the MediaLoadRetryTimer object.\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\n\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of MediaLoadRetryTimer, you\'ll notice a second method called <code>go:</code>.\nThis is the method that ImageContainer calls, rather than <code>run:</code>; that internally calls TimerBatcher, which is how I throttle requests in this example. The source for TimerBatcher is below.\n\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]\n\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about ho', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-36', '', '', '2011-05-09 21:49:43', '2011-05-10 05:49:43', '', 39, 'http://www.avishek.net/blog/?p=75', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (77, 1, '2011-05-09 21:53:13', '2011-05-10 05:53:13', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\n\nThere are a few considerations when implementing a solution like this:\n\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\n\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\n\nA basic implementation is shown below:\n<h3>MediaLoadListener.h</h3>\n\n[sourcecode language="objc"]\n@protocol MediaLoadListener\n	-(void) mediaLoaded:(UIImage*) image;\n@end\n[/sourcecode]\n\n<h3>WaitingIndication.h</h3>\n\n[sourcecode language="objc"]\n@protocol WaitingIndication &lt;NSObject&gt;\n-(void) wait:(UIImageView*) imageView;\n-(void) doneWaiting:(UIImageView*) imageView;\n@end\n[/sourcecode]\n\n<code>MediaLoadListener</code> is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the <code>ImageContainer</code> class.\nThe <code>WaitingIndication</code> will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\n\n<h3>ImageContainer.h</h3>\n\n[sourcecode language="objc"]\n@interface ImageContainer {\n	UIImageView* imageView;\n	NSURL* imageURL;\n        UIViewContentMode fillMode;\n	id&lt;WaitingIndication&gt; waitIndication;\n}\n\n@property (nonatomic, retain) UIImageView* imageView;\n@property (nonatomic, retain)  NSURL* imageURL;\n@property (nonatomic, assign) UIViewContentMode fillMode;\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\n\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\n-(void) layoutMediaIn:(UIView*) view;\n@end\n[/sourcecode]\n\nMost of <code>ImageContainer\'s</code> structure should be pretty obvious. The one thing I should point out is that <code>ImageContainer</code> could have been a <code>UIViewController</code>-derived class, since it basically manages the lifecycle of an <code>UIImageView</code>; however, I didn\'t see it as a full-fledged controller. YMMV.\n\n<b>ImageContainer.m</b>\n\n[sourcecode language="objc"]\n@implementation ImageContainer\n@synthesize imageView;\n@synthesize imageURL;\n@synthesize fillMode;\n@synthesize waitIndication;\n\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\n    self = [super init];\n    if (self) {\n        self.imageURL = imgURL;\n        id&lt;MediaLoadListener&gt; blockSelf = self;\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\n        self.mediaLoadRetryTimer = timer;\n        self.fillMode = UIViewContentModeScaleToFill;\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\n        self.waitIndication = indication;\n        [timer release];\n        [indication release];\n\n    }\n	return self;\n}\n\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\n	self.fillMode = fillMode;\n	return self;\n}\n\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\n	self.waitIndication = indication;\n	return self;\n}\n\n-(void) layoutMediaIn:(UIView*) view {\n	UIImageView* imgView = [UIImageView new];\n	self.imageView = imgView;\n	[imgView release];\n        [waitIndication wait:imageView];\n	imageView.layer.borderWidth = 1;\n	[view addSubview:imageView];\n	[mediaLoadRetryTimer go];\n}\n\n-(void) mediaLoaded:(UIImage *)img {\n		[mediaLoadRetryTimer cancel];\n		[waitIndication doneWaiting:imageView];\n		imageView.image = img;\n        imageView.contentMode = self.fillMode;\n		imageView.layer.borderWidth = 0;\n}\n\n- (void)dealloc {\n	self.imageView = nil;\n	self.imageURL = nil;\n	self.waitIndication = nil;\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nLet\'s talk about the workflow of the entire image loading process.\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the <code>WaitingIndication</code> object to display itself. It then fires the <code>MediaLoadRetryTimer</code> object, which handles firing off load requests at periodic intervals.\nWhen and if the <code>MediaLoadRetryTimer</code> is successful in retrieving the <code>UIImage</code> object, it notifies the <code>ImageContainer</code> by sending it the  <code>mediaLoaded:</code> message.\nUpon receiving it, the <code>ImageContainer</code> stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\nWe shall look into the guts of <code>MediaLoadRetryTimer</code> now. Here\'s the code for it.\n\n<b>MediaLoadRetryTimer.h</b>\n\n[sourcecode language="objc"]\n@class TimerBatcher;\n\n@interface MediaLoadRetryTimer : NSObject {\n    NSTimeInterval timeInterval;\n	NSURL* mediaURL;\n	id&lt;MediaLoadListener&gt; listener;\n	\n	dispatch_source_t timer;\n	dispatch_block_t timerAction;\n	dispatch_queue_t queue;\n}\n\n@property (nonatomic, assign) NSTimeInterval timeInterval;\n@property (nonatomic, retain) NSURL* mediaURL;\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\n\n@property (nonatomic, assign) dispatch_source_t timer;\n@property (copy) dispatch_block_t timerAction;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\n-(void) cancel;\n-(void) go;\n-(void) safeCancelTimer;\n-(void) run;\n@end\n[/sourcecode]\n\n<b>MediaLoadRetryTimer.m</b>\n\n[sourcecode language="objc"]\n@implementation MediaLoadRetryTimer\n@synthesize timer;\n@synthesize timerAction;\n@synthesize timeInterval;\n@synthesize mediaURL;\n@synthesize listener;\n\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\n    self = [super init];\n    \n    if (self) {\n        self.timeInterval = interval;\n        self.mediaURL = mediaURL;\n        self.listener = listener;\n    }\n	\n	return self;\n}\n\n-(void) cancel {\n    [TimerBatcher complete:self];\n	self.listener = nil;\n	if (self.timerAction) {\n		[self safeCancelTimer];\n        dispatch_release(timer);\n        self.timerAction = nil;\n    }\n}\n\n-(void) safeCancelTimer {\n	if (!timer) return;\n	dispatch_source_cancel(timer);\n}\n\n-(void) go {\n	[TimerBatcher registerAs:self];\n	[TimerBatcher run:self];\n}\n\n-(void) run {\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\n	if (!timer) return;\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\n	NSURL* mediaURL = self.mediaURL;\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\n	dispatch_source_t timer = self.timer;\n	self.timerAction = ^{\n		@try {\n			if (loadListener == nil) return;\n			\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\n			UIImage* img = [UIImage imageWithData:data];\n			if (img == nil) return;\n			dispatch_source_cancel(timer);\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\n		}\n		@catch (NSException *exception) {\n		}\n	};\n	\n	dispatch_source_set_event_handler(timer, timerAction);\n	dispatch_resume(timer);\n}\n\n-(void) dealloc {\n	self.mediaURL = nil;\n	[self cancel];\n	[super dealloc];\n}\n@end\n[/sourcecode]\n\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the <code>MediaLoadRetryTimer</code> object.\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\n\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of MediaLoadRetryTimer, you\'ll notice a second method called <code>go:</code>.\nThis is the method that ImageContainer calls, rather than <code>run:</code>; that internally calls TimerBatcher, which is how I throttle requests in this example. The source for TimerBatcher is below.\n\n<b>TimerBatcher.m</b>\n\n[sourcecode language="objc"]\n@interface TimerBatcher : NSObject {\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\n+(void) run:(MediaLoadRetryTimer*) timer;\n+(void) complete:(MediaLoadRetryTimer*) timer;\n\n@end\n\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\n\nstatic NSMutableArray* inactiveTimers;\nstatic NSMutableArray* activeTimers;\nstatic NSUInteger limit;\n\n@implementation TimerBatcher\n+(void) initialize {\n	inactiveTimers = [[NSMutableArray array] retain];\n	activeTimers = [[NSMutableArray array] retain];\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\n}\n\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\n	[inactiveTimers addObject:timer];\n}\n\n+(void) run:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	if ([activeTimers count] &gt;= limit) return;\n	[activeTimers addObject:timer];\n	[inactiveTimers removeObjectAtIndex:index];\n	[timer run];\n}\n\n+(void) complete:(MediaLoadRetryTimer*) timer {\n	NSUInteger index = [activeTimers indexOfObject:timer];\n	if (index == NSNotFound) return;\n	[activeTimers removeObjectAtIndex:index];\n	if ([activeTimers count] &gt;= limit) return;\n	if ([inactiveTimers isEmpty]) return;\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\n}\n@end\n[/sourcecode]\n\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-38', '', '', '2011-05-09 21:53:13', '2011-05-10 05:53:13', '', 39, 'http://www.avishek.net/blog/?p=77', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (76, 1, '2011-05-09 21:50:09', '2011-05-10 05:50:09', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\nMediaLoadListener is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the ImageContainer class.\r\nThe WaitingIndication will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of ImageContainer\'s structure should be pretty obvious. The one thing I should point out is that ImageContainer could have been a UIViewController-derived class, since it basically manages the lifecycle of an UIImageView; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the WaitingIndicator object to display itself. It then fires the MediaLoadRetryTimer object, which handles firing off load requests at periodic intervals.\r\nWhen and if the MediaLoadRetryTimer is successful in retrieving the UIImage object, it notifies the ImageContainer by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the ImageContainer stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of MediaLoadRetryTimer now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the MediaLoadRetryTimer object.\r\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\r\n\r\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of MediaLoadRetryTimer, you\'ll notice a second method called <code>go:</code>.\r\nThis is the method that ImageContainer calls, rather than <code>run:</code>; that internally calls TimerBatcher, which is how I throttle requests in this example. The source for TimerBatcher is below.\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\r\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-37', '', '', '2011-05-09 21:50:09', '2011-05-10 05:50:09', '', 39, 'http://www.avishek.net/blog/?p=76', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (78, 1, '2011-05-09 21:53:32', '2011-05-10 05:53:32', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\n<code>MediaLoadListener</code> is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the <code>ImageContainer</code> class.\r\nThe <code>WaitingIndication</code> will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of <code>ImageContainer\'s</code> structure should be pretty obvious. The one thing I should point out is that <code>ImageContainer</code> could have been a <code>UIViewController</code>-derived class, since it basically manages the lifecycle of an <code>UIImageView</code>; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the <code>WaitingIndication</code> object to display itself. It then fires the <code>MediaLoadRetryTimer</code> object, which handles firing off load requests at periodic intervals.\r\nWhen and if the <code>MediaLoadRetryTimer</code> is successful in retrieving the <code>UIImage</code> object, it notifies the <code>ImageContainer</code> by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the <code>ImageContainer</code> stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of <code>MediaLoadRetryTimer</code> now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the <code>MediaLoadRetryTimer</code> object.\r\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\r\n\r\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of <code>MediaLoadRetryTimer</code>, you\'ll notice a second method called <code>go:</code>.\r\nThis is the method that <code>ImageContainer</code> calls, rather than <code>run:</code>; that internally calls <code>TimerBatcher</code>, which is how I throttle requests in this example. The source for <code>TimerBatcher</code> is below.\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\r\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-39', '', '', '2011-05-09 21:53:32', '2011-05-10 05:53:32', '', 39, 'http://www.avishek.net/blog/?p=78', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (79, 1, '2011-05-09 21:53:39', '2011-05-10 05:53:39', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\n<code>MediaLoadListener</code> is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the <code>ImageContainer</code> class.\r\nThe <code>WaitingIndication</code> will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of <code>ImageContainer\'s</code> structure should be pretty obvious. The one thing I should point out is that <code>ImageContainer</code> could have been a <code>UIViewController</code>-derived class, since it basically manages the lifecycle of an <code>UIImageView</code>; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the <code>WaitingIndication</code> object to display itself. It then fires the <code>MediaLoadRetryTimer</code> object, which handles firing off load requests at periodic intervals.\r\nWhen and if the <code>MediaLoadRetryTimer</code> is successful in retrieving the <code>UIImage</code> object, it notifies the <code>ImageContainer</code> by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the <code>ImageContainer</code> stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of <code>MediaLoadRetryTimer</code> now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the <code>MediaLoadRetryTimer</code> object.\r\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\r\n\r\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of <code>MediaLoadRetryTimer</code>, you\'ll notice a second method called <code>go:</code>.\r\nThis is the method that <code>ImageContainer</code> calls, rather than <code>run:</code>; that internally calls <code>TimerBatcher</code>, which is how I throttle requests in this example. The source for <code>TimerBatcher</code> is below.\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\r\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-40', '', '', '2011-05-09 21:53:39', '2011-05-10 05:53:39', '', 39, 'http://www.avishek.net/blog/?p=79', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (80, 1, '2011-05-09 21:54:22', '2011-05-10 05:54:22', 'In a content-heavy application (a news or a magazine app for example), textual content takes precedence over images in terms of loading/rendering. An acceptable solution is to load/render text and request images from the server/cache in a concurrent fashion. I use the term \'server\' in a very loose fashion, a more appropriate term is probably \'content source\', since we can retrieve this information from anything ranging from our own servers to Twitter/RSS feeds.\r\n<img alt="" src="https://docs.google.com/drawings/pub?id=1r0N72hj_-hgfGI8dN3vaqdYWhoosWv5R85z8D8ADEIM&w=960&h=720" title="AsyncImageLoader" class="alignnone" width="480" height="360" />\r\n\r\nThere are a few considerations when implementing a solution like this:\r\n\r\n<strong>Load request throttling</strong>: You\'re likely to have several images spread across pages. It is not prudent to let 50 concurrent requests fire for 50 images. You want to throttle your requests to a reasonable number. A simple example of throttling your request is shown later.\r\n\r\n<strong>Memory management</strong>: You want to gracefully handle the situation in which the loader is able to retrieve the image, but it the frame on which it is supposed to display the image (however it is implemented) has already been deallocated (for whatever reason).\r\n\r\nA basic implementation is shown below:\r\n<h3>MediaLoadListener.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol MediaLoadListener\r\n	-(void) mediaLoaded:(UIImage*) image;\r\n@end\r\n[/sourcecode]\r\n\r\n<h3>WaitingIndication.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@protocol WaitingIndication &lt;NSObject&gt;\r\n-(void) wait:(UIImageView*) imageView;\r\n-(void) doneWaiting:(UIImageView*) imageView;\r\n@end\r\n[/sourcecode]\r\n\r\n<code>MediaLoadListener</code> is the protocol which would be implemented by any class that wishes to be notified of when the image has been loaded. In our case, this will be the <code>ImageContainer</code> class.\r\nThe <code>WaitingIndication</code> will be implemented by any class that wants to show some indication in lieu of the image while we are retrieving the image.\r\n\r\n<h3>ImageContainer.h</h3>\r\n\r\n[sourcecode language="objc"]\r\n@interface ImageContainer {\r\n	UIImageView* imageView;\r\n	NSURL* imageURL;\r\n        UIViewContentMode fillMode;\r\n	id&lt;WaitingIndication&gt; waitIndication;\r\n}\r\n\r\n@property (nonatomic, retain) UIImageView* imageView;\r\n@property (nonatomic, retain)  NSURL* imageURL;\r\n@property (nonatomic, assign) UIViewContentMode fillMode;\r\n@property (nonatomic, retain) id&lt;WaitingIndication&gt; waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(UIImage*)imgURL;\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode;\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication;\r\n-(void) layoutMediaIn:(UIView*) view;\r\n@end\r\n[/sourcecode]\r\n\r\nMost of <code>ImageContainer\'s</code> structure should be pretty obvious. The one thing I should point out is that <code>ImageContainer</code> could have been a <code>UIViewController</code>-derived class, since it basically manages the lifecycle of an <code>UIImageView</code>; however, I didn\'t see it as a full-fledged controller. YMMV.\r\n\r\n<b>ImageContainer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation ImageContainer\r\n@synthesize imageView;\r\n@synthesize imageURL;\r\n@synthesize fillMode;\r\n@synthesize waitIndication;\r\n\r\n-(ImageContainer*) initWithImageURL:(NSURL*)imgURL {\r\n    self = [super init];\r\n    if (self) {\r\n        self.imageURL = imgURL;\r\n        id&lt;MediaLoadListener&gt; blockSelf = self;\r\n        MediaLoadRetryTimer* timer = [[MediaLoadRetryTimer alloc] initWithInterval:10 withMediaURL:self.imageURL withLoadListener:blockSelf];\r\n        self.mediaLoadRetryTimer = timer;\r\n        self.fillMode = UIViewContentModeScaleToFill;\r\n        id&lt;WaitingIndication&gt; indication = [LoadingRingIndication new];\r\n        self.waitIndication = indication;\r\n        [timer release];\r\n        [indication release];\r\n\r\n    }\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withFillMode:(UIViewContentMode) fillMode {\r\n	self.fillMode = fillMode;\r\n	return self;\r\n}\r\n\r\n-(ImageContainer*) withWaitingIndicator:(id&lt;WaitingIndication&gt;) indication {\r\n	self.waitIndication = indication;\r\n	return self;\r\n}\r\n\r\n-(void) layoutMediaIn:(UIView*) view {\r\n	UIImageView* imgView = [UIImageView new];\r\n	self.imageView = imgView;\r\n	[imgView release];\r\n        [waitIndication wait:imageView];\r\n	imageView.layer.borderWidth = 1;\r\n	[view addSubview:imageView];\r\n	[mediaLoadRetryTimer go];\r\n}\r\n\r\n-(void) mediaLoaded:(UIImage *)img {\r\n		[mediaLoadRetryTimer cancel];\r\n		[waitIndication doneWaiting:imageView];\r\n		imageView.image = img;\r\n        imageView.contentMode = self.fillMode;\r\n		imageView.layer.borderWidth = 0;\r\n}\r\n\r\n- (void)dealloc {\r\n	self.imageView = nil;\r\n	self.imageURL = nil;\r\n	self.waitIndication = nil;\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nLet\'s talk about the workflow of the entire image loading process.\r\nThe <code>layoutInView:</code> method is responsible for setting up the view and asking the <code>WaitingIndication</code> object to display itself. It then fires the <code>MediaLoadRetryTimer</code> object, which handles firing off load requests at periodic intervals.\r\nWhen and if the <code>MediaLoadRetryTimer</code> is successful in retrieving the <code>UIImage</code> object, it notifies the <code>ImageContainer</code> by sending it the  <code>mediaLoaded:</code> message.\r\nUpon receiving it, the <code>ImageContainer</code> stops the timer (we don\'t want more load requests for this image), gets rid of the WaitingIndication, and finally, sets the image.\r\nWe shall look into the guts of <code>MediaLoadRetryTimer</code> now. Here\'s the code for it.\r\n\r\n<b>MediaLoadRetryTimer.h</b>\r\n\r\n[sourcecode language="objc"]\r\n@class TimerBatcher;\r\n\r\n@interface MediaLoadRetryTimer : NSObject {\r\n    NSTimeInterval timeInterval;\r\n	NSURL* mediaURL;\r\n	id&lt;MediaLoadListener&gt; listener;\r\n	\r\n	dispatch_source_t timer;\r\n	dispatch_block_t timerAction;\r\n	dispatch_queue_t queue;\r\n}\r\n\r\n@property (nonatomic, assign) NSTimeInterval timeInterval;\r\n@property (nonatomic, retain) NSURL* mediaURL;\r\n@property (nonatomic, assign) id&lt;MediaLoadListener&gt; listener;\r\n\r\n@property (nonatomic, assign) dispatch_source_t timer;\r\n@property (copy) dispatch_block_t timerAction;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener;\r\n-(void) cancel;\r\n-(void) go;\r\n-(void) safeCancelTimer;\r\n-(void) run;\r\n@end\r\n[/sourcecode]\r\n\r\n<b>MediaLoadRetryTimer.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@implementation MediaLoadRetryTimer\r\n@synthesize timer;\r\n@synthesize timerAction;\r\n@synthesize timeInterval;\r\n@synthesize mediaURL;\r\n@synthesize listener;\r\n\r\n-(MediaLoadRetryTimer*) initWithInterval:(NSTimeInterval) interval withMediaURL:(NSURL*) mediaURL withLoadListener:(id&lt;MediaLoadListener&gt;) listener {\r\n    self = [super init];\r\n    \r\n    if (self) {\r\n        self.timeInterval = interval;\r\n        self.mediaURL = mediaURL;\r\n        self.listener = listener;\r\n    }\r\n	\r\n	return self;\r\n}\r\n\r\n-(void) cancel {\r\n    [TimerBatcher complete:self];\r\n	self.listener = nil;\r\n	if (self.timerAction) {\r\n		[self safeCancelTimer];\r\n        dispatch_release(timer);\r\n        self.timerAction = nil;\r\n    }\r\n}\r\n\r\n-(void) safeCancelTimer {\r\n	if (!timer) return;\r\n	dispatch_source_cancel(timer);\r\n}\r\n\r\n-(void) go {\r\n	[TimerBatcher registerAs:self];\r\n	[TimerBatcher run:self];\r\n}\r\n\r\n-(void) run {\r\n	queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0);\r\n	self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);\r\n	if (!timer) return;\r\n	dispatch_source_set_timer(timer, dispatch_walltime(NULL, 0), timeInterval * NSEC_PER_SEC, 5 * NSEC_PER_SEC);\r\n	id&lt;MediaLoadListener&gt; loadListener = self.listener;\r\n	NSURL* mediaURL = self.mediaURL;\r\n	NSURL* u = [NSURL URLWithString:[NSString stringWithString:[mediaURL absoluteString]]];\r\n	dispatch_source_t timer = self.timer;\r\n	self.timerAction = ^{\r\n		@try {\r\n			if (loadListener == nil) return;\r\n			\r\n			NSData* data = [NSData dataWithContentsOfURL:u options:0 error:nil];\r\n			UIImage* img = [UIImage imageWithData:data];\r\n			if (img == nil) return;\r\n			dispatch_source_cancel(timer);\r\n			dispatch_async(dispatch_get_main_queue(), ^{[loadListener mediaLoaded:img]; });\r\n		}\r\n		@catch (NSException *exception) {\r\n		}\r\n	};\r\n	\r\n	dispatch_source_set_event_handler(timer, timerAction);\r\n	dispatch_resume(timer);\r\n}\r\n\r\n-(void) dealloc {\r\n	self.mediaURL = nil;\r\n	[self cancel];\r\n	[super dealloc];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe meat of this code is in the <code>run:</code> method. To perform concurrent operations, we create a timer source (<code>dispatch_source_t</code>) on a concurrent global queue with low priority. The interval at which the timer will tick is injected into the <code>MediaLoadRetryTimer</code> object.\r\nAt every tick, the action to be taken is defined in a block (<code>timerAction</code>). Inside this block, we attempt to retrieve the image. If we cannot (<code>img == nil</code>) we exit the block. Otherwise, we notify the listener that the image is available.\r\n\r\nAll of this is well and fine, but this does not prevent as many requests spawning as there are images. We need some way of throttling these requests. How you want to throttle it will depend upon your particular situation. If you look at the declaration of <code>MediaLoadRetryTimer</code>, you\'ll notice a second method called <code>go:</code>.\r\nThis is the method that <code>ImageContainer</code> calls, rather than <code>run:</code>; that internally calls <code>TimerBatcher</code>, which is how I throttle requests in this example. The source for <code>TimerBatcher</code> is below.\r\n\r\n<b>TimerBatcher.m</b>\r\n\r\n[sourcecode language="objc"]\r\n@interface TimerBatcher : NSObject {\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer;\r\n+(void) run:(MediaLoadRetryTimer*) timer;\r\n+(void) complete:(MediaLoadRetryTimer*) timer;\r\n\r\n@end\r\n\r\n&lt;b&gt;TimerBatcher.m&lt;/b&gt;\r\n\r\nstatic NSMutableArray* inactiveTimers;\r\nstatic NSMutableArray* activeTimers;\r\nstatic NSUInteger limit;\r\n\r\n@implementation TimerBatcher\r\n+(void) initialize {\r\n	inactiveTimers = [[NSMutableArray array] retain];\r\n	activeTimers = [[NSMutableArray array] retain];\r\n	limit = MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS;\r\n}\r\n\r\n+(void) registerAs:(MediaLoadRetryTimer*) timer {\r\n	[inactiveTimers addObject:timer];\r\n}\r\n\r\n+(void) run:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [inactiveTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	[activeTimers addObject:timer];\r\n	[inactiveTimers removeObjectAtIndex:index];\r\n	[timer run];\r\n}\r\n\r\n+(void) complete:(MediaLoadRetryTimer*) timer {\r\n	NSUInteger index = [activeTimers indexOfObject:timer];\r\n	if (index == NSNotFound) return;\r\n	[activeTimers removeObjectAtIndex:index];\r\n	if ([activeTimers count] &gt;= limit) return;\r\n	if ([inactiveTimers isEmpty]) return;\r\n	[TimerBatcher run:[inactiveTimers objectAtIndex:0]];\r\n}\r\n@end\r\n[/sourcecode]\r\n\r\nThe logic of TimerBatcher is pretty simple in this case. It has a limit defined by <code>MAXIMUM_CONCURRENT_MEDIA_LOAD_THREADS</code>. It allows timers to be activated as long as the number of active timers is below or equal to that limit. Beyond that, it refuses further activation requests, but permits activation requests to be queued. Whenever an active timer finishes, it picks up the next timer in the queue awaiting activation.\r\nYou might have more complex requirements to allow which timers get activated and which don\'t. The above should give you some ideas about how to go about building one.\r\n', 'iOS AppDev Patterns: Asynchronous Image Loader', 0, '', 'inherit', 'open', 'open', '', '39-revision-41', '', '', '2011-05-09 21:54:22', '2011-05-10 05:54:22', '', 39, 'http://www.avishek.net/blog/?p=80', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (81, 1, '2011-07-24 13:19:07', '0000-00-00 00:00:00', 'When developing for the iOS, one thing you\'ll need to think of is how to handle your views on orientation change. This might not be too big an issue if your application is static in terms of UI...you can easily make do with the correct UIViewAutoResizing settings, but for an application with content which requires orientation-specific layout, you\'ll need to worry about explicitly responding to orientation changes.\n\nLet\'s take a sample scenario.\n\n', 'iOS AppDev Patterns: Decorated Orientation', 0, '', 'draft', 'open', 'open', '', '', '', '', '2011-07-24 13:19:07', '2011-07-24 21:19:07', '', 0, 'http://www.avishek.net/blog/?p=81', 0, 'post', '', 0); 
INSERT INTO `wp_posts` VALUES (82, 1, '2011-05-09 22:08:15', '2011-05-10 06:08:15', 'When developing for the iOS, one thing you\'ll need to think of is how to handle your views on orientation change. This might not be too big an issue if your application is static in terms of UI...you can easily make do with the correct UIViewAutoResizing settings, but for an application with lots of dynamic content ', 'iOS AppDev Patterns: Decorated Orientation', 0, '', 'inherit', 'open', 'open', '', '81-revision', '', '', '2011-05-09 22:08:15', '2011-05-10 06:08:15', '', 81, 'http://www.avishek.net/blog/?p=82', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (83, 1, '2011-05-09 22:14:05', '2011-05-10 06:14:05', 'When developing for the iOS, one thing you\'ll need to think of is how to handle your views on orientation change. This might not be too big an issue if your application is static in terms of UI...you can easily make do with the correct UIViewAutoResizing settings, but for an application with lots of dynamic content...', 'iOS AppDev Patterns: Decorated Orientation', 0, '', 'inherit', 'open', 'open', '', '81-revision-2', '', '', '2011-05-09 22:14:05', '2011-05-10 06:14:05', '', 81, 'http://www.avishek.net/blog/?p=83', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (108, 1, '2011-05-18 22:49:04', '2011-05-19 06:49:04', 'I\'ve already talked about the <a href="http://www.avishek.net/blog/?p=87">Content Cursor pattern</a>. This post is an extension of that idea to increase the flexibility of layout <em>across sections</em>.\r\n\r\nTo understand the problem, let us revisit a page from our hypothetical iPad magazine.\r\nHere\'s the layout of the page in <em>portrait mode</em>.\r\n<img src="https://docs.google.com/drawings/pub?id=1QBpcHkOlohUwXVuhMoSOdWgQ8RZ1bOS63k5XnevrzjA&amp;w=346&amp;h=312"/>\r\n\r\n...and here is the same page in <em>landscape mode</em>.\r\n\r\n<img src="https://docs.google.com/drawings/pub?id=1rhH81WsVMNeWvs-xRYVPpI8hkyeTR3qfQIUhxIIC2cY&amp;w=405&amp;h=262"/>\r\n\r\nThe first important thing to notice here is that the two Politics sections have changed in position and/or size. More specifically, the upper Politics section has morphed into a tall rectangle, while the lower one has stretched horizontally.\r\n\r\nThe second important thing is that, because of the change in sizes, block 3, which was in the upper Politics section in portrait mode, has moved to the lower section in landscape mode, because it does not fit inside the upper one anymore.\r\n\r\nHow do we achieve this? How do we flow Content Blocks across multiple Content Sections in different configurations? A Content Cursor is good at laying out content but only within a <em>single Content Section</em>.\r\n\r\n<strong>Linked Content Cursor</strong> provides a solution.\r\n\r\nThe idea is pretty intuitive. We still maintain one <em>Content Cursor per Content Section</em>. However, we <em>link related Content Cursors such that each cursor points to its next logical cursor</em> (if one exists).\r\nTo use our example, that\'d mean linking the Content Cursor of the lower Politics section with the Content Cursor of the upper Politics section.\r\n\r\nHere is a diagram to illustrate.\r\n<img src="https://docs.google.com/drawings/pub?id=1xlb4tnmpHWrKvsBz2JJU-STXHevyfXOkrvgdv9Ho8i8&amp;w=346&amp;h=312"/>\r\n\r\n<strong>So what happens is when Content Cursor #1 runs out of space, it delegates placement of the Content Block to the next Content Cursor, i.e., Content Cursor #2.</strong>\r\n\r\nThe advantage of this is clear. If you have multiple <strong>Content Sections</strong> spread across the page, you never explicitly state which specific section you need to place any <strong>Content Block</strong> (of that type) in. The <strong>Linked Content Cursors</strong> take care of that decision for you.\r\n\r\nThis also implies that regardless of how the sections change in size and/or position, resetting your <strong>Content Cursors</strong> and placing your content from the beginning, causes them to naturally flow across the sections without any bookkeeping on your part.\r\n', 'iOS AppDev Patterns: Linked Content Cursors', 0, '', 'publish', 'open', 'open', '', 'ios-appdev-patterns-linked-content-cursors', '', '\nhttp://www.avishek.net/blog/?p=87', '2011-06-08 07:08:43', '2011-06-08 15:08:43', '', 0, 'http://www.avishek.net/blog/?p=108', 0, 'post', '', 0); 
INSERT INTO `wp_posts` VALUES (85, 1, '2011-05-11 00:40:30', '2011-05-11 08:40:30', 'When developing for the iOS, one thing you\'ll need to think of is how to handle your views on orientation change. This might not be too big an issue if your application is static in terms of UI...you can easily make do with the correct UIViewAutoResizing settings, but for an application with content which requires orientation-specific layout, you\'ll need to worry about explicitly responding to orientation changes.\n\n', 'iOS AppDev Patterns: Decorated Orientation', 0, '', 'inherit', 'open', 'open', '', '81-revision-3', '', '', '2011-05-11 00:40:30', '2011-05-11 08:40:30', '', 81, 'http://www.avishek.net/blog/?p=85', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (86, 1, '2011-05-11 00:41:11', '2011-05-11 08:41:11', 'When developing for the iOS, one thing you\'ll need to think of is how to handle your views on orientation change. This might not be too big an issue if your application is static in terms of UI...you can easily make do with the correct UIViewAutoResizing settings, but for an application with content which requires orientation-specific layout, you\'ll need to worry about explicitly responding to orientation changes.\r\n\r\nLet\'s take a sample scenario.', 'iOS AppDev Patterns: Decorated Orientation', 0, '', 'inherit', 'open', 'open', '', '81-revision-4', '', '', '2011-05-11 00:41:11', '2011-05-11 08:41:11', '', 81, 'http://www.avishek.net/blog/?p=86', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (87, 1, '2011-05-15 23:18:30', '2011-05-16 07:18:30', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\r\n\r\n<strong>Content Cursor</strong> solves this problem.\r\n\r\nA few definitions are in order.\r\n\r\n<strong>Content Block</strong>: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\r\n\r\n<strong>Content Section</strong>: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\r\n\r\n<strong>Content Source</strong>: The entity from which a Content Block derives its content (text/images) from.\r\n\r\nThe relation between the above three items is diagrammed below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=480&amp;h=360" alt="" />\r\n\r\nBack to the discussion at hand. We wish to be able to place <strong>Content Blocks</strong> inside a <strong>Content Section</strong>. Unfortunately, this requires us to specify the top left coordinate of each block in absolute coordinates, which is somewhat inconvenient in terms of maintainability.\r\nThe <strong>Content Cursor</strong> is an abstraction that lets us solve this problem in a simple, well-known fashion. I\'ve borrowed the term \'cursor\' from the humble cursor that indicates where the next character will be inserted while we are editing text. The Content Cursor functions in a similar fashion, except that instead of indicating the position of insertion of the next character, it indicates the position of insertion of the next Content Block, inside a Content Section.\r\n\r\nThe state machine of a basic Content Cursor is shown below.\r\n\r\n<img src="https://docs.google.com/drawings/pub?id=1y0G12OT-X9XiEn8KM1HCXttg0fbR0sKQPmEU5rKFmTs&amp;w=480&amp;h=360"/>\r\n\r\nThe easiest way to visualise this state machine is to think for a second about how a normal text-editing cursor behaves. If there\'s no more space for the next character on the current line, the character will be shown on the next line, effectively beginning a new line. If there\'s no more space in the entire document (word limit, for example), no character will be placed at all.\r\n\r\nThis same idea extended to Content Blocks provides an easy way to place them in a Content Section without having to worry about specifying the absolute coordinates; the Content Cursor keeps track of the position of the next block to be placed.\r\n\r\nThe flow of content might look like this.\r\n\r\n<img src="https://docs.google.com/drawings/pub?id=1XX5ZzIEDS-Mne_Tx6cPXlyhic1a5VO0fuRDx5fton6Q&amp;w=480&amp;h=360"/>\r\n\r\nIn an upcoming post, I shall extend this idea to talk about <strong>Linked Content Cursors</strong>.\r\n', 'iOS AppDev Patterns: Content Cursor', 0, '', 'publish', 'open', 'open', '', 'ios-appdev-patterns-content-cursor', '', '', '2011-07-13 06:15:09', '2011-07-13 14:15:09', '', 0, 'http://www.avishek.net/blog/?p=87', 0, 'post', '', 1); 
INSERT INTO `wp_posts` VALUES (88, 1, '2011-05-15 22:22:41', '2011-05-16 06:22:41', 'iOSoffer only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\n\nContent Cursor solves this problem.\n\nA few definitions are in order.\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\n\nContent Sec', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision', '', '', '2011-05-15 22:22:41', '2011-05-16 06:22:41', '', 87, 'http://www.avishek.net/blog/?p=88', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (89, 1, '2011-05-15 22:27:59', '2011-05-16 06:27:59', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\n\nContent Cursor solves this problem.\n\nA few definitions are in order.\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\n\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\n\nContent Source: The entity from which a Content Block derives its content (text\nThe relation between ', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-2', '', '', '2011-05-15 22:27:59', '2011-05-16 06:27:59', '', 87, 'http://www.avishek.net/blog/?p=89', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (90, 1, '2011-05-15 22:39:40', '2011-05-16 06:39:40', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\n\nContent Cursor solves this problem.\n\nA few definitions are in order.\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\n\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\n\nContent Source: The entity from which a Content Block derives its content (text/images) from.\n\nThe relation between the above three items is diagrammed below.\n<img class="alignnone" title="ContentBlock_ContentSection" src="http://avishek.net/plogger/plog-content/images/sketch-collection/faces-construction-and-shading/facesmall.jpg" alt="" width="1091" height="1500" />', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-3', '', '', '2011-05-15 22:39:40', '2011-05-16 06:39:40', '', 87, 'http://www.avishek.net/blog/?p=90', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (91, 1, '2011-05-15 22:45:24', '2011-05-16 06:45:24', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\n\nContent Cursor solves this problem.\n\nA few definitions are in order.\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\n\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\n\nContent Source: The entity from which a Content Block derives its content (text/images) from.\n\nThe relation between the above three items is diagrammed below.\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720" alt="" />\n\nBack to the discussion at hand. We wish to be able to place Content Blocks inside a Content Section. Unfortunately, this requires us to specify the top left coordinate of each block in absolute coordinates, which is somewhat inconvenient in terms of maintainability.\nThe Content Cursor is an abstraction that lets us solve this problem in a simple, well-known fashion. I\'ve borrowed the term \'cursor\' from the humble cursor that indicates where the next character will be inserted while we are editing text. The Content Cursor functions in a similar fashion, except that instead of indicating the position of insertion of the next character, it indicates the position of insertion of the next Content Block, inside a Content Section.\n', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-4', '', '', '2011-05-15 22:45:24', '2011-05-16 06:45:24', '', 87, 'http://www.avishek.net/blog/?p=91', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (92, 1, '2011-05-15 22:45:48', '2011-05-16 06:45:48', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\r\n\r\nContent Cursor solves this problem.\r\n\r\nA few definitions are in order.\r\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\r\n\r\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\r\n\r\nContent Source: The entity from which a Content Block derives its content (text/images) from.\r\n\r\nThe relation between the above three items is diagrammed below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720" alt="" />\r\n\r\nBack to the discussion at hand. We wish to be able to place Content Blocks inside a Content Section. Unfortunately, this requires us to specify the top left coordinate of each block in absolute coordinates, which is somewhat inconvenient in terms of maintainability.\r\nThe Content Cursor is an abstraction that lets us solve this problem in a simple, well-known fashion. I\'ve borrowed the term \'cursor\' from the humble cursor that indicates where the next character will be inserted while we are editing text. The Content Cursor functions in a similar fashion, except that instead of indicating the position of insertion of the next character, it indicates the position of insertion of the next Content Block, inside a Content Section.\r\n\r\nThe state machine of a basic Content Cursor is shown below.\r\n', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-5', '', '', '2011-05-15 22:45:48', '2011-05-16 06:45:48', '', 87, 'http://www.avishek.net/blog/?p=92', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (93, 1, '2011-05-15 22:53:31', '2011-05-16 06:53:31', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\r\n\r\nContent Cursor solves this problem.\r\n\r\nA few definitions are in order.\r\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\r\n\r\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\r\n\r\nContent Source: The entity from which a Content Block derives its content (text/images) from.\r\n\r\nThe relation between the above three items is diagrammed below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720" alt="" />\r\n\r\nBack to the discussion at hand. We wish to be able to place Content Blocks inside a Content Section. Unfortunately, this requires us to specify the top left coordinate of each block in absolute coordinates, which is somewhat inconvenient in terms of maintainability.\r\nThe Content Cursor is an abstraction that lets us solve this problem in a simple, well-known fashion. I\'ve borrowed the term \'cursor\' from the humble cursor that indicates where the next character will be inserted while we are editing text. The Content Cursor functions in a similar fashion, except that instead of indicating the position of insertion of the next character, it indicates the position of insertion of the next Content Block, inside a Content Section.\r\n\r\nThe state machine of a basic Content Cursor is shown below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720"/>\r\n', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-6', '', '', '2011-05-15 22:53:31', '2011-05-16 06:53:31', '', 87, 'http://www.avishek.net/blog/?p=93', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (94, 1, '2011-05-15 22:53:37', '2011-05-16 06:53:37', 'iOS offers only the most barebones approach to placing content in a view, namely by specifying absolute coordinates. Of course, one can use autoresizing to make sure the positions of these contents are modified proportionally, but the initial positioning of a content block needs specification of the exact x- and y-coordinate of the top left of this \'box\'. This can render the layout inflexible, tedious and brittle. Every small change in position of a block has ripple effects on the position of succeeding blocks.\r\n\r\nContent Cursor solves this problem.\r\n\r\nA few definitions are in order.\r\nContent Block: A rectangular area representing an atomic unit of information, for example, an article or an advertisement. It may contain a mix of text, images, video, etc.\r\n\r\nContent Section: A rectangular region containing multiple Content Blocks. These Content Blocks may be related to each other, for example, an Entertainment section, a Sports section.\r\n\r\nContent Source: The entity from which a Content Block derives its content (text/images) from.\r\n\r\nThe relation between the above three items is diagrammed below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720" alt="" />\r\n\r\nBack to the discussion at hand. We wish to be able to place Content Blocks inside a Content Section. Unfortunately, this requires us to specify the top left coordinate of each block in absolute coordinates, which is somewhat inconvenient in terms of maintainability.\r\nThe Content Cursor is an abstraction that lets us solve this problem in a simple, well-known fashion. I\'ve borrowed the term \'cursor\' from the humble cursor that indicates where the next character will be inserted while we are editing text. The Content Cursor functions in a similar fashion, except that instead of indicating the position of insertion of the next character, it indicates the position of insertion of the next Content Block, inside a Content Section.\r\n\r\nThe state machine of a basic Content Cursor is shown below.\r\n<img src="https://docs.google.com/drawings/pub?id=1G_is1L5uwVOFBJ4zu4tL9qnhREVMqWQS_IwAZTzi2Ks&amp;w=960&amp;h=720"/>\r\n', 'iOS AppDev Patterns: Content Cursor', 0, '', 'inherit', 'open', 'open', '', '87-revision-7', '', '', '2011-05-15 22:53:37', '2011-05-16 06:53:37', '', 87, 'http://www.avishek.net/blog/?p=94', 0, 'revision', '', 0); 
