ft( \\begin{array}{cccc}\r\na & b & c & d \\\\\r\ne & f & g & h \\\\\r\ni & j & k & l \\\\\r\nm & n & o & p \\end{array} \\right)\\)\\transpose\r\n=\r\n\\left( \\begin{array}{cccc}\r\na & e & i & m \\\\\r\nb & f & j & n \\\\\r\nc & g & k & o \\\\\r\nd & h & l & p \\end{array} \\right)\\\r\n[/latex]\r\n', 'Eigenvector algorithms for symmetric matrices: Jacobi rotations', 0, '', 'inherit', 'open', 'open', '', '331-revision-25', '', '', '2011-07-21 03:24:04', '2011-07-21 11:24:04', '', 331, 'http://avishek.net/blog/?p=358', 0, 'revision', '', 0); 
