INSERT INTO `wp_posts` VALUES (480, 1, '2011-07-25 08:25:54', '2011-07-25 16:25:54', '', 'Matrix Theory: ', 0, '', 'inherit', 'open', 'open', '', '479-revision', '', '', '2011-07-25 08:25:54', '2011-07-25 16:25:54', '', 479, 'http://avishek.net/blog/?p=480', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (481, 1, '2011-07-25 11:27:09', '2011-07-25 19:27:09', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\n\n[latex]\nA=\n\\left( \\begin{array}{cc}\n2 & 0 \\\\\n0 & 5 \\end{array} \\right)\\\n[/latex]\n\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\n\n[latex]A.x = \\lambda x[/latex]\n\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\n[latex]\n{\\left( \\begin{array}\n1 & 0 & 0 \\ldots & 0\\end{array} \\right)\\}^T\n{\\left( \\begin{array}\n0 & 1 & 0 \\ldots & 0\\end{array} \\right)\\}^T\n{\\left( \\begin{array}\n0 & 0 & 1 \\ldots & 0\\end{array} \\right)\\}^T\n\\vdots\n{\\left( \\begin{array}\n0 & 0 & 0 \\ldots & 0\\end{array} \\right)\\}^T\n\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-2', '', '', '2011-07-25 11:27:09', '2011-07-25 19:27:09', '', 479, 'http://avishek.net/blog/?p=481', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (484, 1, '2011-07-25 11:28:12', '2011-07-25 19:28:12', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}\r\n1 & 0 & 0 \\ldots & 0\\end{array} \\right)\\}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-5', '', '', '2011-07-25 11:28:12', '2011-07-25 19:28:12', '', 479, 'http://avishek.net/blog/?p=484', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (482, 1, '2011-07-25 11:27:16', '2011-07-25 19:27:16', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}\r\n1 & 0 & 0 \\ldots & 0\\end{array} \\right)\\}^T\r\n{\\left( \\begin{array}\r\n0 & 1 & 0 \\ldots & 0\\end{array} \\right)\\}^T\r\n{\\left( \\begin{array}\r\n0 & 0 & 1 \\ldots & 0\\end{array} \\right)\\}^T\r\n\\vdots\r\n{\\left( \\begin{array}\r\n0 & 0 & 0 \\ldots & 1\\end{array} \\right)\\}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-3', '', '', '2011-07-25 11:27:16', '2011-07-25 19:27:16', '', 479, 'http://avishek.net/blog/?p=482', 0, 'revision', '', 0); 
