INSERT INTO `wp_posts` VALUES (496, 1, '2011-07-25 11:31:27', '2011-07-25 19:31:27', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots \\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots & 0\\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots & 0\\end{array} \\right)}^T\r\n\\vdots\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots & 1\\end{array} \\right)}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-17', '', '', '2011-07-25 11:31:27', '2011-07-25 19:31:27', '', 479, 'http://avishek.net/blog/?p=496', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (497, 1, '2011-07-25 11:31:54', '2011-07-25 19:31:54', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T\r\n\\vdots\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-18', '', '', '2011-07-25 11:31:54', '2011-07-25 19:31:54', '', 479, 'http://avishek.net/blog/?p=497', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (498, 1, '2011-07-25 11:32:02', '2011-07-25 19:32:02', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T\r\n\\vdots\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-19', '', '', '2011-07-25 11:32:02', '2011-07-25 19:32:02', '', 479, 'http://avishek.net/blog/?p=498', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (499, 1, '2011-07-25 11:32:34', '2011-07-25 19:32:34', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T \\\\\r\n\\vdots\\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-20', '', '', '2011-07-25 11:32:34', '2011-07-25 19:32:34', '', 479, 'http://avishek.net/blog/?p=499', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (500, 1, '2011-07-25 11:32:38', '2011-07-25 19:32:38', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T \\\\\r\n\\vdots\\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\r\n[/latex]', 'Matrix Theory: Diagonalisation and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '479-revision-21', '', '', '2011-07-25 11:32:38', '2011-07-25 19:32:38', '', 479, 'http://avishek.net/blog/?p=500', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (501, 1, '2011-07-25 12:20:01', '2011-07-25 20:20:01', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\n\n[latex]\nA=\n\\left( \\begin{array}{cc}\n2 & 0 \\\\\n0 & 5 \\end{array} \\right)\\\n[/latex]\n\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\n\n[latex]A.x = \\lambda x[/latex]\n\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\n[latex]\n{\\left( \\begin{array}{ccc}\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\n{\\left( \\begin{array}{ccc}\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\n{\\left( \\begin{array}{ccc}\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T \\\\\n\\vdots\\\\\n{\\left( \\begin{array}{ccc}\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\n[/latex]\n\nIt\'s now easy to see how our previous statement is true, because any of the above vectors when multipled by a diagonal vector gives the same vector, only scaled by a certain scalar.\n\nLife would be great if we always got to work with diagonal matrices. Unfortunately, that is not the case. Though small-dimensional matrices (2,3,4) yield themselves to algebraic solutions for their eigenvectors/eigenvalues, much of the data we will work are easily higher-dimensional than that.\nSo, what can we do? Examine the diagram below:\n\n<img src="https://docs.google.com/drawings/pub?id=1iMmaI0s7lU98ilHaI-Pp9n92ydrRqtfR5ZeXl4TXefw&amp;w=665&amp;h=522"/>\n\nThe situation is this, we have a matrix A<sub>S</sub> in standard basis. We wish to find the eigenvectors and eigenvalues of this matrix. Now here comes the trick: <strong>A<sub>S</sub> is not diagonal in basis, but there is probably another basis out there somewhere in which it *is* diagonal</strong>. Let\'s assume that this hypothetical basis is B. Now, it follows from our previous discussion that if a matrix is diagonal in a basis, the basis vectors (as expressed in that basis) are the eigenvectors of that matrix.\nThus, the basis vectors of B are the eigenvectors of our matrix A<sub>B</sub> (which is our original A<sub>S</sub> expressed in basis B).\n\nNow all we have done is change the basis, which means that the basis vectors of B that we found are going to be eigenvectors of A no matter what the basis, as long as both the vectors and the transformation matrix A are expressed in the same basis.\n<strong>Thus, the basis matrix of B (in standard basis) is the eigenvector matrix of A<sub>S</sub>.</strong>\n\nThe basic idea underlying all eigenvector computation methods is then, this:<strong> find a set of bases in which the matrix A is diagonal, this set of bases, expressed in the standard basis, is the set of eigenvectors of A. Thus our objective will be to find a similarity transformation on A which will make A diagonal.</strong>\n\nThis concludes the basic matrix theory you\'ll need to understand the eigenvector algorithms for symmetric matrices. From here on, I\'ll dive into the specific eigen', 'Matrix Theory: Diagonalisation and Eigenvector Computation', 0, '', 'inherit', 'open', 'open', '', '479-revision-22', '', '', '2011-07-25 12:20:01', '2011-07-25 20:20:01', '', 479, 'http://avishek.net/blog/?p=501', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (502, 1, '2011-07-25 12:20:46', '2011-07-25 20:20:46', 'I return to the first example about basis vectors, when I spoke of linear transformations. The linear transformation we had was this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe operation it performed on basis vectors of the standard basis S was one of scaling, and scaling only. When operated on by a linear transformation matrix, if a vector is only scaled as a consequence, that vector is an eigenvector of the matrix, and the scalar is the corresponding eigenvalue. This is just the definition of an eigenvector, which I rewrite below:\r\n\r\n[latex]A.x = \\lambda x[/latex]\r\n\r\nYou will have also noticed that the matrix A is a diagonal matrix. It is particularly easy to find the eigenvectors of a matrix if it is diagonal in a basis, because the eigenvectors are always the basis vectors themselves, as expressed in that basis. That last phrase is particularly important. Basis vectors as expressed in that basis always look like this:\r\n[latex]\r\n{\\left( \\begin{array}{ccc}\r\n1 & 0 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 1 & 0 \\ldots 0\\end{array} \\right)}^T \\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 1 \\ldots 0\\end{array} \\right)}^T \\\\\r\n\\vdots\\\\\r\n{\\left( \\begin{array}{ccc}\r\n0 & 0 & 0 \\ldots 1\\end{array} \\right)}^T\r\n[/latex]\r\n\r\nIt\'s now easy to see how our previous statement is true, because any of the above vectors when multipled by a diagonal vector gives the same vector, only scaled by a certain scalar.\r\n\r\nLife would be great if we always got to work with diagonal matrices. Unfortunately, that is not the case. Though small-dimensional matrices (2,3,4) yield themselves to algebraic solutions for their eigenvectors/eigenvalues, much of the data we will work are easily higher-dimensional than that.\r\nSo, what can we do? Examine the diagram below:\r\n\r\n<img src="https://docs.google.com/drawings/pub?id=1iMmaI0s7lU98ilHaI-Pp9n92ydrRqtfR5ZeXl4TXefw&amp;w=665&amp;h=522"/>\r\n\r\nThe situation is this, we have a matrix A<sub>S</sub> in standard basis. We wish to find the eigenvectors and eigenvalues of this matrix. Now here comes the trick: <strong>A<sub>S</sub> is not diagonal in basis, but there is probably another basis out there somewhere in which it *is* diagonal</strong>. Let\'s assume that this hypothetical basis is B. Now, it follows from our previous discussion that if a matrix is diagonal in a basis, the basis vectors (as expressed in that basis) are the eigenvectors of that matrix.\r\nThus, the basis vectors of B are the eigenvectors of our matrix A<sub>B</sub> (which is our original A<sub>S</sub> expressed in basis B).\r\n\r\nNow all we have done is change the basis, which means that the basis vectors of B that we found are going to be eigenvectors of A no matter what the basis, as long as both the vectors and the transformation matrix A are expressed in the same basis.\r\n<strong>Thus, the basis matrix of B (in standard basis) is the eigenvector matrix of A<sub>S</sub>.</strong>\r\n\r\nThe basic idea underlying all eigenvector computation methods is then, this:<strong> find a set of bases in which the matrix A is diagonal, this set of bases, expressed in the standard basis, is the set of eigenvectors of A. Thus our objective will be to find a similarity transformation on A which will make A diagonal.</strong>\r\n\r\nThis concludes the basic matrix theory you\'ll need to understand the eigenvector algorithms for symmetric matrices. From here on, I\'ll dive into the specific eigenvector/eigenvalue numerical methods.', 'Matrix Theory: Diagonalisation and Eigenvector Computation', 0, '', 'inherit', 'open', 'open', '', '479-revision-23', '', '', '2011-07-25 12:20:46', '2011-07-25 20:20:46', '', 479, 'http://avishek.net/blog/?p=502', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (504, 1, '2011-07-26 14:49:23', '2011-07-26 22:49:23', 'I\'ve avoided proofs unless absolutely necessary, but the relation between the same eigenvectors expressed in two different bases, is important.\nGiven that A<sub>S</sub> us the linear transformation matrix in standard basis S, and A<sub>B</sub> is its counterpart in basis B, we can write the relation between them as:\n\n[latex]\nA_B = C^{-1}A_SC\nA_S = CA_BC^{-1}\n[/latex]\n\nwhere C is the similarity transformation. We\'ve seen this relation already; check <a href="http://avishek.net/blog/?p=448">here</a> if you\'ve forgotten about it.\nNow, the definition of an eigenvector gives us:\n\n[latex]\nA_Sx_S=\\lambda x_S\n[/latex]\n\nx is the eigenvector in standard basis S. Now substituting A<sub>S</sub> with the identity we obtained previously into the eigenvector identity, we get:\n\n[latex]\nCA_BC^{-1}x_S= \\lambda x_S\nA_B\\left(C^{-1}x\\right) = \\lambda\\left(C^{-1}x_S\\right)\n[/latex]\n\nIf we take x<sub>B</sub> = C<sup>-1</sup>.x<sub>S</sub>, we get:\n\n[latex]\nA_Bx_B = \\lambda x_B\n[/latex]\n\nThis tells us two important things. One, that the eigenvalue is still [latex]\\lambda[/latex]. Second, the eigenvector expressions in the two bases are related as:\n\n[latex]\nx_B = C^{-1}.x_S\n[/latex]', 'Matrix Theory: Essential Proofs for eigenvector computations', 0, '', 'inherit', 'open', 'open', '', '503-revision', '', '', '2011-07-26 14:49:23', '2011-07-26 22:49:23', '', 503, 'http://avishek.net/blog/?p=504', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (505, 1, '2011-07-26 14:50:19', '2011-07-26 22:50:19', 'I\'ve avoided proofs unless absolutely necessary, but the relation between the same eigenvectors expressed in two different bases, is important.\r\nGiven that A<sub>S</sub> us the linear transformation matrix in standard basis S, and A<sub>B</sub> is its counterpart in basis B, we can write the relation between them as:\r\n\r\n[latex]\r\nA_B = C^{-1}A_SC\r\nA_S = CA_BC^{-1}\r\n[/latex]\r\n\r\nwhere C is the similarity transformation. We\'ve seen this relation already; check <a href="http://avishek.net/blog/?p=448">here</a> if you\'ve forgotten about it.\r\nNow, the definition of an eigenvector gives us:\r\n\r\n[latex]\r\nA_Sx_S=\\lambda x_S\r\n[/latex]\r\n\r\nx is the eigenvector in standard basis S. Now substituting A<sub>S</sub> with the identity we obtained previously into the eigenvector identity, we get:\r\n\r\n[latex]\r\nCA_BC^{-1}x_S= \\lambda x_S\r\nA_B\\left(C^{-1}x\\right) = \\lambda\\left(C^{-1}x_S\\right)\r\n[/latex]\r\n\r\nIf we take x<sub>B</sub> = C<sup>-1</sup>.x<sub>S</sub>, we get:\r\n\r\n[latex]\r\nA_Bx_B = \\lambda x_B\r\n[/latex]\r\n\r\nThis tells us two important things. One, that the eigenvalue is still [latex]\\lambda[/latex]. Second, the eigenvector expressions in the two bases are related as:\r\n\r\n[latex]\r\nx_B = C^{-1}.x_S\r\n[/latex]\r\n\r\nThis gives us the relation we need, and justifies the logic in <a href="http://avishek.net/blog/?p=479">this post</a>.', 'Matrix Theory: An essential Proof for eigenvector computations', 0, '', 'inherit', 'open', 'open', '', '503-revision-2', '', '', '2011-07-26 14:50:19', '2011-07-26 22:50:19', '', 503, 'http://avishek.net/blog/?p=505', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (506, 1, '2011-07-24 13:12:18', '2011-07-24 21:12:18', '<h3>Symmetric Matrices</h3>\r\nA symmetric matrix looks like this:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cccc}\r\na & d & n & w \\\\\r\nd & b & h & e \\\\\r\nn & h & c & i \\\\\r\nw & e & i & d \\end{array} \\right)\\\r\n[/latex]\r\n\r\nNotice how the values are reflected across the diagonal a-b-c-d; this holds true for any symmetric matrix.\r\n\r\n<h3>Diagonal Matrices</h3>\r\nThe following is a diagonal matrix.\r\n\r\n[latex]\r\nD=\r\n\\left( \\begin{array}{cccc}\r\na & 0 & 0 & 0 \\\\\r\n0 & b & 0 & 0 \\\\\r\n0 & 0 & c & 0 \\\\\r\n0 & 0 & 0 & d \\end{array} \\right)\\\r\n[/latex]\r\n\r\nNotice how all the off-diagonal elements (elements not part of the diagonal) are zero; this holds true for any diagonal matrix.\r\nLet\'s take a (short) digression and look at a widely-used way of viewing matrices - as linear transformations.\r\n\r\n<h3>Linear Transformations</h3>\r\n\r\n<img src="https://docs.google.com/drawings/pub?id=1UjD6Vj8mBPfUzNQ42og7Z8I_133IafcCblkmEKSyLLM&amp;w=510&amp;h=476"/>\r\nHere is a simple question: find me the matrix P which when multiplied with the vector [latex]\\overrightarrow{r, \\theta}[/latex] gives me the rotated vector [latex]\\overrightarrow{r,\\left(\\theta + \\alpha\\right)}[/latex].\r\n\r\n[latex]\r\nP.\\left( \\begin{array}{c}\r\nr cos \\theta \\\\\r\nr sin \\theta \\end{array} \\right).P\r\n=\r\n\\left( \\begin{array}{c}\r\nr cos \\left(\\theta+\\alpha\\right) \\\\\r\nr sin \\left(\\theta+\\alpha\\right) \\end{array} \\right)\r\n[/latex]\r\n\r\nThis is how I do it. Expand the trigonometric expressions for [latex]cos \\left(\\theta+\\alpha\\right)[/latex] and [latex]sin \\left(\\theta+\\alpha\\right)[/latex], so that you get:\r\n\r\n[latex]\r\nP.\\left( \\begin{array}{c}\r\nr cos \\theta \\\\\r\nr sin \\theta \\end{array} \\right)\r\n=\r\n\\left( \\begin{array}{c}\r\nr cos \\theta.cos \\alpha - r sin \\theta.sin \\alpha \\\\\r\nr sin \\theta.cos \\alpha + r cos \\alpha.sin \\theta \\end{array} \\right)\r\n[/latex]\r\n\r\nA little inspection gives the answer:\r\n\r\n[latex]\r\nP =\r\n\\left( \\begin{array}{cccc}\r\ncos \\alpha & -sin \\alpha \\\\\r\nsin \\alpha & cos \\alpha \\end{array} \\right)\\\r\n[/latex]\r\n\r\nThe matrix P is a linear transformation; why it is linear and what its properties are I\'ll leave to the formal definitions in books. It suffices to say that you can look at a matrix as if it were a map or a function to which you could pass in a vector and get a new vector out of it.\r\nAs in the above example, all matrices have geometrical descriptions: the above one is a rotation vector, for instance. For the purposes of this series, I shall concentrate for the moment on the type of transformation given by a diagonal matrix.\r\n\r\n<h3>Basis Vectors</h3>\r\nAgain, let\'s look at an example in 2 dimensions.\r\nHere\'s an arbitrary diagonal matrix:\r\n\r\n[latex]\r\nA=\r\n\\left( \\begin{array}{cc}\r\n2 & 0 \\\\\r\n0 & 5 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nI choose two very special vectors, the normalised x- and y-vectors:\r\n\r\n[latex]\r\nx_1 = \\left( \\begin{array}{cc}\r\n1 \\\\\r\n0 \\end{array} \\right)\\\r\nx_2 = \\left( \\begin{array}{cc}\r\n0 \\\\\r\n1 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nIf we multiply D with x1 and x2 separately, we get:\r\n\r\n[latex]\r\nA.x_1 = \\left( \\begin{array}{cc}\r\n2 \\\\\r\n0 \\end{array} \\right)\\\r\n= 2.\r\n\\left( \\begin{array}{cc}\r\n1 \\\\\r\n0 \\end{array} \\right)\\\r\n\\\\\r\nA.x_2 = \\left( \\begin{array}{cc}\r\n5 \\\\\r\n0 \\end{array} \\right)\\\r\n= 5.\r\n\\left( \\begin{array}{cc}\r\n0 \\\\\r\n1 \\end{array} \\right)\\\r\n[/latex]\r\n\r\nWell, nothing earth-shattering, but this gives me an opportunity to introduce the idea of basis vectors. Basis vectors are essentially vectors which are used to define a coordinate space. In 2D space, for example, we normally use the two basis vectors [1,0] as the x-axis and [0,1] as the y-axis, but there is nothing stopping us from choosing any two arbitrary vectors to be able to specify vectors in 2D space. Well, not entirely arbitrary, they cannot be linearly dependent, for example; you can find out more about the precise requirements for defining well-formed basis vectors in books, but for now it suffices to note that most arbitrary sets of vectors can be chosen to be basis vectors.\r\n\r\nThe other idea I want you to take away from the above example is that the diagonal matrix merely stretched (or squashed, depending upon the contents of the diagonal) the basis vectors by a factor. The basis vectors still point in their original directions: only their magnitudes has changed. If I were to denote any basis vector as x, and [latex]\\lambda[/latex] as the factor, then I could have written:\r\n\r\n[latex]\r\nA.x = \\lambda .x\r\n[/latex]\r\n\r\nThis is the definition of an eigenvector x for a matrix A. An eigenvector, when multiplied by a matrix, is only scaled by a number. It does not undergo rotation, projection or any other transformation. The scaling number itself is termed the eigenvalue.\r\nThus, in the example above, the basis vectors [1,0]<sup>T</sup> and [0,1]<sup>T</sup> are the eigenvectors of the matrix A.\r\n\r\nIn the next installment, I shall introduce similarity transformations and how it is a standard way of solving the eigenvector problems in many numerical computing packages.', 'Matrix Theory: Linear transformations, Basis vectors and Eigenvectors', 0, '', 'inherit', 'open', 'open', '', '331-revision-112', '', '', '2011-07-24 13:12:18', '2011-07-24 21:12:18', '', 331, 'http://avishek.net/blog/?p=506', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (507, 1, '2011-07-26 14:50:26', '2011-07-26 22:50:26', 'I\'ve avoided proofs unless absolutely necessary, but the relation between the same eigenvectors expressed in two different bases, is important.\r\nGiven that A<sub>S</sub> us the linear transformation matrix in standard basis S, and A<sub>B</sub> is its counterpart in basis B, we can write the relation between them as:\r\n\r\n[latex]\r\nA_B = C^{-1}A_SC\r\nA_S = CA_BC^{-1}\r\n[/latex]\r\n\r\nwhere C is the similarity transformation. We\'ve seen this relation already; check <a href="http://avishek.net/blog/?p=448">here</a> if you\'ve forgotten about it.\r\nNow, the definition of an eigenvector gives us:\r\n\r\n[latex]\r\nA_Sx_S=\\lambda x_S\r\n[/latex]\r\n\r\nx is the eigenvector in standard basis S. Now substituting A<sub>S</sub> with the identity we obtained previously into the eigenvector identity, we get:\r\n\r\n[latex]\r\nCA_BC^{-1}x_S= \\lambda x_S\r\nA_B\\left(C^{-1}x\\right) = \\lambda\\left(C^{-1}x_S\\right)\r\n[/latex]\r\n\r\nIf we take x<sub>B</sub> = C<sup>-1</sup>.x<sub>S</sub>, we get:\r\n\r\n[latex]\r\nA_Bx_B = \\lambda x_B\r\n[/latex]\r\n\r\nThis tells us two important things. One, that the eigenvalue is still [latex]\\lambda[/latex]. Second, the eigenvector expressions in the two bases are related as:\r\n\r\n[latex]\r\nx_B = C^{-1}.x_S\r\n[/latex]\r\n\r\nThis gives us the relation we need, and justifies the logic in <a href="http://avishek.net/blog/?p=479">this post</a>.', 'Matrix Theory: An essential proof for eigenvector computations', 0, '', 'inherit', 'open', 'open', '', '503-revision-3', '', '', '2011-07-26 14:50:26', '2011-07-26 22:50:26', '', 503, 'http://avishek.net/blog/?p=507', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (508, 1, '2011-07-26 14:53:57', '2011-07-26 22:53:57', 'I\'ve avoided proofs unless absolutely necessary, but the relation between the same eigenvectors expressed in two different bases, is important.\r\nGiven that A<sub>S</sub> us the linear transformation matrix in standard basis S, and A<sub>B</sub> is its counterpart in basis B, we can write the relation between them as:\r\n\r\n[latex]\r\nA_B = C^{-1}A_SC\r\nA_S = CA_BC^{-1}\r\n[/latex]\r\n\r\nwhere C is the similarity transformation. We\'ve seen this relation already; check <a href="http://avishek.net/blog/?p=448">here</a> if you\'ve forgotten about it.\r\nNow, the definition of an eigenvector gives us:\r\n\r\n[latex]\r\nA_Sx_S=\\lambda x_S\r\n[/latex]\r\n\r\nx is the eigenvector in standard basis S. Now substituting A<sub>S</sub> with the identity we obtained previously into the eigenvector identity, we get:\r\n\r\n[latex]\r\nCA_BC^{-1}x_S= \\lambda x_S\r\nA_B\\left(C^{-1}x\\right) = \\lambda\\left(C^{-1}x_S\\right)\r\n[/latex]\r\n\r\nIf we take x<sub>B</sub> = C<sup>-1</sup>.x<sub>S</sub>, we get:\r\n\r\n[latex]\r\nA_Bx_B = \\lambda x_B\r\n[/latex]\r\n\r\nThis tells us two important things. One, that the eigenvalue is still [latex]\\lambda[/latex]. Second, the eigenvector expressions in the two bases are related as:\r\n\r\n[latex]\r\nx_B = C^{-1}.x_S\r\n[/latex]\r\n\r\nThis gives us the relation we need, and justifies the logic in <a href="http://avishek.net/blog/?p=479">this post</a>.', 'Matrix Theory: An essential proof for eigenvector computations', 0, '', 'inherit', 'open', 'open', '', '503-revision-4', '', '', '2011-07-26 14:53:57', '2011-07-26 22:53:57', '', 503, 'http://avishek.net/blog/?p=508', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (509, 1, '2011-07-27 12:59:10', '2011-07-27 20:59:10', 'Continuing on with my exploration of the data mining landscape, I extracted out a decision tree out of the data under scrutiny. It is the same data (20,000 samples, 56 samples), but the dimensions I\'ve chosen for partitioning are a bit different from the raw attributes. I\'ve conflated the 56 dimensions into a single number, since this is a test score we\'re talking about, and I\'m not sure modelling the indivdual responses for constructing the tree would be the best idea. I\'m not really looking for close fits, buckets or bins should be adequate for discretising the response space.\r\nAccordingly, I\'ve partitioned the pre-scores as EXCELLENT, GOOD, AVERAGE, etc. The attribute that I\'m attempting to predict is also a score, but this is the post-score. Well, not really the score itself, the improvement in score is a more sensible metric to attempt to guess.\r\n\r\nI had a problem with trying to visualise the data, but I\'ve been able to make do with indenting the different levels of decision nodes; this should be fine till I really need to use a visualisation library. I think the code could use a bit of work - probability notation does not lend itself easy to elegant variable naming. I\'ll probably write a lot more on this topic once I\'m into Bayesian Nets.', 'Decision Trees', 0, '', 'publish', 'open', 'open', '', 'decision-trees', '', '', '2011-07-27 12:59:10', '2011-07-27 20:59:10', '', 0, 'http://avishek.net/blog/?p=509', 0, 'post', '', 0); 
INSERT INTO `wp_posts` VALUES (510, 1, '2011-07-27 12:58:17', '2011-07-27 20:58:17', 'Continuing on with my exploration of the data mining landscape, I extracted out a decision tree out of the data under scrutiny. It is the same data (20,000 samples, 56 samples), but the dimensions I\'ve chosen for partitioning are a bit different from the raw attributes. I\'ve conflated the 56 dimensions into a single number, since this is a test score we\'re talking about, and I\'m not sure modelling the indivdual responses for constructing the tree would be the best idea. I\'m not really looking for close fits, buckets or bins should be adequate for discretising the response space.\nAccordingly, I\'ve partitioned the pre-scores as EXCELLENT, GOOD, AVERAGE, etc. The attribute that I\'m attempting to predict is also a score, but this is the post-score. Well, not really the score itself, the improvement in score is a more sensible metric to attempt to guess.\n\nI had a problem with trying to visualise the data, but I\'ve been able to make do with indenting the different levels of decision nodes; this should be fine till I really need to use a visualisation library. I think the code could use a bit of work - probability notation does not lend itself easy to elegant variable naming. I\'ll probably write a lot more on this topic once I\'m into Bayesian Nets', 'Decision Trees', 0, '', 'inherit', 'open', 'open', '', '509-revision', '', '', '2011-07-27 12:58:17', '2011-07-27 20:58:17', '', 509, 'http://avishek.net/blog/?p=510', 0, 'revision', '', 0); 
