INSERT INTO `wp_posts` VALUES (531, 1, '2011-08-03 11:29:07', '2011-08-03 19:29:07', 'Really, all I wanted to do was use Processing from Ruby. <a href="https://github.com/jashkenas">jashkenas</a> has kindly written a <a href="https://github.com/jashkenas/ruby-processing">gem</a> which does just that. There was only a slight wrinkle: I wanted to pull my data from MySQL through ActiveRecord. Well, JRuby makes this process slightly more interesting than usual, so I document the process here. To start off with, install the gem with:\r\n[code]sudo gem install ruby-processing[/code]\r\n\r\nGo into the directory where the ruby-processing gem is installed, and from there into {ruby-processing.gem.dir}/lib/core. In my case, this was <strong>/usr/lib/ruby/gems/1.8/gems/ruby-processing-1.0.9/lib/core</strong>.\r\nOnce inside there, you\'ll find a file named <strong>jruby-complete.jar</strong>. Get rid of it, because we\'ll be replacing it with a fresh (and different) version of jruby-complete.jar. Download the <a href="http://jruby.org.s3.amazonaws.com/downloads/1.6.3/jruby-complete-1.6.3.jar">1.6.3 version of JRuby-complete jar file</a>. Rename it to jruby-complete.jar and put it in place of the jarfile we just deleted.\r\n\r\nOne step remains: this jarfile does not contain the activerecord-jdbcmysql-adapter gem. Install that with:\r\n\r\n[code]java -jar jruby-complete.jar -S gem install  activerecord-jdbcmysql-adapter --user-install[/code]\r\n\r\nYou\'re good to go now. One more thing, just remember to replace the ActiveRecord adapter string with <strong>"jdbcmysql"</strong> and allow usage of that gem in your code with:\r\n\r\n[code]require \'arjdbc\'[/code].', 'Getting ActiveRecord to behave nicely with Ruby-Processing in JRuby', 0, '', 'inherit', 'open', 'open', '', '526-revision-5', '', '', '2011-08-03 11:29:07', '2011-08-03 19:29:07', '', 526, 'http://avishek.net/blog/?p=531', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (532, 1, '2011-08-04 13:04:36', '2011-08-04 21:04:36', '', 'parallel_coordinates_hover', 0, '', 'inherit', 'open', 'open', '', 'parallel_coordinates_hover', '', '', '2011-08-04 13:04:36', '2011-08-04 21:04:36', '', 533, 'http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_hover.flv', 0, 'attachment', 'video/x-flv', 0); 
INSERT INTO `wp_posts` VALUES (533, 1, '2011-08-04 13:18:27', '2011-08-04 21:18:27', '<a href="http://processing.org/">Processing</a> is growing on me. Inspired by the different and (very) interesting data visualisation examples I\'ve seen, I decided to take a shot at interacting with the parallel coordinates that I generated <a href="http://avishek.net/blog/?p=518">here</a>. Of course, I had to reduce the number of samples for this demonstration; it\'d slow to a unholy crawl otherwise. For this video, I\'ve taken 300 samples. The interaction is essentially a mouse-hover highlighting of any sample(s) under it. I fiddled with the colors a bit, but decided that a white-on-greyscale scheme would show up better.\r\nOf course, I still haven\'t gotten around to labeling the axes. This I\'ll probably pick up next. But as the video demonstrates, there\'s a lot to Processing than meets the eye.\r\n\r\nPS: By the way, the actual demonstration ends around the halfway mark; I was trying to figure out how to stop the bloody recorder.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_hover.flv 400 300]\r\n', 'Data interactions in parallel coordinates', 0, '', 'publish', 'open', 'open', '', 'data-interactions-in-parallel-coordinates', '', '\nhttp://avishek.net/blog/?p=518', '2011-08-04 18:51:26', '2011-08-05 02:51:26', '', 0, 'http://avishek.net/blog/?p=533', 0, 'post', '', 1); 
