INSERT INTO `wp_posts` VALUES (537, 1, '2011-08-04 13:18:27', '2011-08-04 21:18:27', '<a href="http://processing.org/">Processing</a> is growing on me. Inspired by the different and (very) interesting data visualisation examples I\'ve seen, I decided to take a shot at interacting with the parallel coordinates that I generated <a href="http://avishek.net/blog/?p=518">here</a>. Of course, I had to reduce the number of samples for this demonstration; it\'d slow to a unholy crawl otherwise. For this video, I\'ve taken 300 samples. The interaction is essentially a mouse-hover highlighting of any sample(s) under it. I fiddled with the colors a bit, but decided that a white-on-greyscale scheme would show up better.\r\nOf course, I still haven\'t gotten around to labeling the axes. This I\'ll probably pick up next. But as the video demonstrates, there\'s a lot to Processing than meets the eye.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_hover.flv 400 300]\r\n', 'Data interactions in parallel coordinates', 0, '', 'inherit', 'open', 'open', '', '533-revision-4', '', '', '2011-08-04 13:18:27', '2011-08-04 21:18:27', '', 533, 'http://avishek.net/blog/?p=537', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (540, 1, '2011-08-04 13:20:06', '2011-08-04 21:20:06', '<a href="http://processing.org/">Processing</a> is growing on me. Inspired by the different and (very) interesting data visualisation examples I\'ve seen, I decided to take a shot at interacting with the parallel coordinates that I generated <a href="http://avishek.net/blog/?p=518">here</a>. Of course, I had to reduce the number of samples for this demonstration; it\'d slow to a unholy crawl otherwise. For this video, I\'ve taken 300 samples. The interaction is essentially a mouse-hover highlighting of any sample(s) under it. I fiddled with the colors a bit, but decided that a white-on-greyscale scheme would show up better.\r\nOf course, I still haven\'t gotten around to labeling the axes. This I\'ll probably pick up next. But as the video demonstrates, there\'s a lot to Processing than meets the eye.\r\n\r\nPS: By the way, the actual demonstration ends around the halfway mark; I was trying to figure out how to stop the bloody recorder.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_hover.flv 400 300]\r\n', 'Data interactions in parallel coordinates', 0, '', 'inherit', 'open', 'open', '', '533-revision-5', '', '', '2011-08-04 13:20:06', '2011-08-04 21:20:06', '', 533, 'http://avishek.net/blog/?p=540', 0, 'revision', '', 0); 
