INSERT INTO `wp_posts` VALUES (543, 1, '2011-08-06 03:35:42', '2011-08-06 11:35:42', '', 'parallel_coordinates_40x', 0, '', 'inherit', 'open', 'open', '', 'parallel_coordinates_40x-2', '', '', '2011-08-06 03:35:42', '2011-08-06 11:35:42', '', 0, 'http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.jpg', 0, 'attachment', 'image/jpeg', 0); 
INSERT INTO `wp_posts` VALUES (544, 1, '2011-08-06 03:42:07', '2011-08-06 11:42:07', 'This is an update on the visualisation post on parallel coordinates. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position. The speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\n\n<a href=\'http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv\'>parallel_coordinates_40x</a>\n', 'Data interaction in parallel coordinates: 40x Performance', 0, '', 'inherit', 'open', 'open', '', '541-revision', '', '', '2011-08-06 03:42:07', '2011-08-06 11:42:07', '', 541, 'http://avishek.net/blog/?p=544', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (545, 1, '2011-08-06 03:42:25', '2011-08-06 11:42:25', 'This is an update on the visualisation post on parallel coordinates. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position. The speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n<a href=\'http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv\'>parallel_coordinates_40x</a>\r\n', 'Data interaction in parallel coordinates: 40x Performance', 0, '', 'inherit', 'open', 'open', '', '541-revision-2', '', '', '2011-08-06 03:42:25', '2011-08-06 11:42:25', '', 541, 'http://avishek.net/blog/?p=545', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (546, 1, '2011-08-06 03:43:40', '2011-08-06 11:43:40', 'This is an update on the visualisation post on parallel coordinates. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position. The speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x Performance', 0, '', 'inherit', 'open', 'open', '', '541-revision-3', '', '', '2011-08-06 03:43:40', '2011-08-06 11:43:40', '', 541, 'http://avishek.net/blog/?p=546', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (547, 1, '2011-08-06 03:43:59', '2011-08-06 11:43:59', 'This is an update on the visualisation post on parallel coordinates. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position. The speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x-60x Performance', 0, '', 'inherit', 'open', 'open', '', '541-revision-4', '', '', '2011-08-06 03:43:59', '2011-08-06 11:43:59', '', 541, 'http://avishek.net/blog/?p=547', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (548, 1, '2011-08-06 03:44:29', '2011-08-06 11:44:29', 'This is an update on the visualisation post on parallel coordinates. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position. The speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x-60x speedup', 0, '', 'inherit', 'open', 'open', '', '541-revision-5', '', '', '2011-08-06 03:44:29', '2011-08-06 11:44:29', '', 541, 'http://avishek.net/blog/?p=548', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (549, 1, '2011-08-06 03:48:23', '2011-08-06 11:48:23', 'This is an update on the <a href="http://avishek.net/blog/?p=533">visualisation post on parallel coordinates</a>. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position.\r\n\r\nThe speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x-60x speedup', 0, '', 'inherit', 'open', 'open', '', '541-revision-6', '', '', '2011-08-06 03:48:23', '2011-08-06 11:48:23', '', 541, 'http://avishek.net/blog/?p=549', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (550, 1, '2011-08-06 06:32:36', '2011-08-06 14:32:36', 'This is an update on the <a href="http://avishek.net/blog/?p=533">visualisation post on parallel coordinates</a>. Understanding the Processing model gave me the idea that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position.\r\n\r\nThe speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x-60x speedup', 0, '', 'inherit', 'open', 'open', '', '541-revision-7', '', '', '2011-08-06 06:32:36', '2011-08-06 14:32:36', '', 541, 'http://avishek.net/blog/?p=550', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (551, 1, '2011-08-06 08:01:36', '2011-08-06 16:01:36', 'This is an update on the <a href="http://avishek.net/blog/?p=533">visualisation post on parallel coordinates</a>. Understanding the Processing model made me realise that it probably wasn\'t a good idea to draw all the samples each time draw() was called. Of course, every refreshed call of draw() does not clear away the previous frame\'s graphics, so that just makes it easier. In the end, I went and explicitly drew only the samples which were under the current mouse position.\r\n\r\nThe speedup is obvious and massive: whereas the previous version worked well with only 300 samples, the current one processes 18000 samples without breaking a sweat. At 29,000 samples, there is a bit of a slowdown, but only just a bit, you wait 1 second for the highlighting instead of 6-7.\r\nHere\'s the new video, using 18k samples. Notice how much denser the mesh is.\r\n\r\n[flv:http://avishek.net/blog/wp-content/uploads/2011/08/parallel_coordinates_40x.flv 400 300]\r\n', 'Data interaction in parallel coordinates: 40x-60x speedup', 0, '', 'inherit', 'open', 'open', '', '541-revision-8', '', '', '2011-08-06 08:01:36', '2011-08-06 16:01:36', '', 541, 'http://avishek.net/blog/?p=551', 0, 'revision', '', 0); 
