INSERT INTO `wp_posts` VALUES (573, 1, '2011-08-20 05:39:03', '2011-08-20 13:39:03', 'If you\'re using Ruby-Processing, you\'ll be working with the jruby-complete.jar. To install Basis, you simply type:\n\n[code]\njava -jar jruby-complete.jar -S gem install basis-processing --user-install\n[/code]\n\nI\'ve also created a basis_processing.rb so that you don\'t need to include all the files individually, so just use <code>require \'basis-processing\'</code>\'', 'Installing the Basis gem', 0, '', 'inherit', 'open', 'open', '', '572-revision', '', '', '2011-08-20 05:39:03', '2011-08-20 13:39:03', '', 572, 'http://avishek.net/blog/?p=573', 0, 'revision', '', 0); 
INSERT INTO `wp_posts` VALUES (574, 1, '2011-08-20 05:40:04', '2011-08-20 13:40:04', 'If you\'re using Ruby-Processing, you\'ll be working with the jruby-complete.jar. To install <a href="https://github.com/asengupta/Basis">Basis</a>, you simply type:\n\n[code]\njava -jar jruby-complete.jar -S gem install basis-processing --user-install\n[/code]\n\nI\'ve also created a <strong>basis_processing.rb</strong> so that you don\'t need to include all the files individually, so just use <code>require \'basis-processing\'</code>\' in your code to get started.\n', 'Installing the Basis gem', 0, '', 'inherit', 'open', 'open', '', '572-revision-2', '', '', '2011-08-20 05:40:04', '2011-08-20 13:40:04', '', 572, 'http://avishek.net/blog/?p=574', 0, 'revision', '', 0); 
