INSERT INTO `wp_posts` VALUES (576, 1, '2011-08-20 05:52:33', '2011-08-20 13:52:33', 'If you\'re using Ruby-Processing, you\'ll be working with the jruby-complete.jar. To install <a href="https://github.com/asengupta/Basis">Basis</a>, you simply type:\r\n\r\n[code]\r\njava -jar jruby-complete.jar -S gem install basis-processing --user-install\r\n[/code]\r\n\r\nI\'ve also created a <strong>basis_processing.rb</strong> so that you don\'t need to include all the files individually, so just use <code>require \'basis_processing\'</code>\' in your code to get started.\r\n', 'Installing the Basis gem', 0, '', 'inherit', 'open', 'open', '', '572-revision-4', '', '', '2011-08-20 05:52:33', '2011-08-20 13:52:33', '', 572, 'http://avishek.net/blog/?p=576', 0, 'revision', '', 0); 
