INSERT INTO `wp_posts` VALUES (629, 1, '2011-10-06 10:28:51', '2011-10-06 18:28:51', 'You can use Ruby-Processing in two ways.\r\n\r\n<ul>Use the jruby-complete.jar that Ruby-Processing ships, the Gems-in-a-Jar approach. In this mode, all gems you install will be packaged as part of the JAR.</ul>\r\n<ul>Using the JRuby already installed on your system.</ul>\r\n\r\nIf you\'re following the first approach, first head to the location where the jruby-complete.jar is located, for Ruby-Processing. There, do this:\r\n\r\n[code]\r\njava -jar jruby-complete.jar -S gem install basis-processing --user-install\r\n[/code]\r\n\r\nAlternatively, if you\'re using a conventional JRuby installation, do this:\r\n\r\n[code]\r\nsudo jruby -S gem install basis-processing\r\n[/code]\r\n', 'Installing the Basis gem (updated)', 0, '', 'inherit', 'open', 'open', '', '572-revision-6', '', '', '2011-10-06 10:28:51', '2011-10-06 18:28:51', '', 572, 'http://avishek.net/blog/?p=629', 0, 'revision', '', 0); 
